            // --- VOICE DICTATION HELPER ---
            class VoiceTranscriptionHelper {
                constructor() {
                    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
                    if (SpeechRecognition) {
                        this.recognition = new SpeechRecognition();
                        this.recognition.continuous = true;
                        this.recognition.interimResults = true;
                        this.isSupported = true;
                    } else {
                        this.isSupported = false;
                    }
                    this.isListening = false;
                    this.activeTextarea = null;
                }

                start(textarea) {
                    if (!this.isSupported) {
                        showToast('Voice dictation is not supported in this browser.', 'error');
                        return;
                    }
                    if (this.isListening) this.stop();

                    this.activeTextarea = textarea;
                    this.recognition.onresult = (event) => {
                        let finalTranscript = '';
                        for (let i = event.resultIndex; i < event.results.length; ++i) {
                            if (event.results[i].isFinal) {
                                finalTranscript += event.results[i][0].transcript;
                            }
                        }

                        if (finalTranscript) {
                            const start = this.activeTextarea.selectionStart;
                            const end = this.activeTextarea.selectionEnd;
                            const text = this.activeTextarea.value;
                            this.activeTextarea.value = text.substring(0, start) + ' ' + finalTranscript.trim() + ' ' + text.substring(end);
                            this.activeTextarea.selectionStart = this.activeTextarea.selectionEnd = start + finalTranscript.length + 2;
                        }
                    };

                    this.recognition.onerror = (event) => {
                        console.error('Speech recognition error', event.error);
                        this.stop();
                    };

                    this.recognition.onend = () => {
                        this.isListening = false;
                        this.updateUI(false);
                        showToast('Dictation ended.', 'info');
                    };

                    this.recognition.start();
                    this.isListening = true;
                    this.updateUI(true);
                    showToast('Listening... Speak now.', 'info');
                }

                stop() {
                    if (this.isSupported && this.isListening) {
                        this.recognition.stop();
                    }
                }

                updateUI(listening) {
                    if (!this.activeTextarea) return;
                    const btn = this.activeTextarea.nextElementSibling;
                    if (btn && btn.classList.contains('toggle-dictation')) {
                        if (listening) {
                            btn.innerHTML = '<i data-lucide="mic" class="w-5 h-5 text-red-500 animate-pulse"></i>';
                        } else {
                            btn.innerHTML = '<i data-lucide="mic" class="w-5 h-5"></i>';
                        }
                        if (window.lucide) window.lucide.createIcons();
                    }
                }
            }
            window.voiceDictation = new VoiceTranscriptionHelper();

            document.addEventListener('click', (e) => {
                const btn = e.target.closest('.toggle-dictation');
                if (btn) {
                    const textarea = btn.previousElementSibling;
                    if (window.voiceDictation.isListening && window.voiceDictation.activeTextarea === textarea) {
                        window.voiceDictation.stop();
                    } else {
                        window.voiceDictation.start(textarea);
                    }
                }
            });

            // --- API & DATA HANDLING ---
            function getEffectiveFolderId() {
                const authFolder = String(state.auth?.DriveFolderId || '').trim();
                return authFolder || state.settings.folderId;
            }

            async function apiCall(action, payload = {}, showOverlay = true) {
                const OFFLINE_ACTIONS = ['addTrial', 'createTrialRecord', 'updateTrialRecord', 'updateTrialStatus', 'addFormulation', 'addIngredient', 'finalizeTrial', 'addBatchTrials', 'updateProject', 'addBlock'];

                const queueItem = (errType, msg) => {
                    if (OFFLINE_ACTIONS.includes(action)) {
                        const queuedAction = {
                            id: Date.now().toString(),
                            action: action,
                            payload: payload,
                            timestamp: new Date().toISOString(),
                            status: 'pending',
                            attempts: 0
                        };
                        state.syncQueue = state.syncQueue || [];
                        state.syncQueue.push(queuedAction);
                        saveSyncQueue(); // Centralized saving
                        showToast(`Offline mode: ${action} saved locally.`, 'info');
                        if (typeof renderSyncStatus === 'function') renderSyncStatus();
                        return { success: true, offline: true, ...payload };
                    }
                    return { _errType: errType, message: msg };
                };

                const getAuthPayload = () => {
                    const authObject = state.auth?.user ? { ...state.auth.user, token: state.auth.token } : { ...state.auth };
                    if (!authObject || typeof authObject !== 'object') return undefined;
                    if (authObject.token && authObject.Token === undefined) authObject.Token = authObject.token;
                    if (authObject.Token && authObject.token === undefined) authObject.token = authObject.Token;
                    return authObject;
                };

                if (!navigator.onLine) {
                    return queueItem('network', 'Offline');
                }

                // If running inside Apps Script HTML environment, use google.script.run
                if (window.google && window.google.script && typeof google.script.run === 'object') {
                    return new Promise((resolve, reject) => {
                        if (showOverlay) loadingOverlay.classList.remove('hidden');
                        try {
                            const fullPayload = {
                                ...payload,
                                spreadsheetId: state.settings.sheetId,
                                folderId: getEffectiveFolderId(),
                                auth: getAuthPayload()
                            };
                            google.script.run

                                .withSuccessHandler((response) => {
                                    resolve(response);
                                })
                                .withFailureHandler((error) => {
                                    console.error(`API Error (${action}):`, error);
                                    resolve(queueItem('server', error?.message || String(error)));
                                })
                                .handleRequest({ action, payload: fullPayload });
                        } catch (err) {
                            resolve(queueItem('client', err?.message || String(err)));
                        } finally {
                            if (showOverlay) loadingOverlay.classList.add('hidden');
                        }
                    });
                }

                if (showOverlay) loadingOverlay.classList.remove('hidden');
                try {
                    const fullPayload = {
                        ...payload,
                        spreadsheetId: state.settings.sheetId,
                        folderId: getEffectiveFolderId()
                    };
                    const res = await fetch(String(state.settings.scriptUrl).replace(/\s/g, ''), {
                        method: 'POST',
                        headers: { "Content-Type": "text/plain;charset=utf-8" },
                        body: JSON.stringify({ action, payload: fullPayload, auth: getAuthPayload() }),
                    });


                    if (!res.ok) {
                        return queueItem('network', `HTTP ${res.status}: ${res.statusText} `);
                    }

                    const text = await res.text();
                    let result;
                    try {
                        result = JSON.parse(text);
                    } catch (e) {
                        return { _errType: 'parse', message: "Invalid JSON from server" };
                    }

                    const errorMsg = result.message || (result.data && result.data.message);
                    const isError = result.status === 'error' || (result.data && result.data.status === 'error') || result.success === false || (result.data && result.data.success === false);

                    if (isError) {
                        return { _errType: 'server', message: errorMsg || 'Unknown server error' };
                    }

                    return result.data !== undefined ? result.data : result;
                } catch (error) {
                    console.error('API Call Error:', action, error);
                    return queueItem('fetch', error.message);
                } finally {
                    if (showOverlay) loadingOverlay.classList.add('hidden');
                }
            }

            function showToast(message, type = 'success') {
                toast.textContent = message;
                toast.className = `toast show ${type} `;
                const toastMessage = String(message || '');
                const isApiKeyMessage = /api\s*key|apikey/i.test(toastMessage);

                // Mobile-friendly persistent alert strip for failures.
                if (type === 'error' || type === 'warning') {
                    const issueBanner = document.getElementById('issue-banner');
                    const issueText = document.getElementById('issue-banner-text');
                    if (issueBanner && issueText) {
                        issueText.textContent = message;
                        issueBanner.classList.remove('hidden', 'error', 'warning');
                        issueBanner.classList.add(type);
                        clearTimeout(window._issueBannerTimer);
                        const issueBannerDuration = isApiKeyMessage ? 5000 : 20000;
                        window._issueBannerTimer = setTimeout(() => {
                            issueBanner.classList.add('hidden');
                        }, issueBannerDuration);
                    }
                }

                setTimeout(() => { toast.className = toast.className.replace('show', ''); }, 5000);
            }
            window.showToast = showToast; // Make globally accessible

            window.dismissIssueBanner = function () {
                const issueBanner = document.getElementById('issue-banner');
                if (issueBanner) issueBanner.classList.add('hidden');
            };

            function hideToast() {
                if (toast) toast.className = toast.className.replace('show', '');
            }
            window.hideToast = hideToast;


