            // --- SPECIFIC FEATURE LOGIC (FORMULATIONS, TRIALS, AI, ETC.) ---
            function addFormulationIngredientRow(ingredient = null) {
                const container = document.getElementById('formulation-ingredients-container'); if (!container) return;
                const opts = state.ingredients.map(ing => `<option value="${ing.ID}">${sanitizeHTML(ing.Name)}</option>`).join('');
                const row = document.createElement('div'); row.className = 'flex items-center space-x-2 formulation-ingredient-row';
                row.innerHTML = `<select class="ingredient-selector flex-grow p-2 border rounded-md bg-white form-input"><option value="">Select ingredient</option>${opts}</select><input type="number" step="any" class="ingredient-quantity w-24 p-2 border rounded-md form-input" placeholder="Qty"><select class="ingredient-unit-selector w-20 p-2 border rounded-md bg-white form-input"><option>ml</option><option>L</option><option>gm</option><option>kg</option></select><button type="button" data-action="remove-ingredient-row" class="text-red-500 font-bold">&times;</button>`;
                container.appendChild(row);
                if (ingredient) { row.querySelector('.ingredient-selector').value = ingredient.id; row.querySelector('.ingredient-quantity').value = ingredient.quantity; row.querySelector('.ingredient-unit-selector').value = ingredient.unit; }
            }

            function updateFormulationCost() {
                const ingredients = [...document.querySelectorAll('.formulation-ingredient-row')].map(r => { const selector = r.querySelector('.ingredient-selector'); if (!selector || selector.value === "") return null; return { id: selector.value, quantity: r.querySelector('.ingredient-quantity').value, unit: r.querySelector('.ingredient-unit-selector').value }; }).filter(Boolean);
                document.getElementById('formulation-total-cost').textContent = `${CURRENCY_SYMBOL}${calculateFormulationCost(ingredients).toFixed(2)}`;
            }

            function calculateFormulationCost(ingredients) {
                if (!ingredients || !state.ingredients) return 0;
                return ingredients.reduce((acc, currentIng) => {
                    const details = state.ingredients.find(i => i.ID === currentIng.id);
                    if (!details) return acc;
                    const baseCost = parseFloat(details.Cost);
                    const baseUnit = details.Unit.toLowerCase();
                    let usedQuantity = parseFloat(currentIng.quantity) || 0;
                    const usedUnit = currentIng.unit.toLowerCase();
                    if (isNaN(baseCost) || isNaN(usedQuantity)) return acc;
                    let quantityInBaseUnit = usedQuantity;
                    if (baseUnit === 'l' && usedUnit === 'ml') quantityInBaseUnit /= 1000;
                    else if (baseUnit === 'ml' && usedUnit === 'l') quantityInBaseUnit *= 1000;
                    else if (baseUnit === 'kg' && usedUnit === 'gm') quantityInBaseUnit /= 1000;
                    else if (baseUnit === 'gm' && usedUnit === 'kg') quantityInBaseUnit *= 1000;
                    return acc + (baseCost * quantityInBaseUnit);
                }, 0);
            }

            // --- STATISTICAL ENGINE ---
            // --- STATISTICAL ENGINE ---
            function pow(n) { return n * n; }

            function calculateVPD(temp, humidity) {
                if (temp == null || humidity == null) return null;
                const t = parseFloat(temp);
                const rh = parseFloat(humidity);
                if (isNaN(t) || isNaN(rh)) return null;
                const es = 0.61078 * Math.exp(17.27 * t / (t + 237.3));
                const ea = es * rh / 100;
                return (es - ea).toFixed(3);
            }

            // --- ROBUST STATISTICAL ANALYSIS ENGINE (RCBD) ---
            // SCIENTIFICALLY RIGOROUS IMPLEMENTATION
            // References: Gomez & Gomez (1984), Steel & Torrie (1980), Piepho (2004)
            function calculateRCBD_Stats(project, trials, blocks) {
                const t = [...new Set(trials.map(tr => tr.FormulationID))].length;
                const r = blocks.length;

                if (t < 2 || r < 2) return {};

                const treatmentIds = [...new Set(trials.map(tr => tr.FormulationID))];
                const blockIds = [...new Set(blocks.map(b => b.ID))];
                const timePoints = {};

                trials.forEach(trial => {
                    const efficacyRaw = safeJsonParse(trial.EfficacyDataJSON, []);
                    const efficacy = validateEfficacyData(efficacyRaw);
                    if (efficacy.length === 0) return;

                    const lastObs = efficacy.sort((a, b) => b.daa - a.daa)[0];
                    if (lastObs) {
                        const value = extractMetricValue(lastObs, project);
                        if (value != null && !isNaN(value) && value >= 0) {
                            const daa = lastObs.daa;
                            const tId = trial.FormulationID;
                            const bId = trial.BlockID;
                            if (!timePoints[daa]) timePoints[daa] = [];
                            timePoints[daa].push({ tId, bId, value, trialId: trial.ID });
                        }
                    }
                });

                const results = {};
                Object.keys(timePoints).forEach(daa => {
                    let data = timePoints[daa];
                    const expectedN = treatmentIds.length * blockIds.length;
                    const actualN = data.length;

                    // Yates Missing Plot Estimation
                    let estimatedDF_Subtract = 0;
                    if (actualN === expectedN - 1) {
                        let missingT = null, missingB = null;
                        treatmentIds.forEach(tId => {
                            blockIds.forEach(bId => {
                                if (!data.some(d => d.tId === tId && d.bId === bId)) {
                                    missingT = tId; missingB = bId;
                                }
                            });
                        });
                        if (missingT && missingB) {
                            const T = data.filter(d => d.tId === missingT).reduce((s, d) => s + d.value, 0);
                            const B = data.filter(d => d.bId === missingB).reduce((s, d) => s + d.value, 0);
                            const G = data.reduce((s, d) => s + d.value, 0);
                            const V = (t * T + r * B - G) / ((t - 1) * (r - 1));
                            data.push({ tId: missingT, bId: missingB, value: V, isEstimated: true });
                            estimatedDF_Subtract = 1;
                        }
                    } else if (actualN < expectedN) {
                        results[daa] = { error: 'UNBALANCED_DESIGN', message: 'Incomplete data - unable to run standard ANOVA.' };
                        return;
                    }

                    const grandTotal = data.reduce((sum, d) => sum + d.value, 0);
                    const N = data.length;
                    const grandMean = grandTotal / N;

                    const treatmentTotals = {}, treatmentMeans = {};
                    treatmentIds.forEach(tId => {
                        const total = data.filter(d => d.tId === tId).reduce((sum, d) => sum + d.value, 0);
                        treatmentTotals[tId] = total; treatmentMeans[tId] = total / r;
                    });

                    const blockTotals = {};
                    blockIds.forEach(bId => {
                        blockTotals[bId] = data.filter(d => d.bId === bId).reduce((sum, d) => sum + d.value, 0);
                    });

                    const CF = (grandTotal * grandTotal) / N;
                    const totalSS = data.reduce((sum, d) => sum + (d.value * d.value), 0) - CF;
                    let trSS = treatmentIds.reduce((s, tId) => s + (treatmentTotals[tId] ** 2) / r, 0) - CF;
                    let blSS = blockIds.reduce((s, bId) => s + (blockTotals[bId] ** 2) / t, 0) - CF;
                    const errSS = Math.max(0, totalSS - trSS - blSS);

                    const trDF = t - 1;
                    const blDF = r - 1;
                    const errDF = (t - 1) * (r - 1) - estimatedDF_Subtract;
                    const totalDF = N - 1 - estimatedDF_Subtract;

                    const trMS = trSS / trDF, blMS = blSS / blDF, errMS = errSS / errDF;
                    if (errMS <= 0 || !isFinite(errMS)) { results[daa] = { error: 'LOW_VARIANCE' }; return; }

                    const trF = trMS / errMS, blF = blMS / errMS;
                    let trP = (typeof jStat !== 'undefined') ? 1 - jStat.centralF.cdf(trF, trDF, errDF) : 0.05;
                    let blP = (typeof jStat !== 'undefined') ? 1 - jStat.centralF.cdf(blF, blDF, errDF) : 0.05;

                    const trSig = formatSignificance(trP);
                    const expCV = grandMean !== 0 ? (Math.sqrt(errMS) / grandMean) * 100 : 0;
                    const tVal = (typeof jStat !== 'undefined') ? jStat.studentt.inv(0.975, errDF) : 2.05;
                    const sed = Math.sqrt((2 * errMS) / r);
                    const lsd = tVal * sed;

                    const treatmentStats = treatmentIds.map(tId => {
                        const points = data.filter(d => d.tId === tId);
                        const vals = points.map(d => d.value);
                        const mean = treatmentMeans[tId];
                        const sd = vals.length > 1 ? jStat.stdev(vals) : 0;
                        const outliers = points.filter(p => sd > 0 && Math.abs(p.value - mean) > 2.5 * sd).map(p => p.trialId);
                        return {
                            treatmentId: tId,
                            treatmentName: state.formulations.find(f => f.ID === tId)?.Name || 'Unknown',
                            mean, sd, n: r,
                            flags: outliers.length > 0 ? ['OUTLIER'] : [],
                            outlierTrialIds: outliers
                        };
                    });

                    assignCLD(treatmentStats, lsd);
                    calculateWCE(treatmentStats, project);

                    results[daa] = {
                        lsd, cv: expCV, grandMean, sed,
                        adequacyWarning: errDF < 12 ? "Low power design (Error DF < 12)" : null,
                        anovaTable: {
                            treatment: { df: trDF, ss: trSS, ms: trMS, f: trF, p: trP, sig: trSig.symbol },
                            block: { df: blDF, ss: blSS, ms: blMS, f: blF, p: blP },
                            error: { df: errDF, ss: errSS, ms: errMS },
                            total: { df: totalDF, ss: totalSS }
                        },
                        treatmentStats
                    };
                });
                return results;
            }

            /**
             * Compact Letter Display (CLD) Algorithm
             * Standard for mean separation in agricultural science (Piepho, 2004)
             */
            function assignCLD(treatmentStats, lsd) {
                const sorted = [...treatmentStats].sort((a, b) => b.mean - a.mean);
                const n = sorted.length;
                const cliques = [];
                for (let i = 0; i < n; i++) {
                    const clique = [i];
                    for (let j = 0; j < n; j++) {
                        if (i === j) continue;
                        if (clique.every(idx => Math.abs(sorted[idx].mean - sorted[j].mean) <= lsd)) clique.push(j);
                    }
                    clique.sort((a, b) => a - b);
                    if (!cliques.some(c => c.join(',') === clique.join(','))) {
                        if (!cliques.some(c => clique.every(idx => c.includes(idx)))) {
                            for (let k = cliques.length - 1; k >= 0; k--) {
                                if (cliques[k].every(idx => clique.includes(idx))) cliques.splice(k, 1);
                            }
                            cliques.push(clique);
                        }
                    }
                }
                cliques.sort((a, b) => a[0] - b[0]);
                const letters = 'abcdefghijklmnopqrstuvwxyz'.split('');
                sorted.forEach(ts => ts.rank = '');
                cliques.forEach((c, i) => {
                    const l = letters[i % 26];
                    c.forEach(idx => sorted[idx].rank += l);
                });
                treatmentStats.forEach(ts => {
                    const m = sorted.find(s => s.treatmentId === ts.treatmentId);
                    if (m) ts.rank = m.rank.split('').sort().join('');
                });
            }

            function assignCLDByComparator(treatmentStats, isNonSignificant) {
                const sorted = [...treatmentStats].sort((a, b) => b.mean - a.mean);
                const n = sorted.length;
                const cliques = [];
                for (let i = 0; i < n; i++) {
                    const clique = [i];
                    for (let j = 0; j < n; j++) {
                        if (i === j) continue;
                        if (clique.every(idx => isNonSignificant(sorted[idx], sorted[j]))) clique.push(j);
                    }
                    clique.sort((a, b) => a - b);
                    if (!cliques.some(c => c.join(',') === clique.join(','))) {
                        if (!cliques.some(c => clique.every(idx => c.includes(idx)))) {
                            for (let k = cliques.length - 1; k >= 0; k--) {
                                if (cliques[k].every(idx => clique.includes(idx))) cliques.splice(k, 1);
                            }
                            cliques.push(clique);
                        }
                    }
                }
                cliques.sort((a, b) => a[0] - b[0]);
                const letters = 'abcdefghijklmnopqrstuvwxyz'.split('');
                sorted.forEach(ts => ts.rank = '');
                cliques.forEach((c, i) => {
                    const l = letters[i % 26];
                    c.forEach(idx => sorted[idx].rank += l);
                });
                treatmentStats.forEach(ts => {
                    const m = sorted.find(s => s.treatmentId === ts.treatmentId);
                    if (m) ts.rank = m.rank.split('').sort().join('');
                });
            }

            /**
             * Calculate WCE with identified control (Abbott's formula)
             */
            function calculateWCE(treatmentStats, project) {
                const controlId = project.ControlTreatmentID;

                if (!controlId) {
                    // Fallback: use highest mean as control
                    const worstMean = Math.max(...treatmentStats.map(ts => ts.mean));
                    treatmentStats.forEach(ts => {
                        ts.wce = worstMean > 0 ? ((worstMean - ts.mean) / worstMean * 100) : 0;
                    });
                    return;
                }

                const control = treatmentStats.find(ts => ts.treatmentId === controlId);

                if (!control) {
                    console.warn(`Control treatment ${controlId} not found`);
                    return;
                }

                const controlMean = control.mean;

                treatmentStats.forEach(ts => {
                    if (ts.treatmentId === controlId) {
                        ts.wce = 0;
                        ts.wceLabel = 'Control';
                    } else if (controlMean > 0) {
                        ts.wce = ((controlMean - ts.mean) / controlMean) * 100;

                        // Weed science interpretation
                        if (ts.wce >= 90) ts.wceLabel = 'Excellent';
                        else if (ts.wce >= 80) ts.wceLabel = 'Good';
                        else if (ts.wce >= 70) ts.wceLabel = 'Acceptable';
                        else if (ts.wce >= 0) ts.wceLabel = 'Poor';
                        else ts.wceLabel = 'Negative';
                    }
                });
            }


            async function runProjectAnalysis(projectId) {
                const project = state.projects.find(p => p.ID === projectId);
                if (!project) return;

                project.isAnalyzing = true; // Ensure set here too if called manually

                showToast('Running Statistical Analysis...', 'info');

                const blocks = state.blocks.filter(b => b.ProjectID === projectId);
                const trials = state.trials.filter(t => t.ProjectID === projectId);

                if (blocks.length === 0 || trials.length === 0) {
                    showToast('Not enough data to analyze.', 'warning');
                    project.isAnalyzing = false;
                    return;
                }

                try {
                    // 1. Calculate Stats
                    const stats = calculateRCBD_Stats(project, trials, blocks);

                    console.log('[Analysis] Calculated stats:', stats);

                    // 2. Save Results (CRITICAL: Must stringify for Google Sheets!)
                    project.AnalysisResults = stats;
                    const analysisResultsJSON = JSON.stringify(stats);

                    console.log('[Analysis] Saving to backend...');
                    console.log('[Analysis] Project ID:', projectId);
                    console.log('[Analysis] JSON length:', analysisResultsJSON.length);

                    const saveResult = await apiCall('updateProject', {
                        ID: projectId,
                        AnalysisResultsJSON: analysisResultsJSON
                    }, false);

                    console.log('[Analysis] Save result:', saveResult);

                    if (!saveResult || (!saveResult.success && saveResult.success !== undefined) || saveResult._errType) {
                        console.error('[Analysis] SAVE FAILED! Backend returned:', saveResult);
                        showToast('Save Failed: ' + (saveResult.message || 'Unknown Server Error'), 'error');
                    }

                    // 3. Update Dashboard if visible
                    if (state.currentPage === 'projectDashboard' && state.activeProjectId === projectId) {
                        // Note: Calling render.projectDashboard here might be redundant if this was auto-triggered,
                        // BUT it is necessary to refresh the UI with the results!
                        // Since we set isAnalyzing=false afterwards, the loop condition (!results) will false, so no loop.
                        try {
                            render.projectDashboard();
                        } catch (e) { console.error("Dashboard render failed", e); }
                    }

                    showToast('Analysis Complete.', 'success');
                } catch (err) {
                    console.error("Analysis Failed:", err);
                    showToast('Analysis encountered an error.', 'error');
                } finally {
                    project.isAnalyzing = false;
                }
            }

