            // --- BACKGROUND PROCESSING & AI ---
            async function analyzePhotoForEfficacy(fileData, mimeType, analysisContext = {}) {
                try {
                    if (!fileData || typeof fileData !== 'string' || !fileData.includes(',')) {
                        throw new Error("Invalid image data provided for analysis.");
                    }
                    const historyPrompt = analysisContext.trial
                        ? window.buildWeedTrackingPromptContext(analysisContext.trial, analysisContext.daa)
                        : '';
                    const prompt = `As an agricultural expert analyzing a photo from a herbicide trial, identify up to 2 dominant weed species and estimate their cover/status. Respond ONLY with a single minified JSON object in this exact format: {"weedDetails": [{"species": "...", "cover": NUMBER, "status": "Controlled|Burndown|Re-emerged|Resistant|Unaffected", "notes": "..."}]}.
                    - "weedDetails": An array of objects.
                    - "species": The scientific or common name of the weed.
                    - "cover": Estimate the percentage of the ground covered by this specific weed species (0-100).
                    - "status": The observed condition of the weed.
                    - "notes": A brief qualitative observation.
                    - Prefer stable species naming across dates (e.g., Bermudagrass = Cynodon dactylon).
                    - Do NOT introduce a new species unless clearly visible.
                    - On day 0 to day 1, avoid reporting increased cover unless there is clear regrowth evidence.
                    ${historyPrompt}`;

                        const geminiCall = (genAI) => genAI.models.generateContent({
                        model: getActiveApiModel(),
                        contents: [{ text: prompt }, { inlineData: { mimeType: mimeType, data: fileData.split(',')[1] } }],
                        config: {
                            responseMimeType: "application/json",
                            responseSchema: {
                                type: Type.OBJECT,
                                properties: {
                                    weedDetails: {
                                        type: Type.ARRAY,
                                        items: {
                                            type: Type.OBJECT,
                                            properties: {
                                                species: { type: Type.STRING },
                                                cover: { type: Type.NUMBER },
                                                status: { type: Type.STRING },
                                                notes: { type: Type.STRING }
                                            },
                                            required: ["species", "cover", "status", "notes"]
                                        }
                                    }
                                },
                                required: ["weedDetails"]
                            }
                        }
                    });

                    let aiResponseText;
                    try {
                        const response = await callGeminiApi('Analyzing photo for efficacy', geminiCall);
                        aiResponseText = extractResponseText(response);
                    } catch (geminiErr) {
                        console.warn('[Efficacy] Gemini failed, trying vision fallback...', geminiErr.message);
                        aiResponseText = await callVisionFallback(prompt, fileData.split(',')[1], mimeType);
                    }

                    // ALSO run offline weed cover detection in parallel
                    // Use GREEN-ONLY mode to avoid counting pre-existing burnt weeds
                    let weedCoverEstimate = null;
                    try {
                        const greenOnly = true; // Only count living green weeds
                        const coverResult = await analyzeWeedCover(fileData, greenOnly);
                        weedCoverEstimate = {
                            cover: coverResult.cover,
                            vari: coverResult.vari,
                            vegetationIndex: coverResult.vegetationIndex,
                            confidence: coverResult.confidence,
                            source: 'offline',
                            mode: coverResult.mode,
                            breakdown: coverResult.breakdown,
                            details: coverResult.details
                        };
                        console.log('[Weed Cover] Offline estimate (green-only):', coverResult);
                    } catch (error) {
                        console.warn('[Weed Cover] Offline analysis failed:', error);
                    }

                    const parsed = JSON.parse(aiResponseText);
                    let weedDetails = parsed.weedDetails || [];
                    if (analysisContext.trial) {
                        weedDetails = window.applyHistoricalWeedTracking(analysisContext.trial, { daa: analysisContext.daa, weedDetails }).weedDetails;
                    }
                    return {
                        weedDetails,
                        weedCoverEstimate: weedCoverEstimate
                    };
                } catch (error) {
                    console.error('Efficacy analysis failed (all providers):', error);
                    if (error.message === 'ALL_KEYS_EXHAUSTED' || error.message.includes('quota')) {
                        throw new Error('QUOTA_EXCEEDED');
                    }
                    return null;
                }
            }

            async function identifyWeedsFromPhoto(fileData, mimeType) {
                try {
                    if (!fileData || typeof fileData !== 'string' || !fileData.includes(',')) {
                        throw new Error("Invalid image data provided for identification.");
                    }
                    const prompt = `You are an expert botanist specializing in weed identification for agriculture. Analyze this photo and identify ALL visible weed species. For EACH different weed species you can see:
1. Provide the scientific name
2. List common names
3. Give a confidence score (0-1) for your identification
4. Categorize the growth stage

IMPORTANT: Identify EVERY distinct weed species visible in the photo, not just the most prominent one. List them all in the identifications array.

Respond ONLY with a single minified JSON object in this format: {"identifications": [{"name": "Scientific Name", "commonNames": ["Common Name 1", ...], "confidence": 0.95, "growthStage": "Seedling|Vegetative|Flowering|Mature"}]}`;

                    const geminiCall = (genAI) => genAI.models.generateContent({
                        model: getActiveApiModel(),
                        contents: [{ text: prompt }, { inlineData: { mimeType: mimeType, data: fileData.split(',')[1] } }],
                        config: {
                            responseMimeType: "application/json",
                            responseSchema: {
                                type: Type.OBJECT,
                                properties: {
                                    identifications: {
                                        type: Type.ARRAY,
                                        items: {
                                            type: Type.OBJECT,
                                            properties: {
                                                name: { type: Type.STRING },
                                                commonNames: { type: Type.ARRAY, items: { type: Type.STRING } },
                                                confidence: { type: Type.NUMBER },
                                                growthStage: { type: Type.STRING }
                                            },
                                            required: ["name", "commonNames", "confidence", "growthStage"]
                                        }
                                    }
                                },
                                required: ["identifications"]
                            }
                        }
                    });

                    let resultText;
                    try {
                        const response = await callGeminiApi('Identifying weeds from photo', geminiCall);
                        console.log('Weed identification raw response:', response);
                        resultText = extractResponseText(response);
                    } catch (geminiErr) {
                        console.warn('[Weed ID] Gemini failed, trying vision fallback...', geminiErr.message);
                        resultText = await callVisionFallback(prompt, fileData.split(',')[1], mimeType);
                    }

                    console.log('Weed identification result text:', resultText);

                    if (!resultText) {
                        console.warn('Empty response from weed identification');
                        return [];
                    }

                    // Clean up the response text
                    const cleanedText = resultText.replace(/```json/g, '').replace(/```/g, '').trim();
                    const parsed = JSON.parse(cleanedText);
                    console.log('Weed identification parsed:', parsed);

                    return parsed.identifications || parsed.results || [];
                } catch (error) {
                    console.error('Weed identification failed (all providers):', error);
                    return [];
                }
            }

            async function uploadPhotos(photosData, folderPath = null) {

                if (!photosData || photosData.length === 0) return [];
                const results = [];
                for (const photoData of photosData) {
                    try {
                        if (!getEffectiveFolderId()) throw new Error("Folder ID missing. Check Settings.");
                        console.log(`[Upload] Sending photo to path: ${JSON.stringify(folderPath)}`);
                        const result = await apiCall('uploadPhoto', {
                            fileData: photoData.fileData,
                            fileName: photoData.fileName,
                            mimeType: photoData.mimeType,
                            folderPath: folderPath // Pass it as folderPath
                        }, false);
                        results.push(result);
                    } catch (error) {
                        console.error('Photo upload failed for one photo:', error);
                        results.push(null);
                    }
                    await new Promise(resolve => setTimeout(resolve, 300));
                }
                return results.map((result, index) => {
                    if (!result || !result.url) return null;
                    return {
                        ...photosData[index],
                        url: result.url
                    };
                }).filter(Boolean);
            }

            function buildSortedGeneralPhotoIndex(trial) {
                    return safeJsonParse(trial?.PhotoURLs, []).map((photo, index) => {
                        const dateValue = photo?.date ? new Date(photo.date).getTime() : NaN;
                        return {
                            index,
                            sortDate: Number.isFinite(dateValue) ? dateValue : Number.MAX_SAFE_INTEGER,
                            photo
                        };
                    }).sort((a, b) => a.sortDate - b.sortDate || a.index - b.index);
                }

                function resolveGeneralPhotoIndex(trial, photoLocator = {}) {
                    const photos = safeJsonParse(trial?.PhotoURLs, []);
                    if (!photos.length) return -1;

                    if (Number.isInteger(photoLocator.index) && photoLocator.index >= 0 && photoLocator.index < photos.length) {
                        return photoLocator.index;
                    }

                    if (photoLocator.tempId) {
                        const tempMatch = photos.findIndex(p => p?.tempId === photoLocator.tempId);
                        if (tempMatch > -1) return tempMatch;
                    }

                    if (photoLocator.url) {
                        const urlMatch = photos.findIndex(p => p?.url === photoLocator.url);
                        if (urlMatch > -1) return urlMatch;
                    }

                    return -1;
                }

                function getFirstGeneralPhotoIndex(trial) {
                    const sorted = buildSortedGeneralPhotoIndex(trial);
                    return sorted.length ? sorted[0].index : -1;
                }

                function mergeTrialWeedSpecies(existingSpecies, identifications) {
                    const merged = [];
                    const seen = new Set();
                    const pushUnique = (name) => {
                        const cleaned = String(name || '').trim();
                        if (!cleaned) return;
                        const canonical = window.canonicalizeWeedSpecies ? window.canonicalizeWeedSpecies(cleaned) : cleaned;
                        const key = canonical.toLowerCase();
                        if (seen.has(key)) return;
                        seen.add(key);
                        merged.push(canonical);
                    };

                    String(existingSpecies || '').split(',').map(name => name.trim()).filter(Boolean).forEach(pushUnique);
                    (identifications || []).forEach(item => pushUnique(item?.name));
                    return merged.join(', ');
                }

                function shouldAutoIdentifyGeneralPhotoWeeds(trial, photoLocator = {}) {
                    const photos = safeJsonParse(trial?.PhotoURLs, []);
                    if (!photos.length) return false;

                    const photoIndex = resolveGeneralPhotoIndex(trial, photoLocator);
                    if (photoIndex === -1) return false;

                    const firstPhotoIndex = getFirstGeneralPhotoIndex(trial);
                    const hasStoredIdentification = photos.some(p => Array.isArray(p?.identifications) && p.identifications.length > 0);
                    const trialWeedsMissing = !String(trial?.WeedSpecies || '').trim();

                    return photoIndex === firstPhotoIndex || !hasStoredIdentification || trialWeedsMissing;
                }

                async function persistGeneralPhotoWeedIdentifications(trialId, photoLocator, identifications) {
                    const trial = state.trials.find(t => t.ID === trialId);
                    if (!trial) throw new Error('Trial not found.');

                    const photos = safeJsonParse(trial.PhotoURLs, []);
                    const photoIndex = resolveGeneralPhotoIndex(trial, photoLocator);
                    if (photoIndex === -1 || !photos[photoIndex]) throw new Error('Photo not found in trial.');

                    const cleanIdentifications = Array.isArray(identifications)
                        ? identifications.filter(item => String(item?.name || '').trim())
                        : [];

                    photos[photoIndex] = {
                        ...photos[photoIndex],
                        identifications: cleanIdentifications,
                        weedIdentificationCheckedAt: new Date().toISOString()
                    };

                    trial.PhotoURLs = JSON.stringify(photos);
                    trial.WeedSpecies = mergeTrialWeedSpecies(trial.WeedSpecies, cleanIdentifications);

                    await apiCall('updateTrialRecord', {
                        ID: trial.ID,
                        PhotoURLs: trial.PhotoURLs,
                        WeedSpecies: trial.WeedSpecies
                    }, false);

                    refreshRelevantUI(trial.ID, 'general_upload');
                    return cleanIdentifications;
                }

                async function analyzeGeneralPhotoWeeds(trialId, photoLocator, options = {}) {
                    const trial = state.trials.find(t => t.ID === trialId);
                    if (!trial) throw new Error('Trial not found.');

                    const photos = safeJsonParse(trial.PhotoURLs, []);
                    const photoIndex = resolveGeneralPhotoIndex(trial, photoLocator);
                    if (photoIndex === -1 || !photos[photoIndex]) throw new Error('Photo not found.');

                    const photo = photos[photoIndex];
                    const shouldToast = options.showToast !== false;

                    let fileData = options.sourceFileData || photo.fileData;
                    let mimeType = options.sourceMimeType || photo.mimeType || 'image/jpeg';

                    if (!fileData) {
                        if (!photo.url) throw new Error('Photo is not uploaded yet.');
                        const base64Photo = await fetchPhotoAsBase64(photo.url);
                        if (!base64Photo?.fileData) throw new Error('Could not load photo for weed identification.');
                        fileData = base64Photo.fileData;
                        mimeType = base64Photo.mimeType || mimeType;
                    }

                    if (shouldToast) {
                        showToast(`Checking weeds for photo ${photoIndex + 1}...`, 'info');
                    }

                    const identifications = await identifyWeedsFromPhoto(fileData, mimeType);
                    await persistGeneralPhotoWeedIdentifications(trialId, { index: photoIndex }, identifications);

                    if (shouldToast) {
                        if (identifications.length > 0) {
                            showToast(`Weed names updated for photo ${photoIndex + 1}.`, 'success');
                        } else {
                            showToast(`No weeds identified in photo ${photoIndex + 1}.`, 'warning');
                        }
                    }

                    return identifications;
                }

            function handlePhotoEditSubmit(form) {
                const trialId = form.querySelector('[name="trialId"]').value;
                const photoIndex = parseInt(form.querySelector('[name="photoIndex"]').value);
                const trial = state.trials.find(t => t.ID === trialId);
                if (!trial) return;
                const photos = safeJsonParse(trial.PhotoURLs);
                const photo = photos[photoIndex];
                if (photo) {
                    // Extract values with trimming to ensure cleanliness
                    const newLabel = (form.querySelector('[name="label"]').value || '').trim();
                    const newDate = form.querySelector('[name="date"]').value;
                    const oldDate = photo.date; // Store the old date to detect changes
                    const wTemp = (form.querySelector('[name="temp"]').value || '').trim();
                    const wHum = (form.querySelector('[name="humidity"]').value || '').trim();
                    const wWind = (form.querySelector('[name="wind"]').value || '').trim();
                    const wRain = (form.querySelector('[name="rain"]').value || '').trim();

                    // Update local state immediately
                    photo.label = newLabel;
                    photo.date = newDate;

                    // Explicitly update weather object
                    photo.weather = {
                        temp: wTemp,
                        humidity: wHum,
                        wind: wWind,
                        rain: wRain
                    };

                    trial.PhotoURLs = JSON.stringify(photos);

                    // **NEW: If photo date changed, recalculate DAA in Efficacy data**
                    if (oldDate !== newDate && newDate) {
                        try {
                            const efficacyData = safeJsonParse(trial.EfficacyDataJSON, []);
                            const newDaa = window.calculateDAA(newDate, trial.Date);

                            // Find and update efficacy observations that match this photo's old date
                            const oldPhotoDateStr = oldDate ? window.toDateKey(oldDate) : null;
                            const newPhotoDateStr = newDate ? window.toDateKey(newDate) : null;

                            let updated = false;
                            efficacyData.forEach(obs => {
                                // Match by date and optional photoUrl if available
                                          const obsDateKey = window.toDateKey(obs.date);
                                          if (obsDateKey === oldPhotoDateStr || (photo.url && obs.photoUrl === photo.url)) {
                                    obs.date = newPhotoDateStr;
                                    obs.daa = newDaa; // Already non-negative from calculateDAA
                                    updated = true;
                                    console.log(`[Photo Date Update] Recalculated DAA for observation: ${newPhotoDateStr} -> DAA ${obs.daa}`);
                                }
                            });

                            if (updated) {
                                trial.EfficacyDataJSON = JSON.stringify(efficacyData);
                            }
                        } catch (e) {
                            console.warn('[Photo Date Update] Could not update efficacy DAA:', e);
                                            // Always recalculate DAA for efficacy observations linked to this photo.
                                            // Matches by: old date, new date (re-edit), or photoUrl.
                                            // Normalizes obs.date to handle ISO/locale/timestamp mismatches.
                                            if (newDate) {
                                                try {
                                                    const efficacyData = safeJsonParse(trial.EfficacyDataJSON, []);
                                                    const oldPhotoDateStr = oldDate ? window.toDateKey(oldDate) : null;
                                                    const newPhotoDateStr = window.toDateKey(newDate);
                                                    const newDaa = window.calculateDAA(newDate, trial.Date);

                                                    let updated = false;
                                                    efficacyData.forEach(obs => {
                                                        const obsDateKey = window.toDateKey(obs.date);
                                                        if (obsDateKey === oldPhotoDateStr
                                                            || obsDateKey === newPhotoDateStr
                                                            || (photo.url && obs.photoUrl === photo.url)) {
                                                            obs.date = newPhotoDateStr;
                                                            obs.daa = newDaa;
                                                            updated = true;
                                                            console.log(`[Photo Date Update] obs matched: ${obsDateKey} -> ${newPhotoDateStr}, DAA ${newDaa}`);
                                                        }
                                                    });

                                                    // Safety pass: keep daa consistent with each observation date.
                                                    efficacyData.forEach(obs => {
                                                        const obsDateKey = window.toDateKey(obs.date);
                                                        if (obsDateKey) {
                                                            obs.date = obsDateKey;
                                                            obs.daa = window.calculateDAA(obsDateKey, trial.Date);
                                                        }
                                                    });

                                                    if (updated) {
                                                        trial.EfficacyDataJSON = JSON.stringify(efficacyData);
                                                        console.log(`[Photo Date Update] Saved ${efficacyData.filter(o => window.toDateKey(o.date) === newPhotoDateStr).length} obs with DAA=${newDaa}`);
                                                    } else {
                                                        console.warn('[Photo Date Update] No matching efficacy obs found. oldDate:', oldPhotoDateStr, 'existingDates:', efficacyData.map(o => o.date));
                                                    }
                                                } catch (e) {
                                                    console.warn('[Photo Date Update] Could not update efficacy DAA:', e);
                                                }
                                            }
                        }
                    }

                    // Optimistic UI Update: Close and refresh immediately
                    showToast('Photo details updated.', 'success');
                    closeModal();
                    openTrialDetail(trialId);

                    // Background Sync
                    // We do NOT wait for this to finish before closing UI
                    apiCall('updateTrialRecord', {
                        ID: trialId,
                        PhotoURLs: trial.PhotoURLs,
                        EfficacyDataJSON: trial.EfficacyDataJSON // Also sync updated DAA values
                    }, false)
                        .catch(err => {
                            console.error('Background sync failed:', err);
                            showToast('Warning: Changes saved locally but sync failed. Please check connection.', 'warning');
                        });
                }
            }

            function handleOpenPhotoEditModal(trialId, photoIndex) {
                const trial = state.trials.find(t => t.ID === trialId);
                if (!trial) return;

                const photos = safeJsonParse(trial.PhotoURLs);
                const photo = photos[photoIndex];
                if (!photo) return;

                openModal('photoEdit', true);

                // Defer population slightly to ensure DOM is ready
                setTimeout(() => {
                    const form = document.getElementById('photo-edit-form');
                    if (!form) return;

                    form.querySelector('[name="trialId"]').value = trialId;
                    form.querySelector('[name="photoIndex"]').value = String(photoIndex);
                    form.querySelector('[name="label"]').value = photo.label || '';

                    if (photo.date) {
                        form.querySelector('[name="date"]').value = new Date(photo.date).toISOString().split('T')[0];
                    }

                    if (photo.weather) {
                        form.querySelector('[name="temp"]').value = photo.weather.temp || '';
                        form.querySelector('[name="humidity"]').value = photo.weather.humidity || '';
                        form.querySelector('[name="wind"]').value = photo.weather.wind || '';
                        form.querySelector('[name="rain"]').value = photo.weather.rain || '';
                    }

                    // Add listener for date change in edit modal
                    const dateInput = form.querySelector('[name="date"]');
                    dateInput.addEventListener('change', async () => {
                        const newDate = dateInput.value;
                        if (!newDate) return;

                        // Try to get location from trial
                        const locationStr = trial.Location || '';
                        let lat, lon;
                        if (locationStr.includes(',')) {
                            [lat, lon] = locationStr.split(',').map(s => s.trim());
                        }

                        if (lat && lon) {
                            showToast('Fetching weather for new date...', 'info');
                            const w = await fetchWeather(lat, lon, newDate);
                            if (w) {
                                form.querySelector('[name="temp"]').value = w.temp || '';
                                form.querySelector('[name="humidity"]').value = w.humidity || '';
                                form.querySelector('[name="wind"]').value = w.wind || '';
                                form.querySelector('[name="rain"]').value = w.rain || '';
                                showToast('Weather updated.', 'success');
                            }
                        } else {
                            showToast('Trial has no location. Cannot fetch weather.', 'warning');
                        }
                    });
                }, 50);
            }

