                        'organize-drive-photos': () => {
                            showConfirmation(
                                'Organize Drive Photos?',
                                'This will analyze your Trial records and move all existing Trial photos into "Project > Trial" subfolders. This will be done in batches to prevent timeouts.',
                                async () => {
                                    let movedTotal = 0;
                                    let errorsTotal = 0;
                                    let startIndex = 0;
                                    let isComplete = false;

                                    try {
                                        showToast('Starting organization...', 'info', 0);

                                        while (!isComplete) {
                                            const result = await apiCall('organizeExistingPhotos', { startIndex }, false);

                                            // Handle potential API error nested in success result
                                            if (result._errType) throw new Error(result.message);

                                            if (result.success) {
                                                movedTotal += result.moved;
                                                errorsTotal += result.errors;
                                                startIndex = result.nextIndex;
                                                isComplete = result.isComplete;

                                                const percent = result.total > 0 ? Math.round((startIndex / result.total) * 100) : 100;
                                                showToast(`Organizing: ${Math.min(100, percent)}% complete... (${movedTotal} moved)`, 'info', 0);
                                            } else {
                                                throw new Error(result.message || 'Batch failed');
                                            }
                                        }

                                        hideToast();
                                        showToast(`Successfully moved ${movedTotal} photos. (${errorsTotal} errors)`, 'success');
                                    } catch (err) {
                                        hideToast();
                                        showToast('Error organizing photos: ' + err.message, 'error');
                                    }
                                }
                            );
                        },
