                    "inf": [3.64, 4.12, 4.40, 4.60, 4.76, 4.88, 4.99, 5.08, 5.16, 5.23, 5.29, 5.35, 5.40, 5.45, 5.49, 5.54, 5.57, 5.61, 5.65]
