            function buildProjectConclusionFromResults(project, analysisResults, projectTrials) {
                const daas = Object.keys(analysisResults || {}).sort((a, b) => parseFloat(a) - parseFloat(b));
                if (!daas.length) {
                    return normalizeReportText(project?.Narrative || project?.Conclusion || 'Project report generated from available protocol and trial metadata.');
                }

                const finalDaa = daas[daas.length - 1];
                const finalRes = analysisResults[finalDaa] || {};
                const treatmentStats = Array.isArray(finalRes.treatmentStats) ? finalRes.treatmentStats : [];

                if (!treatmentStats.length) {
                    return `Analysis results are available across ${daas.length} assessment window(s), but final treatment-level statistics at ${finalDaa} DA-A are incomplete.`;
                }

                const ranked = [...treatmentStats].sort((a, b) => (parseFloat(b.wce) || 0) - (parseFloat(a.wce) || 0));
                const best = ranked[0] || {};
                const bestName = state.formulations.find(f => f.ID === best.treatmentId)?.Name || best.treatmentId || 'Top treatment';
                const avgWce = ranked.reduce((s, r) => s + (parseFloat(r.wce) || 0), 0) / ranked.length;

                return normalizeReportText(`The project includes ${projectTrials.length} trial plots and ${ranked.length} analyzed treatment(s). At ${finalDaa} DA-A, ${bestName} ranked highest with ${Number(best.wce || 0).toFixed(1)}% control efficiency. Mean control efficiency across treatments at the final assessment was ${avgWce.toFixed(1)}%.`);
            }

            async function generateTrialSummary(trials) {
                try {
                    const provider = new MultiProviderAI();
                    // Use a fast provider for summaries if available, or default
                    const context = `
                        Comparing ${trials.length} herbicide trials.
                        Data: ${JSON.stringify(trials.map(t => ({
                        formulation: t.FormulationName,
                        weed: t.WeedSpecies,
                        result: t.Result,
                        cost: t.EstimatedCost,
                        cover: safeJsonParse(t.AISummariesJSON, {}).cover || 'N/A'
                    })))}
                        Task: Write a 2-3 sentence executive summary comparing the performance and cost-effectiveness of these treatments. Identify the winner if clear.
                    `;

                    // Attempt to use a model - defaulting to a fast one if possible, or iterating
                    // Since MultiProviderAI handles iteration, we just need a standard "text generation" method if exposed,
                    // or we can use a specific provider flow.
                    // Assuming MultiProviderAI has a generic 'generateText' or we can repurpose 'analyzePhoto'
                    // Wait, MultiProviderAI seems designed for photos.
                    // Let's add a generic text generation method to MultiProviderAI or use 'callGroq' etc directly if we have keys.
                    // Actually, looking at MultiProviderAI, it has 'generateText' method!

                    return await provider.generateText(context);

                } catch (e) {
                    console.warn("AI Log Summary failed", e);
                    return "AI Summary unavailable.";
                }
            }

            function getPhotoSource(photo) {
                if (!photo || typeof photo !== 'object') return '';
                const candidates = [
                    photo.fileData,
                    photo.url,
                    photo.fileUrl,
                    photo.publicUrl,
                    photo.src,
                    photo.imageUrl,
                    photo.link
                ];

                for (const value of candidates) {
                    if (typeof value !== 'string') continue;
                    const normalized = value.trim();
                    if (normalized) return normalized;
                }
                return '';
            }

            function normalizePhotoFetchUrl(rawUrl) {
                const src = String(rawUrl || '').trim();
                if (!src) return '';
                if (/^data:image\//i.test(src)) return src;

                // Normalize common Google Drive sharing URLs to direct-view URLs.
                const idMatch = src.match(/(?:[?&]id=|\/d\/)([a-zA-Z0-9_-]{10,})/i);
                if (idMatch && idMatch[1]) {
                    return `https://drive.google.com/uc?export=view&id=${idMatch[1]}`;
                }
                return src;
            }

            async function getImageAsResizedBase64(url, width = 800) {
                if (!url) return null;
                const source = normalizePhotoFetchUrl(url);
                if (!source) return null;

                if (source.startsWith('data:image')) {
                    return source;
                }

                console.log('[Photo] Attempting to fetch:', source.substring(0, 80) + '...');

                try {
                    console.log('[Photo] Method 1: Direct fetch');
                    const res = await fetch(source, { mode: 'cors' });
                    if (!res.ok) throw new Error(`HTTP ${res.status}`);
                    const blob = await res.blob();

                    return await new Promise((resolve) => {
                        const reader = new FileReader();
                        reader.onloadend = () => {
                            const raw = String(reader.result || '').trim();
                            if (raw.startsWith('data:image/')) {
                                console.log('[Photo] Direct fetch succeeded');
                                return resolve(raw);
                            }
                            if (raw.startsWith('data:')) {
                                const base64 = raw.split(',')[1] || '';
                                if (base64) {
                                    console.log('[Photo] Direct fetch succeeded (converted)');
                                    return resolve(`data:image/jpeg;base64,${base64}`);
                                }
                            }
                            return resolve(null);
                        };
                        reader.readAsDataURL(blob);
                    });
                } catch (directError) {
                    console.warn('[Photo] Direct fetch failed:', directError?.message || directError);
                }

                try {
                    console.log('[Photo] Method 2: Using weserv proxy');
                    const proxyUrl = `https://images.weserv.nl/?url=${encodeURIComponent(source)}&w=${width}&output=jpg&q=80`;
                    const res = await fetch(proxyUrl);
                    if (!res.ok) throw new Error(`Proxy HTTP ${res.status}`);
                    const blob = await res.blob();

                    return await new Promise((resolve) => {
                        const reader = new FileReader();
                        reader.onloadend = () => {
                            const raw = String(reader.result || '').trim();
                            if (raw.startsWith('data:image/')) {
                                console.log('[Photo] Proxy fetch succeeded');
                                return resolve(raw);
                            }
                            if (raw.startsWith('data:')) {
                                const base64 = raw.split(',')[1] || '';
                                if (base64) {
                                    console.log('[Photo] Proxy fetch succeeded (converted)');
                                    return resolve(`data:image/jpeg;base64,${base64}`);
                                }
                            }
                            return resolve(null);
                        };
                        reader.readAsDataURL(blob);
                    });
                } catch (proxyError) {
                    console.error('[Photo] All methods failed:', proxyError?.message || proxyError);
                    return null;
                }
            }

            function getPdfImageFormatFromData(dataUrl) {
                const src = String(dataUrl || '').toLowerCase();
                if (src.startsWith('data:image/png')) return 'PNG';
                if (src.startsWith('data:image/webp')) return 'WEBP';
                return 'JPEG';
            }

            function normalizeDataUrlForPdf(dataUrl) {
                const src = String(dataUrl || '').trim();
                if (!src) return null;
                if (src.startsWith('data:image/')) return src;
                if (src.startsWith('data:')) {
                    const base64 = src.split(',')[1] || '';
                    return base64 ? `data:image/jpeg;base64,${base64}` : null;
                }
                return null;
            }

            function createPdfDoc(orientationOrOptions = 'p', unit = 'mm', format = 'a4') {
                const { jsPDF } = window.jspdf;
                if (typeof orientationOrOptions === 'object' && orientationOrOptions !== null) {
                    return new jsPDF({
                        compress: true,
                        putOnlyUsedFonts: true,
                        ...orientationOrOptions
                    });
                }
                return new jsPDF({
                    orientation: orientationOrOptions || 'p',
                    unit: unit || 'mm',
                    format: format || 'a4',
                    compress: true,
                    putOnlyUsedFonts: true
                });
            }

            function addImageToPdfSafe(doc, imageData, x, y, w, h) {
                if (!doc || !Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(w) || !Number.isFinite(h) || w <= 0 || h <= 0) return false;
                const normalized = normalizeDataUrlForPdf(imageData);
                if (!normalized) return false;
                try {
                    doc.addImage(normalized, getPdfImageFormatFromData(normalized), x, y, w, h);
                    return true;
                } catch (e1) {
                    try {
                        doc.addImage(normalized, 'JPEG', x, y, w, h);
                        return true;
                    } catch (e2) {
                        console.warn('Photo embedding failed after fallback.', e2);
                        return false;
                    }
                }
            }

            function reconcileEfficacyWithPhotos(trialDate, efficacyData, photoList) {
                const photos = Array.isArray(photoList) ? photoList : [];
                const photoUrlSet = new Set(photos.map(p => String(p?.url || '').trim()).filter(Boolean));
                const photoDateSet = new Set(photos.map(p => window.toDateKey(p?.date)).filter(Boolean));
                const photoDateByUrl = new Map(
                    photos
                        .map(p => [String(p?.url || '').trim(), window.toDateKey(p?.date)])
                        .filter(([u, d]) => u && d)
                );

                const normalized = safeJsonParse(JSON.stringify(Array.isArray(efficacyData) ? efficacyData : []), []);
                const reconciled = [];

                normalized.forEach(obs => {
                    const obsUrl = String(obs?.photoUrl || '').trim();
                    const obsDateKey = window.toDateKey(obs?.date);
                    const notes = String(obs?.notes || '').toLowerCase();
                    const looksAutoPhotoObs = obs?.weedCoverMode === 'auto' || notes.includes('photo') || notes.includes('ai analysis');

                    if (obsUrl) {
                        // Photo-linked observation must be dropped if the photo was deleted.
                        if (!photoUrlSet.has(obsUrl)) {
                            return;
                        }
                        const photoDateKey = photoDateByUrl.get(obsUrl) || obsDateKey;
                        obs.date = photoDateKey || obs.date;
                        obs.daa = window.calculateDAA(obs.date, trialDate);
                        reconciled.push(obs);
                        return;
                    }

                    // Legacy auto-generated observations without photoUrl should not survive
                    // if their date no longer exists in the remaining photos.
                    if (looksAutoPhotoObs && obsDateKey && photoDateSet.size > 0 && !photoDateSet.has(obsDateKey)) {
                        return;
                    }

                    if (obsDateKey) {
                        obs.date = obsDateKey;
                        obs.daa = window.calculateDAA(obsDateKey, trialDate);
                    }
                    reconciled.push(obs);
                });

                return reconciled;
            }

            function getTrialTotalControlDays(trial, efficacyOverride = null) {
                const finalDays = parseFloat(trial?.FinalControlDuration);
                if (Number.isFinite(finalDays) && finalDays >= 0) {
                    const d = Math.round(finalDays);
                    return { days: d, source: 'finalized', label: `${d} days (finalized)` };
                }

                const efficacy = Array.isArray(efficacyOverride)
                    ? efficacyOverride
                    : validateEfficacyData(safeJsonParse(trial?.EfficacyDataJSON, []));
                if (efficacy.length > 0) {
                    const daas = efficacy.map(e => parseFloat(e?.daa)).filter(v => Number.isFinite(v));
                    if (daas.length > 0) {
                        const d = Math.max(0, Math.round(Math.max(...daas)));
                        return { days: d, source: 'observation', label: `${d} days (from DA-A observations)` };
                    }
                }

                const start = trial?.Date ? new Date(trial.Date) : null;
                if (start && !isNaN(start.getTime())) {
                    const d = Math.max(0, Math.round((Date.now() - start.getTime()) / (1000 * 60 * 60 * 24)));
                    return { days: d, source: 'elapsed', label: `${d} days (elapsed since application)` };
                }

                return { days: 0, source: 'unknown', label: '0 days (insufficient date data)' };
            }

            function summarizeProjectControlDays(trials) {
                const arr = Array.isArray(trials) ? trials : [];
                if (!arr.length) return 'Control days: unavailable (no trials).';
                const days = arr.map(t => getTrialTotalControlDays(t).days).filter(v => Number.isFinite(v));
                if (!days.length) return 'Control days: unavailable.';
                const mean = days.reduce((a, b) => a + b, 0) / days.length;
                const min = Math.min(...days);
                const max = Math.max(...days);
                return `Control duration across trials averaged ${mean.toFixed(1)} days (range ${min}-${max} days).`;
            }

            /**
             * Export RCBD Project Data to R Format
             * Generates R data frame and analysis script
             */
            window.exportToR = async function (projectId) {
                const project = state.projects.find(p => p.ID === projectId);
                if (!project) {
                    showToast('Project not found', 'error');
                    return;
                }

                const trials = state.trials.filter(t => t.ProjectID === projectId);
                const blocks = state.blocks.filter(b => b.ProjectID === projectId);

                if (trials.length === 0) {
                    showToast('No trials found for this project', 'error');
                    return;
                }

                showToast('Generating R export...', 'info');

                // Get RCBD statistics for the project
                const stats = calculateRCBD_Stats(project, trials, blocks);

                // Build R script
                let rScript = `# Herbicide Trial Analysis - RCBD\n`;
                rScript += `# Project: ${project.Name}\n`;
                rScript += `# Date: ${new Date().toLocaleDateString()}\n`;
                rScript += `# Exported from Herbicide Trial Management App\n\n`;

                rScript += `# Load required packages\n`;
                rScript += `if (!require("agricolae")) install.packages("agricolae")\n`;
                rScript += `library(agricolae)\n\n`;

                // Extract data for each DAA
                const daaKeys = Object.keys(stats);

                if (daaKeys.length === 0) {
                    showToast('No statistical data available', 'error');
                    return;
                }

                // Use latest DAA for demonstration
                const latestDaa = daaKeys[daaKeys.length - 1];
                const daaStats = stats[latestDaa];

                // Build data vectors
                const treatmentNames = [];
                const blockNames = [];
                const values = [];

                trials.forEach(trial => {
                    const formulation = state.formulations.find(f => f.ID === trial.FormulationID);
                    const block = blocks.find(b => b.ID === trial.BlockID);

                    if (!formulation || !block) return;

                    const efficacy = validateEfficacyData(safeJsonParse(trial.EfficacyDataJSON));
                    const observation = efficacy.find(obs => obs.daa === parseInt(latestDaa));

                    if (observation) {
                        const value = extractMetricValue(observation, project);
                        if (value !== null) {
                            treatmentNames.push(formulation.Name);
                            blockNames.push(block.Name);
                            values.push(value);
                        }
                    }
                });

                // Generate R data vectors
                rScript += `# Data\n`;
                rScript += `treatment <- c(${treatmentNames.map(t => `"${t}"`).join(', ')})\n`;
                rScript += `block <- c(${blockNames.map(b => `"${b}"`).join(', ')})\n`;
                rScript += `response <- c(${values.join(', ')})\n\n`;

                // Create data frame
                rScript += `# Create data frame\n`;
                rScript += `data <- data.frame(treatment, block, response)\n`;
                rScript += `print(head(data))\n\n`;

                // ANOVA
                rScript += `# Randomized Complete Block Design (RCBD) Analysis\n`;
                rScript += `model <- aov(response ~ treatment + block, data = data)\n`;
                rScript += `anova_table <- summary(model)\n`;
                rScript += `print(anova_table)\n\n`;

                // LSD Test
                rScript += `# LSD Test (Least Significant Difference)\n`;
                rScript += `lsd_result <- LSD.test(model, "treatment", p.adj = "none", console = TRUE)\n`;
                rScript += `print(lsd_result$groups)\n\n`;

                // Additional statistics
                rScript += `# Experimental CV\n`;
                rScript += `cv <- cv.model(model)\n`;
                rScript += `cat("Coefficient of Variation:", cv, "%\\n")\n\n`;

                // Plot
                rScript += `# Bar plot with error bars\n`;
                rScript += `library(ggplot2)\n`;
                rScript += `means <- aggregate(response ~ treatment, data = data, FUN = mean)\n`;
                rScript += `sds <- aggregate(response ~ treatment, data = data, FUN = sd)\n`;
                rScript += `plot_data <- merge(means, sds, by = "treatment")\n`;
                rScript += `colnames(plot_data) <- c("treatment", "mean", "sd")\n\n`;

                rScript += `ggplot(plot_data, aes(x = treatment, y = mean)) +\n`;
                rScript += `  geom_bar(stat = "identity", fill = "steelblue") +\n`;
                rScript += `  geom_errorbar(aes(ymin = mean - sd, ymax = mean + sd), width = 0.2) +\n`;
                rScript += `  labs(title = "${project.Name}",\n`;
                rScript += `       x = "Treatment",\n`;
                rScript += `       y = "${project.TargetMetric || 'Weed Cover'} (%)") +\n`;
                rScript += `  theme_minimal()\n`;

                // Download R script
                const blob = new Blob([rScript], { type: 'text/plain' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `${project.Name.replace(/[^a-z0-9]/gi, '_')}_RCBD_Analysis.R`;
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
                URL.revokeObjectURL(url);

                showToast('R script exported successfully!', 'success');
            }

            /**
             * Export RCBD Project Data to SAS Format
             * Generates SAS dataset and PROC GLM script
             */
            window.exportToSAS = async function (projectId) {
                const project = state.projects.find(p => p.ID === projectId);
                if (!project) {
                    showToast('Project not found', 'error');
                    return;
                }

                const trials = state.trials.filter(t => t.ProjectID === projectId);
                const blocks = state.blocks.filter(b => b.ProjectID === projectId);

                if (trials.length === 0) {
                    showToast('No trials found for this project', 'error');
                    return;
                }

                showToast('Generating SAS export...', 'info');

                const stats = calculateRCBD_Stats(project, trials, blocks);
                const daaKeys = Object.keys(stats);

                if (daaKeys.length === 0) {
                    showToast('No statistical data available', 'error');
                    return;
                }

                // Use latest DAA
                const latestDaa = daaKeys[daaKeys.length - 1];

                // Build CSV data first
                let csvData = 'Treatment,Block,Response\n';

                trials.forEach(trial => {
                    const formulation = state.formulations.find(f => f.ID === trial.FormulationID);
                    const block = blocks.find(b => b.ID === trial.BlockID);

                    if (!formulation || !block) return;

                    const efficacy = validateEfficacyData(safeJsonParse(trial.EfficacyDataJSON));
                    const observation = efficacy.find(obs => obs.daa === parseInt(latestDaa));

                    if (observation) {
                        const value = extractMetricValue(observation, project);
                        if (value !== null) {
                            csvData += `"${formulation.Name}","${block.Name}",${value}\n`;
                        }
                    }
                });

                // Build SAS program
                let sasScript = `/* Herbicide Trial Analysis - RCBD */\n`;
                sasScript += `/* Project: ${project.Name} */\n`;
                sasScript += `/* Date: ${new Date().toLocaleDateString()} */\n`;
                sasScript += `/* Exported from Herbicide Trial Management App */\n\n`;

                sasScript += `/* Import CSV data */\n`;
                sasScript += `PROC IMPORT DATAFILE="herbicide_data.csv"\n`;
                sasScript += `    OUT=work.trial_data\n`;
                sasScript += `    DBMS=CSV REPLACE;\n`;
                sasScript += `    GETNAMES=YES;\n`;
                sasScript += `RUN;\n\n`;

                sasScript += `/* RCBD Analysis using PROC GLM */\n`;
                sasScript += `PROC GLM DATA=work.trial_data;\n`;
                sasScript += `    CLASS Treatment Block;\n`;
                sasScript += `    MODEL Response = Treatment Block;\n`;
                sasScript += `    MEANS Treatment / LSD ALPHA=0.05;\n`;
                sasScript += `    MEANS Treatment / LSD ALPHA=0.01;\n`;
                sasScript += `    OUTPUT OUT=residuals R=resid;\n`;
                sasScript += `RUN;\n\n`;

                sasScript += `/* Calculate CV */\n`;
                sasScript += `PROC MEANS DATA=work.trial_data MEAN STD CV;\n`;
                sasScript += `    VAR Response;\n`;
                sasScript += `RUN;\n\n`;

                sasScript += `/* Treatment means */\n`;
                sasScript += `PROC MEANS DATA=work.trial_data MEAN STD;\n`;
                sasScript += `    CLASS Treatment;\n`;
                sasScript += `    VAR Response;\n`;
                sasScript += `RUN;\n\n`;

                sasScript += `/* Bar chart */\n`;
                sasScript += `PROC SGPLOT DATA=work.trial_data;\n`;
                sasScript += `    VBAR Treatment / RESPONSE=Response STAT=mean LIMITS=upper;\n`;
                sasScript += `    YAXIS LABEL="${project.TargetMetric || 'Weed Cover'} (%)";\n`;
                sasScript += `    TITLE "${project.Name}";\n`;
                sasScript += `RUN;\n`;

                // Create ZIP file with both CSV and SAS program
                // For simplicity, download separately

                // Download CSV
                const csvBlob = new Blob([csvData], { type: 'text/csv' });
                const csvUrl = URL.createObjectURL(csvBlob);
                const csvLink = document.createElement('a');
                csvLink.href = csvUrl;
                csvLink.download = `herbicide_data.csv`;
                document.body.appendChild(csvLink);
                csvLink.click();
                document.body.removeChild(csvLink);
                URL.revokeObjectURL(csvUrl);

                // Download SAS script
                setTimeout(() => {
                    const sasBlob = new Blob([sasScript], { type: 'text/plain' });
                    const sasUrl = URL.createObjectURL(sasBlob);
                    const sasLink = document.createElement('a');
                    sasLink.href = sasUrl;
                    sasLink.download = `${project.Name.replace(/[^a-z0-9]/gi, '_')}_RCBD_Analysis.sas`;
                    document.body.appendChild(sasLink);
                    sasLink.click();
                    document.body.removeChild(sasLink);
                    URL.revokeObjectURL(sasUrl);

                    showToast('SAS files exported successfully!', 'success');
                }, 500);
            }

            window.exportAnalysisBundle = async function (projectId) {
                const project = state.projects.find(p => p.ID === projectId);
                if (!project) {
                    showToast('Project not found', 'error');
                    return;
                }

                const trials = state.trials.filter(t => t.ProjectID === projectId);
                const blocks = state.blocks.filter(b => b.ProjectID === projectId);

                if (trials.length === 0 || blocks.length === 0) {
                    showToast('No RCBD data found for this project', 'error');
                    return;
                }

                if (typeof JSZip === 'undefined' || typeof saveAs === 'undefined') {
                    showToast('Export libraries not loaded (JSZip/FileSaver)', 'error');
                    return;
                }

                showToast('Generating analysis bundle...', 'info');

                const statsByDaa = calculateRCBD_Stats(project, trials, blocks);
                const daaKeys = Object.keys(statsByDaa).sort((a, b) => parseFloat(a) - parseFloat(b));

                if (daaKeys.length === 0) {
                    showToast('No statistical data available', 'error');
                    return;
                }

                const latestDaa = daaKeys[daaKeys.length - 1];
                const stats = statsByDaa[latestDaa];

                if (!stats || stats.error) {
                    showToast('Analysis unavailable for export (design incomplete?)', 'error');
                    return;
                }

                const csvEscape = (v) => {
                    if (v === null || v === undefined) return '';
                    const s = String(v);
                    if (/[\",\n\r]/.test(s)) return `"${s.replace(/\"/g, '""')}"`;
                    return s;
                };
                const toCsv = (headers, rows) => {
                    const head = headers.map(csvEscape).join(',');
                    const body = rows.map(r => headers.map(h => csvEscape(r[h])).join(',')).join('\n');
                    return `${head}\n${body}\n`;
                };
                const safeFileBase = (name) => String(name || 'Project').replace(/[^a-z0-9_\-]+/gi, '_').replace(/_+/g, '_').replace(/^_+|_+$/g, '');

                const latestDaaNum = parseInt(latestDaa, 10);

                const datasetRows = [];
                trials.forEach(trial => {
                    const formulation = state.formulations.find(f => f.ID === trial.FormulationID);
                    const block = blocks.find(b => b.ID === trial.BlockID);
                    if (!block) return;
                    const efficacyRaw = safeJsonParse(trial.EfficacyDataJSON, []);
                    const efficacy = validateEfficacyData(efficacyRaw);
                    const obs = efficacy.find(o => o.daa === latestDaaNum);
                    if (!obs) return;
                    const value = extractMetricValue(obs, project);
                    if (value === null || value === undefined || isNaN(value)) return;
                    datasetRows.push({
                        ProjectID: projectId,
                        ProjectName: project.Name,
                        DAA: latestDaaNum,
                        TrialID: trial.ID,
                        BlockID: block.ID,
                        BlockName: block.Name,
                        Replication: trial.Replication || '',
                        TreatmentID: trial.FormulationID || '',
                        TreatmentName: trial.FormulationName || formulation?.Name || '',
                        IsControl: String(trial.IsControl).toLowerCase() === 'true' ? 1 : 0,
                        Response: Number(value).toFixed(4),
                        Date: trial.Date || '',
                        Location: trial.Location || '',
                        Investigator: trial.InvestigatorName || ''
                    });
                });

                const anova = stats.anovaTable || {};
                const anovaRows = [
                    { Source: 'Treatment', DF: anova.treatment?.df, SS: anova.treatment?.ss, MS: anova.treatment?.ms, F: anova.treatment?.f, P: anova.treatment?.p },
                    { Source: 'Block', DF: anova.block?.df, SS: anova.block?.ss, MS: anova.block?.ms, F: anova.block?.f, P: anova.block?.p },
                    { Source: 'Error', DF: anova.error?.df, SS: anova.error?.ss, MS: anova.error?.ms, F: '', P: '' },
                    { Source: 'Total', DF: anova.total?.df, SS: anova.total?.ss, MS: '', F: '', P: '' }
                ].map(r => ({
                    Source: r.Source,
                    DF: r.DF ?? '',
                    SS: (typeof r.SS === 'number' && isFinite(r.SS)) ? r.SS.toFixed(6) : '',
                    MS: (typeof r.MS === 'number' && isFinite(r.MS)) ? r.MS.toFixed(6) : '',
                    F: (typeof r.F === 'number' && isFinite(r.F)) ? r.F.toFixed(6) : '',
                    P: (typeof r.P === 'number' && isFinite(r.P)) ? r.P.toFixed(8) : ''
                }));

                const groupingRows = (stats.treatmentStats || [])
                    .slice()
                    .sort((a, b) => (b.mean || 0) - (a.mean || 0))
                    .map(ts => ({
                        TreatmentID: ts.treatmentId,
                        TreatmentName: ts.treatmentName || (state.formulations.find(f => f.ID === ts.treatmentId)?.Name || ''),
                        Mean: (typeof ts.mean === 'number' && isFinite(ts.mean)) ? ts.mean.toFixed(6) : '',
                        SD: (typeof ts.sd === 'number' && isFinite(ts.sd)) ? ts.sd.toFixed(6) : '',
                        Group: ts.rank || '',
                        WCE: (typeof ts.wce === 'number' && isFinite(ts.wce)) ? ts.wce.toFixed(2) : ''
                    }));

                const summaryRows = [
                    { Key: 'ProjectID', Value: projectId },
                    { Key: 'ProjectName', Value: project.Name },
                    { Key: 'Metric', Value: project.Metric || '' },
                    { Key: 'ExportDAA', Value: latestDaaNum },
                    { Key: 'Blocks', Value: blocks.length },
                    { Key: 'Treatments', Value: new Set(trials.map(t => t.FormulationID)).size },
                    { Key: 'Plots', Value: trials.length },
                    { Key: 'LSD_0.05', Value: (typeof stats.lsd === 'number' && isFinite(stats.lsd)) ? stats.lsd.toFixed(6) : '' },
                    { Key: 'CV_percent', Value: (typeof stats.cv === 'number' && isFinite(stats.cv)) ? stats.cv.toFixed(3) : '' },
                    { Key: 'Treatment_F', Value: (typeof anova.treatment?.f === 'number' && isFinite(anova.treatment.f)) ? anova.treatment.f.toFixed(6) : '' },
                    { Key: 'Treatment_P', Value: (typeof anova.treatment?.p === 'number' && isFinite(anova.treatment.p)) ? anova.treatment.p.toFixed(8) : '' }
                ];

                const zip = new JSZip();
                const base = safeFileBase(project.Name);
                zip.file(`${base}_dataset_DAT${latestDaaNum}.csv`, toCsv(Object.keys(datasetRows[0] || { ProjectID: '', TrialID: '', BlockID: '', TreatmentID: '', Response: '' }), datasetRows));
                zip.file(`${base}_anova_DAT${latestDaaNum}.csv`, toCsv(['Source', 'DF', 'SS', 'MS', 'F', 'P'], anovaRows));
                zip.file(`${base}_groupings_DAT${latestDaaNum}.csv`, toCsv(['TreatmentID', 'TreatmentName', 'Mean', 'SD', 'Group', 'WCE'], groupingRows));
                zip.file(`${base}_summary_DAT${latestDaaNum}.csv`, toCsv(['Key', 'Value'], summaryRows));

                const blob = await zip.generateAsync({ type: 'blob' });
                saveAs(blob, `${base}_AnalysisBundle_DAT${latestDaaNum}.zip`);
                showToast('Analysis bundle exported successfully!', 'success');
            }

            async function generateProfessionalPdfReport() {
                const trials = state.selectedTrials.map(id => state.trials.find(t => t.ID === id)).filter(Boolean);
                if (trials.length === 0) return showToast('Select at least one trial to compare.', 'error');

                showToast('Generating Professional Report...', 'info');

                // Ensure comparison view is up to date
                runComparison();

                // CHANGED: Try to get chart, but fallback to partial PDF if unavailable
                let canvas = null;
                let chartAvailable = false;
                try {
                    canvas = await waitForElement('compare-chart', 3000);
                    if (canvas) {
                        chartAvailable = true;
                        // Wait for chart animations to complete
                        await new Promise(resolve => setTimeout(resolve, 500));
                    }
                } catch (e) {
                    console.warn('[Professional PDF] Chart unavailable:', e);
                    chartAvailable = false;
                }

                const { jsPDF } = window.jspdf;
                const doc = createPdfDoc('l', 'mm', 'a4'); // Landscape A4
                const pageWidth = doc.internal.pageSize.getWidth();

                // Header
                doc.setFillColor(13, 148, 136); // Teal 600
                doc.rect(0, 0, pageWidth, 20, 'F');
                doc.setTextColor(255, 255, 255);
                doc.setFontSize(16);
                doc.setFont(undefined, 'bold');
                doc.text("Comparative Field Trial Report", 14, 13);
                doc.setFontSize(10);

                // Chart (if available) or placeholder
                let currentY = 30;
                if (chartAvailable && canvas) {
                    const imgData = canvas.toDataURL('image/png');
                    doc.addImage(imgData, 'PNG', 10, currentY, pageWidth - 20, 100);
                    currentY = 135;
                } else {
                    // Chart unavailable message
                    doc.setFillColor(255, 243, 224); // Amber 50 background
                    doc.rect(10, currentY, pageWidth - 20, 30, 'F');
                    doc.setFillColor(217, 119, 6); // Amber 600 border
                    doc.rect(10, currentY, pageWidth - 20, 30); // Border only
                    doc.setTextColor(120, 53, 15); // Amber 900
                    doc.setFontSize(12);
                    doc.text('Warning: Comparison chart unavailable (rendering failed or insufficient data).', 14, currentY + 12);
                    doc.text('Review trial details above to interpret results.', 14, currentY + 20);
                    currentY = currentY + 35;
                    showToast('Chart unavailable - generating report with summary only.', 'warning');
                }

                // AI Executive Summary
                const summaryY = currentY + 5;
                showToast('Generating AI Insights...', 'info');
                const aiSummary = await generateTrialSummary(trials);

                // Split text to fit
                const splitText = doc.splitTextToSize(aiSummary, pageWidth - 40);
                const textHeight = splitText.length * 5; // Approx 5mm per line (font size 10 is ~3.5mm + padding)
                const boxHeight = textHeight + 20; // Add padding top/bottom

                doc.setFillColor(240, 253, 250); // Light Teal bg
                doc.rect(14, summaryY, pageWidth - 28, boxHeight, 'F');
                doc.setFontSize(11);
                doc.setTextColor(13, 148, 136); // Teal 600
                doc.text("AI Executive Summary:", 18, summaryY + 8);
                doc.setTextColor(50, 50, 50);
                doc.setFontSize(10);
                doc.text(splitText, 18, summaryY + 15);

                // Table
                const tableStartY = summaryY + boxHeight + 10; // Dynamic start based on box height
                const head = [['Metric', ...trials.map(t => t.FormulationName)]];

                // Reconstruct table data for PDF
                const rows = [
                    ['Investigator', ...trials.map(t => t.InvestigatorName || '-')],
                    ['Location', ...trials.map(t => t.Location || '-')],
                    ['Date', ...trials.map(t => formatReportDateLong(t.Date))],
                    ['Dosage', ...trials.map(t => t.Dosage || '-')],
                    ['Cost/ha', ...trials.map(t => {
                        const f = state.formulations.find(f => f.ID === t.FormulationID);
                        return f ? CURRENCY_SYMBOL + parseFloat(f.EstimatedCost || 0).toFixed(2) : '-';
                    })],
                    ['Result', ...trials.map(t => t.Result || '-')],
                    ['Weed Species', ...trials.map(t => t.WeedSpecies || '-')],
                    ['AI Cover Analysis', ...trials.map(t => {
                        const s = safeJsonParse(t.AISummariesJSON, {});
                        return s.cover || '-';
                    })],
                    ['Weather', ...trials.map(t => `${t.Temperature || ''}C, ${t.Rain || ''}mm`)],
                ];

                // Add Last Control % if chart is showing a weed
                const weedSelect = document.getElementById('compare-weed-filter');
                if (weedSelect && weedSelect.value) {
                    const selectedWeed = weedSelect.value;
                    const controlRow = [`Final ${selectedWeed} Cover%`, ...trials.map(t => {
                        const eff = validateEfficacyData(safeJsonParse(t.EfficacyDataJSON, []));
                        const last = eff.slice().sort((a, b) => (parseFloat(b?.daa) || 0) - (parseFloat(a?.daa) || 0))[0];
                        const detail = last ? (last.weedDetails || []).find(d => d.species === selectedWeed) : null;
                        return detail ? detail.cover + '%' : 'N/A';
                    })];
                    rows.push(controlRow);
                }

                doc.autoTable({
                    startY: tableStartY,
                    head: head,
                    body: rows,
                    headStyles: { fillColor: [13, 148, 136] },
                    theme: 'grid',
                    styles: { fontSize: 10, cellPadding: 2, valign: 'middle' },
                    didParseCell: function (data) {
                        // Color code "Result" row
                        if (data.row.raw[0] === 'Result' && data.column.index > 0) {
                            const text = data.cell.text[0];
                            if (text === 'Excellent') {
                                data.cell.styles.fillColor = [220, 252, 231]; // Green 100
                                data.cell.styles.textColor = [22, 101, 52];  // Green 800
                                data.cell.styles.fontStyle = 'bold';
                            } else if (text === 'Poor') {
                                data.cell.styles.fillColor = [254, 226, 226]; // Red 100
                                data.cell.styles.textColor = [153, 27, 27];   // Red 800
                            }
                        }
                    },
                    didDrawCell: function (data) {
                        // Draw bars for "Final Cover%" row
                        if (data.row.raw[0].includes('Final') && data.row.raw[0].includes('%') && data.column.index > 0) {
                            const text = data.cell.text[0];
                            const val = parseFloat(text);
                            if (!isNaN(val)) {
                                // data.cell.text = ''; // Clear text? No, keep it.
                                // Draw bar at bottom of cell
                                const x = data.cell.x + 2;
                                const y = data.cell.y + data.cell.height - 4;
                                const maxW = data.cell.width - 4;
                                const barW = (val / 100) * maxW;

                                // Background bar
                                doc.setFillColor(229, 231, 235);
                                doc.rect(x, y, maxW, 2, 'F');

                                // Value bar (Green for low cover - wait, low cover is GOOD for herbicide)
                                // High cover = Bad. Low cover = Good.
                                // So Green if val < 10, Red if val > 50?
                                // Let's use standard: Green < 15, Orange < 40, Red > 40
                                if (val < 15) doc.setFillColor(22, 163, 74);
                                else if (val < 40) doc.setFillColor(234, 179, 8);
                                else doc.setFillColor(220, 38, 38);

                                doc.rect(x, y, barW, 2, 'F');
                            }
                        }
                    }
                });

                // Footer
                const pageCount = doc.internal.getNumberOfPages();
                for (let i = 1; i <= pageCount; i++) {
                    doc.setPage(i);
                    doc.setFontSize(8);
                    doc.setTextColor(150);
                    doc.text(`Page ${i} of ${pageCount} - Weedicide Herbicide App`, pageWidth / 2, doc.internal.pageSize.getHeight() - 10, { align: 'center' });
                }

                doc.save('Comparative_Report_Pro.pdf');
                showToast('Report downloaded.', 'success');
            }


            async function generateComparisonScientificReport() {
                    const trials = state.selectedTrials.map(id => state.trials.find(t => t.ID === id)).filter(Boolean);
                    if (trials.length === 0) return showToast('Select at least one trial to compare.', 'error');
                    showToast('Generating Multi-Trial Scientific Report\u2026', 'info');
                    const { jsPDF } = window.jspdf;
                    const doc = createPdfDoc();
                    const pageWidth = doc.internal.pageSize.getWidth();
                    const pageHeight = doc.internal.pageSize.getHeight();
                    const margin = 14;
                    const maxWidth = pageWidth - 2 * margin;
                    const reportDate = formatReportDateLong(new Date());
                    const checkPage = (need, y) => { if (y + need > pageHeight - 18) { doc.addPage(); return 20; } return y; };
                    const addSectionHeader = (title, y) => {
                        y = checkPage(14, y);
                        doc.setFillColor(13, 148, 136); doc.rect(margin, y, maxWidth, 9, 'F');
                        doc.setTextColor(255, 255, 255); doc.setFontSize(12); doc.setFont(undefined, 'bold');
                        doc.text(title, margin + 3, y + 6.5);
                        doc.setTextColor(0, 0, 0); doc.setFont(undefined, 'normal'); doc.setFontSize(10);
                        return y + 13;
                    };
                    const addSubHeader = (title, y) => {
                        y = checkPage(12, y);
                        doc.setFont(undefined, 'bold'); doc.setFontSize(11); doc.setTextColor(5, 100, 90);
                        doc.text(title, margin, y);
                        doc.setTextColor(0, 0, 0); doc.setFont(undefined, 'normal'); doc.setFontSize(10);
                        return y + 7;
                    };
                    const addBodyText = (text, y, opts = {}) => {
                        doc.setFontSize(opts.fontSize || 9); doc.setFont(undefined, opts.style || 'normal');
                        const lines = doc.splitTextToSize(String(text || '').trim(), opts.width || maxWidth);
                        const lh = opts.lineHeight || 4.5;
                        const needed = lines.length * lh + 3;
                        y = checkPage(needed, y);
                        doc.text(lines, margin, y, { maxWidth: opts.width || maxWidth });
                        doc.setFont(undefined, 'normal'); doc.setFontSize(10);
                        return y + needed + (opts.gap || 0);
                    };
                    const trialData = trials.map(t => {
                        const efficacy = validateEfficacyData(safeJsonParse(t.EfficacyDataJSON, []));
                        const interp = buildTrialDataInterpretation(t, 'scientific');
                        const controlDays = getTrialTotalControlDays(t, efficacy);
                        const wce = calculateWeedControlEfficiency(efficacy);
                        const interpSection = buildResultsInterpretationSection(t, efficacy);
                        const photoTimeline = buildPhotoTimelineInterpretation(t, efficacy);
                        const methodLine = buildMethodologySentence(t, formatReportDateLong(t.Date));
                        return { t, efficacy, interp, controlDays, wce, interpSection, photoTimeline, methodLine };
                    });
                    const resultRank = { 'Excellent': 4, 'Good': 3, 'Fair': 2, 'Poor': 1 };
                    const ranked = [...trialData].sort((a, b) => (resultRank[b.t.Result] || 0) - (resultRank[a.t.Result] || 0));
                    const allLocations = [...new Set(trials.map(t => t.Location).filter(Boolean))];
                    const allFormulations = [...new Set(trials.map(t => t.FormulationName).filter(Boolean))];
                    const allSpecies = [...new Set(trials.flatMap(t => (t.WeedSpecies || '').split(',').map(s => s.trim()).filter(Boolean)))];
                    const allSpeciesFromData = [...new Set(trialData.flatMap(({ wce }) => wce.map(w => w.species)))]
                        .filter(s => s && s.toLowerCase() !== 'total' && !window.isMixedWeedPlaceholder(s))
                        .sort();
                    const datesSorted = trials.slice().sort((a, b) => new Date(a.Date) - new Date(b.Date));

                    // COVER PAGE
                    doc.setFillColor(13, 148, 136); doc.rect(0, 0, pageWidth, 55, 'F');
                    doc.setFillColor(5, 100, 82); doc.rect(0, 50, pageWidth, 5, 'F');
                    doc.setTextColor(255, 255, 255); doc.setFontSize(20); doc.setFont(undefined, 'bold');
                    doc.text('MULTI-TRIAL COMPARATIVE', pageWidth / 2, 18, { align: 'center' });
                    doc.text('SCIENTIFIC REPORT', pageWidth / 2, 30, { align: 'center' });
                    doc.setFontSize(11); doc.setFont(undefined, 'normal');
                    doc.text(`${trials.length} Trial${trials.length > 1 ? 's' : ''} Evaluated  \u2022  ${reportDate}`, pageWidth / 2, 43, { align: 'center' });
                    doc.setTextColor(0, 0, 0);
                    let y = 65;
                    doc.setFont(undefined, 'bold'); doc.setFontSize(11);
                    doc.text('Trials Included in This Report', margin, y); y += 5;
                    doc.autoTable({
                        startY: y,
                        head: [['#', 'Treatment / Formulation', 'Investigator', 'Location', 'Trial Date', 'Result']],
                        body: trials.map((t, i) => [i + 1, t.FormulationName || '-', t.InvestigatorName || '-', t.Location || '-', formatReportDateLong(t.Date), t.Result || '-']),
                        headStyles: { fillColor: [13, 148, 136] }, theme: 'grid', styles: { fontSize: 9, cellPadding: 2 }
                    });
                    y = doc.lastAutoTable.finalY + 8;
                    doc.autoTable({
                        startY: y,
                        head: [['Report Overview', '']],
                        body: [
                            ['Total Trials', trials.length], ['Unique Formulations', allFormulations.length],
                            ['Location(s)', allLocations.join(', ') || '-'],
                            ['Target Species', allSpecies.slice(0, 6).join(', ') + (allSpecies.length > 6 ? '\u2026' : '') || '-'],
                            ['Date Range', `${formatReportDateLong(datesSorted[0]?.Date)} \u2013 ${formatReportDateLong(datesSorted[datesSorted.length - 1]?.Date)}`],
                            ['Top Performer', (ranked[0]?.t.FormulationName || '-') + ' (' + (ranked[0]?.t.Result || 'N/A') + ')']
                        ],
                        headStyles: { fillColor: [30, 64, 175], fontSize: 10 }, theme: 'plain',
                        styles: { fontSize: 9, cellPadding: 3 }, columnStyles: { 0: { fontStyle: 'bold', cellWidth: 65 } }
                    });
                    y = doc.lastAutoTable.finalY + 10;

                    // SECTION 1: EXECUTIVE COMPARATIVE SUMMARY
                    doc.addPage(); y = 20;
                    y = addSectionHeader('1. Executive Comparative Summary', y);
                    const top = ranked[0]; const bottom = ranked[ranked.length - 1];
                    const goodCount = trials.filter(t => t.Result === 'Excellent' || t.Result === 'Good').length;
                    const execText = applyReportStyleGuard(
                        `This document presents a unified scientific evaluation of ${trials.length} herbicide field trial(s) conducted across ${allLocations.length} location(s) (${allLocations.join(', ') || 'N/A'}). ` +
                        `A total of ${allFormulations.length} formulation(s) \u2014 ${allFormulations.join(', ')} \u2014 were assessed for efficacy against ${allSpecies.slice(0, 5).join(', ') || 'target weed species'}.\n\n` +
                        (top ? `The highest-rated formulation was ${top.t.FormulationName} (Result: ${top.t.Result || 'N/A'}; ${top.controlDays?.label || 'control data available'}). ` : '') +
                        (bottom && bottom !== top ? `${bottom.t.FormulationName} recorded the lowest rating (${bottom.t.Result || 'N/A'}). ` : '') +
                        `${goodCount} of ${trials.length} trial(s) achieved a Good or Excellent classification.\n\n` +
                        `All efficacy values are based on visual field observation. Statistical conclusions should be interpreted in context of environmental conditions, timing, and species composition at each trial site.`
                    );
                    y = addBodyText(execText, y, { lineHeight: 5, gap: 4 });
                    y = addSubHeader('Per-Trial Classification Summary', y);
                    doc.autoTable({
                        startY: y,
                        head: [['#', 'Formulation', 'Location', 'Date', 'Classification', 'Result', 'Control Days']],
                        body: trialData.map(({ t, interp, controlDays }, i) => [i + 1, t.FormulationName || '-', t.Location || '-', formatReportDateLong(t.Date), interp.finalClassification || '-', t.Result || '-', controlDays?.label || '-']),
                        headStyles: { fillColor: [13, 148, 136] }, theme: 'striped', styles: { fontSize: 9, cellPadding: 2 }
                    });
                    y = doc.lastAutoTable.finalY + 10;
                    if (allSpeciesFromData.length) {
                        y = addSubHeader('Comparative WCE (%) by Species', y);
                        doc.autoTable({
                            startY: y,
                            head: [['Species', ...trials.map((t, i) => `#${i + 1} ${(t.FormulationName || '').substring(0, 11)}`)]],
                            body: allSpeciesFromData.map(sp => [sp, ...trialData.map(({ wce }) => { const w = wce.find(x => x.species === sp); return w ? w.wce.toFixed(1) + '%' : '-'; })]),
                            headStyles: { fillColor: [30, 64, 175] }, theme: 'grid', styles: { fontSize: 8, cellPadding: 2 }
                        });
                        y = doc.lastAutoTable.finalY + 10;
                    }

                    // SECTION 2: TRIAL PROTOCOLS & FIELD CONDITIONS
                    doc.addPage(); y = 20;
                    y = addSectionHeader('2. Trial Protocols & Field Conditions', y);
                    doc.autoTable({
                        startY: y,
                        head: [['Parameter', ...trials.map((_, i) => `Trial ${i + 1}`)]],
                        body: [
                            ['Formulation', ...trials.map(t => t.FormulationName || '-')],
                            ['Investigator', ...trials.map(t => t.InvestigatorName || '-')],
                            ['Location', ...trials.map(t => t.Location || '-')],
                            ['Trial Date', ...trials.map(t => formatReportDateLong(t.Date))],
                            ['Dosage', ...trials.map(t => t.Dosage || '-')],
                            ['Temperature (\u00b0C)', ...trials.map(t => t.Temperature || '-')],
                            ['Humidity (%)', ...trials.map(t => t.Humidity || '-')],
                            ['Wind (km/h)', ...trials.map(t => t.Windspeed || '-')],
                            ['Rain (mm)', ...trials.map(t => t.Rain || '-')],
                            ['Weed Species', ...trials.map(t => t.WeedSpecies || '-')],
                            ['Status', ...trials.map(t => t.IsCompleted ? 'Finalized' : 'Ongoing')],
                            ['Replication', ...trials.map(t => t.Replication || 'N/A')]
                        ],
                        headStyles: { fillColor: [13, 148, 136] }, theme: 'grid',
                        styles: { fontSize: 8, cellPadding: 2 }, columnStyles: { 0: { fontStyle: 'bold', cellWidth: 36 } }
                    });
                    y = doc.lastAutoTable.finalY + 10;
                    y = addSubHeader('Methodology Narratives', y);
                    for (const { t, methodLine } of trialData) {
                        y = checkPage(24, y);
                        doc.setFont(undefined, 'bold'); doc.setFontSize(9);
                        doc.text(t.FormulationName + ':', margin, y); y += 5;
                        y = addBodyText(applyReportStyleGuard(methodLine), y, { fontSize: 9, lineHeight: 4.5, gap: 4 });
                    }

                    // SECTION 3: PER-TRIAL DETAILED RESULTS
                    for (let ti = 0; ti < trialData.length; ti++) {
                        const { t, efficacy, interp, controlDays, wce, interpSection, photoTimeline } = trialData[ti];
                        doc.addPage(); y = 20;
                        y = addSectionHeader(`3.${ti + 1}  Individual Trial Results \u2014 ${t.FormulationName}`, y);
                        doc.autoTable({
                            startY: y,
                            body: [
                                ['Date', formatReportDateLong(t.Date), 'Location', t.Location || '-'],
                                ['Investigator', t.InvestigatorName || '-', 'Dosage', t.Dosage || '-'],
                                ['Classification', interp.finalClassification || t.Result || '-', 'Control Days', controlDays?.label || '-'],
                                ['Weed Species', t.WeedSpecies || '-', 'Status', t.IsCompleted ? 'Finalized' : 'Ongoing']
                            ],
                            theme: 'plain', styles: { fontSize: 9, cellPadding: 2 },
                            columnStyles: { 0: { fontStyle: 'bold', cellWidth: 34 }, 2: { fontStyle: 'bold', cellWidth: 34 } }
                        });
                        y = doc.lastAutoTable.finalY + 6;
                        y = addSubHeader('Results Narrative', y);
                        y = addBodyText(applyReportStyleGuard(interp.coverSummary), y, { fontSize: 9, lineHeight: 4.5, gap: 2 });
                        y = addSubHeader('Conclusions', y);
                        y = addBodyText(applyReportStyleGuard(interp.conclusion), y, { fontSize: 9, lineHeight: 4.5, gap: 4 });
                        if (wce.length) {
                            y = addSubHeader('Weed Control Efficiency by Species', y);
                            doc.autoTable({
                                startY: y,
                                head: [['Species', 'Initial Cover %', 'Final Cover %', 'WCE %', 'Rating']],
                                body: wce.map(w => [w.species, Number.isFinite(w.initialCover) ? w.initialCover.toFixed(1) : '-', Number.isFinite(w.finalCover) ? w.finalCover.toFixed(1) : '-', Number.isFinite(w.wce) ? w.wce.toFixed(1) : '-', w.controlRating || '-']),
                                headStyles: { fillColor: [13, 148, 136] }, theme: 'striped', styles: { fontSize: 9, cellPadding: 2 },
                                didParseCell: data => {
                                    if (data.column.index === 3 && data.section === 'body') {
                                        const v = parseFloat(data.cell.text[0]);
                                        if (!isNaN(v)) { data.cell.styles.fillColor = v >= 75 ? [220,252,231] : v >= 50 ? [254,249,195] : [254,226,226]; data.cell.styles.textColor = v >= 75 ? [22,101,52] : v >= 50 ? [113,63,18] : [153,27,27]; }
                                    }
                                }
                            });
                            y = doc.lastAutoTable.finalY + 6;
                        }
                        if (interpSection && (interpSection.paragraphs?.length || interpSection.phaseRows?.length)) {
                            y = addSubHeader(interpSection.title || 'Results Interpretation', y);
                            for (const p of (interpSection.paragraphs || [])) { y = addBodyText(applyReportStyleGuard(p), y, { fontSize: 9, lineHeight: 4.5, gap: 2 }); }
                            if (interpSection.phaseRows?.length) {
                                doc.autoTable({ startY: y, head: [['Phase', 'Window', 'Interpretation']], body: interpSection.phaseRows, headStyles: { fillColor: [13, 148, 136] }, styles: { fontSize: 8 }, theme: 'striped' });
                                y = doc.lastAutoTable.finalY + 6;
                            }
                            if (interpSection.speciesRows?.length) {
                                doc.autoTable({ startY: y, head: [['Species Group', 'Observed Performance', 'Practical Implication']], body: interpSection.speciesRows, headStyles: { fillColor: [45, 55, 72] }, styles: { fontSize: 8 }, theme: 'grid' });
                                y = doc.lastAutoTable.finalY + 8;
                            }
                        }
                        const orderedEff = [...efficacy].sort((a, b) => parseFloat(a.daa || 0) - parseFloat(b.daa || 0));
                        if (orderedEff.length) {
                            y = addSubHeader('Efficacy Timeline', y);
                            const tvResult = buildValidatedTimelineRows(orderedEff, { reportMode: true, excludeAutoGenerated: true });
                            if (tvResult.rows.length) {
                                doc.autoTable({ startY: y, head: [['DA-A', 'Species', 'Status', 'Notes']], body: tvResult.rows, headStyles: { fillColor: [13, 148, 136] }, theme: 'striped', styles: { fontSize: 8 } });
                                y = doc.lastAutoTable.finalY + 8;
                            }
                        }
                        const stats = safeJsonParse(t.StatisticsJSON, {});
                        if (stats?.anovaResults?.anovaTable) {
                            const ao = stats.anovaResults.anovaTable;
                            const nf = (v, d = 2) => Number.isFinite(Number(v)) ? Number(v).toFixed(d) : '-';
                            y = addSubHeader('Statistical Analysis (ANOVA)', y);
                            doc.autoTable({
                                startY: y, head: [['Source', 'DF', 'SS', 'MS', 'F', 'Prob']],
                                body: [['Treatments', ao.treatment?.df ?? '-', nf(ao.treatment?.ss), nf(ao.treatment?.ms), nf(ao.treatment?.f), ao.treatment?.sig || '-'], ['Blocks', ao.block?.df ?? '-', nf(ao.block?.ss), nf(ao.block?.ms), nf(ao.block?.f), ao.block?.sig || '-'], ['Error', ao.error?.df ?? '-', nf(ao.error?.ss), nf(ao.error?.ms), '-', '-'], ['Total', ao.total?.df ?? '-', nf(ao.total?.ss), '-', '-', '-']],
                                headStyles: { fillColor: [44, 62, 80] }, theme: 'grid', styles: { fontSize: 9 }
                            });
                            y = doc.lastAutoTable.finalY + 8;
                        }
                        if (photoTimeline?.rows?.length) {
                            y = addSubHeader(photoTimeline.title || 'Photo Documentation Timeline', y);
                            doc.autoTable({ startY: y, head: [['Date', 'DAA', 'Stage', 'Est. Cover', 'Interpretation']], body: photoTimeline.rows.map(r => [r.date, r.daa, r.stage, r.estimatedCover, r.interpretation]), headStyles: { fillColor: [13, 148, 136] }, styles: { fontSize: 7 }, theme: 'striped' });
                            y = doc.lastAutoTable.finalY + 4;
                            if (photoTimeline.summary) y = addBodyText(applyReportStyleGuard(photoTimeline.summary), y, { fontSize: 8, lineHeight: 4, gap: 4 });
                        }
                        if (t.Conclusion) { y = addSubHeader('Recorded Conclusion', y); y = addBodyText(t.Conclusion, y, { fontSize: 9, lineHeight: 4.5, gap: 2 }); }
                        if (t.Notes) { y = addSubHeader('Field Notes', y); y = addBodyText(t.Notes, y, { fontSize: 9, lineHeight: 4.5, gap: 2 }); }
                        const photos = safeJsonParse(t.PhotoURLs, []);
                        if (photos.length) {
                            y = checkPage(70, y); y = addSubHeader('Photo Documentation', y);
                            let xOff = margin; const mpx = 48;
                            for (const p of photos) {
                                const src = getPhotoSource(p); if (!src) continue;
                                try {
                                    const imgData = await getImageAsResizedBase64(src, 300); if (!imgData) continue;
                                    const img = new Image(); img.src = imgData;
                                    await new Promise((res, rej) => { img.onload = res; img.onerror = rej; setTimeout(rej, 4000); });
                                    const ar = img.width > 0 && img.height > 0 ? img.width / img.height : 1;
                                    const iw = ar > 1 ? mpx : mpx * ar; const ih = ar > 1 ? mpx / ar : mpx;
                                    if (xOff + iw > pageWidth - margin) { xOff = margin; y += mpx + 8; }
                                    if (y + mpx + 10 > pageHeight - 18) { doc.addPage(); y = 20; xOff = margin; }
                                    if (addImageToPdfSafe(doc, imgData, xOff, y, iw, ih)) {
                                        doc.setFontSize(7);
                                        const lbl = (p.label || (p.date ? formatReportDateLong(p.date) : '')).substring(0, 20);
                                        if (lbl) doc.text(lbl, xOff, y + ih + 3.5);
                                        xOff += mpx + 6;
                                    }
                                } catch (e) { /* skip */ }
                            }
                            y += mpx + 10;
                        }
                    }

                    // SECTION 4: COMPARATIVE CHART & FULL DATA TABLE
                    doc.addPage(); y = 20;
                    y = addSectionHeader('4. Comparative Efficacy Charts & Data', y);
                    let compChartImg = null;
                    try { compChartImg = await generateTreatmentComparisonChart(trials); } catch (e) { /* skip */ }
                    if (compChartImg && String(compChartImg).startsWith('data:image/')) {
                        y = checkPage(90, y); addImageToPdfSafe(doc, compChartImg, margin, y, maxWidth, 78); y += 82;
                        doc.setFont(undefined, 'italic'); doc.setFontSize(8);
                        doc.text('Figure 1: Mean WCE comparison across all evaluated formulations with 95% confidence intervals.', margin, y, { maxWidth });
                        doc.setFont(undefined, 'normal'); doc.setFontSize(10); y += 8;
                    }
                    try {
                        const canvas = document.getElementById('compare-chart');
                        if (canvas && canvas.width > 0) {
                            const uiImg = canvas.toDataURL('image/png');
                            y = checkPage(90, y); addImageToPdfSafe(doc, uiImg, margin, y, maxWidth, 78); y += 82;
                            doc.setFont(undefined, 'italic'); doc.setFontSize(8);
                            doc.text('Figure 2: Field assessment comparison chart (weed cover / control trend by species).', margin, y, { maxWidth });
                            doc.setFont(undefined, 'normal'); doc.setFontSize(10); y += 8;
                        }
                    } catch (e) { /* skip */ }
                    y = addSubHeader('Full Side-by-Side Comparative Data Table', y);
                    doc.autoTable({
                        startY: y,
                        head: [['Parameter', ...trials.map((t, i) => `#${i + 1} ${(t.FormulationName || '').substring(0, 12)}`)]],
                        body: [
                            ['Date', ...trials.map(t => formatReportDateLong(t.Date))],
                            ['Location', ...trials.map(t => t.Location || '-')],
                            ['Dosage', ...trials.map(t => t.Dosage || '-')],
                            ['Result', ...trials.map(t => t.Result || '-')],
                            ['Classification', ...trialData.map(({ interp }) => interp.finalClassification || '-')],
                            ['Control Days', ...trialData.map(({ controlDays }) => controlDays?.label || '-')],
                            ['Temperature', ...trials.map(t => t.Temperature ? t.Temperature + '\u00b0C' : '-')],
                            ['Rain', ...trials.map(t => t.Rain ? t.Rain + ' mm' : '-')],
                            ['Humidity', ...trials.map(t => t.Humidity ? t.Humidity + '%' : '-')],
                            ['Weed Species', ...trials.map(t => t.WeedSpecies || '-')],
                            ['Status', ...trials.map(t => t.IsCompleted ? 'Finalized' : 'Ongoing')]
                        ],
                        headStyles: { fillColor: [13, 148, 136] }, theme: 'grid',
                        styles: { fontSize: 8, cellPadding: 2 }, columnStyles: { 0: { fontStyle: 'bold', cellWidth: 36 } },
                        didParseCell: data => {
                            if (data.row.raw[0] === 'Result' && data.column.index > 0 && data.section === 'body') {
                                const v = data.cell.text[0];
                                if (v === 'Excellent') { data.cell.styles.fillColor = [220,252,231]; data.cell.styles.textColor = [22,101,52]; data.cell.styles.fontStyle = 'bold'; }
                                else if (v === 'Good') { data.cell.styles.fillColor = [219,234,254]; data.cell.styles.textColor = [30,64,175]; }
                                else if (v === 'Poor') { data.cell.styles.fillColor = [254,226,226]; data.cell.styles.textColor = [153,27,27]; }
                            }
                        }
                    });
                    y = doc.lastAutoTable.finalY + 10;

                    // SECTION 5: CONCLUSIONS & RECOMMENDATIONS
                    doc.addPage(); y = 20;
                    y = addSectionHeader('5. Comparative Conclusions & Recommendations', y);
                    y = addSubHeader('Performance Ranking', y);
                    doc.autoTable({
                        startY: y,
                        head: [['Rank', 'Formulation', 'Result', 'Classification', 'Control Days', 'Location']],
                        body: ranked.map(({ t, interp, controlDays }, i) => [i + 1, t.FormulationName || '-', t.Result || '-', interp.finalClassification || '-', controlDays?.label || '-', t.Location || '-']),
                        headStyles: { fillColor: [13, 148, 136] }, theme: 'striped', styles: { fontSize: 9, cellPadding: 2 }
                    });
                    y = doc.lastAutoTable.finalY + 8;
                    const recText = applyReportStyleGuard(
                        `Based on the comparative assessment of ${trials.length} trial(s) across ${allLocations.length} location(s), the following conclusions are drawn:\n\n` +
                        (top ? `Top-performing formulation: ${top.t.FormulationName} (${top.t.Result || 'N/A'}) \u2014 ${top.interp.conclusion || ''}\n\n` : '') +
                        (ranked.length > 1 ? `All evaluated formulations demonstrated field-measurable efficacy variation across location and environmental conditions. Protocol adherence, species targeting accuracy, and dosage precision are recommended areas for improvement in future application cycles. ` : '') +
                        `This report is generated from field-observed data. Statistical significance of any comparative claim requires replicated ANOVA-validated datasets with a minimum of three complete blocks per treatment.\n\nReport Generated: ${reportDate}`
                    );
                    y = addBodyText(recText, y, { fontSize: 9, lineHeight: 5, gap: 4 });
                    const totalPages = doc.internal.getNumberOfPages();
                    for (let pi = 1; pi <= totalPages; pi++) {
                        doc.setPage(pi); doc.setFontSize(8); doc.setTextColor(160, 160, 160);
                        doc.text(`Multi-Trial Comparative Scientific Report  \u2022  ${reportDate}  \u2022  Page ${pi} of ${totalPages}`, pageWidth / 2, pageHeight - 7, { align: 'center' });
                        doc.setTextColor(0, 0, 0);
                    }
                    const safeName = trials.map(t => (t.FormulationName || 'Trial').replace(/[^a-z0-9]/gi, '_').substring(0, 15)).join('-');
                    doc.save(`Multi_Trial_Scientific_Report_${safeName}.pdf`);
                    showToast('Multi-Trial Scientific Report generated!', 'success');
                }

            async function generatePpt(trialId) {
                const trial = state.trials.find(t => t.ID === trialId);
                if (!trial) return;
                showToast('Generating PowerPoint...', 'info');
                const chartImages = await generateScientificCharts(trial);
                // Generate new analytical charts
                const treatmentCompImg = await generateTreatmentComparisonChart([trial]);
                const heatmapImg = await generateSpeciesHeatmapChart(trial);

                const exportCtx = buildTrialExportContext(trial, 'executive');
                const efficacyData = exportCtx.efficacyData;
                const pptInterpretationSection = exportCtx.interpretationSection;
                const pptPhotoTimelineSection = exportCtx.photoTimelineSection;
                const controlDays = exportCtx.controlDays;
                const continuity = buildSpeciesContinuityTable(efficacyData);
                const envIndex = buildEnvironmentalSuitabilityIndex(trial);
                const significance = buildStatisticalSignificanceBlock(safeJsonParse(trial.StatisticsJSON, {})?.anovaResults?.anovaTable || null);
                const dosePanel = buildDoseResponseRecommendationPanel([trial], null);
                const brief = buildOnePageExecutiveBrief({
                    title: `Executive Brief - ${trial.FormulationName || 'Trial'}`,
                    objective: `Evaluate efficacy for ${trial.FormulationName || 'test treatment'} in field conditions.`,
                    keyFinding: exportCtx.derivedInterpretation.coverSummary,
                    statsNote: significance.text,
                    recommendation: dosePanel.recommendation,
                    risk: envIndex.note
                });

                const pptx = new PptxGenJS();
                pptx.layout = 'LAYOUT_16x9';

                // Slide 1: Title
                const slide1 = pptx.addSlide();
                slide1.addText('Herbicide Trial Report', { x: 1, y: 1, w: '80%', fontSize: 24, bold: true, color: '008080' });
                slide1.addText(trial.FormulationName, { x: 1, y: 2, w: '80%', fontSize: 18 });
                slide1.addText(`Investigator: ${trial.InvestigatorName}`, { x: 1, y: 3, fontSize: 14 });
                slide1.addText(`Date: ${formatReportDateLong(trial.Date)}`, { x: 1, y: 3.5, fontSize: 14 });
                slide1.addText(`Total Control Days: ${controlDays.days} (${controlDays.source})`, { x: 1, y: 4.0, fontSize: 13, color: '334155' });

                // Slide 2: AI Summary
                const summary = await generateTrialSummary([trial]); // Generate specific summary for this trial
                const slideSummary = pptx.addSlide();
                slideSummary.addText('Executive Summary', { x: 0.5, y: 0.5, fontSize: 18, color: '008080', bold: true });
                slideSummary.addText(applyReportStyleGuard(summary), { x: 1, y: 1.5, w: '80%', fontSize: 14, color: '333333' });

                const slideBrief = pptx.addSlide();
                slideBrief.addText('One-Page Executive Brief', { x: 0.5, y: 0.4, fontSize: 18, color: '008080', bold: true });
                const briefLines = [
                    `Objective: ${brief.objective}`,
                    `Key finding: ${brief.keyFinding}`,
                    `Statistical note: ${brief.statsNote}`,
                    `Environmental context: ${brief.risk}`,
                    `Recommendation: ${brief.recommendation}`
                ];
                slideBrief.addText(briefLines.map(t => applyReportStyleGuard(t)).join('\n\n'), { x: 0.8, y: 1.1, w: 12, h: 5.2, fontSize: 13, color: '1f2937', valign: 'top' });

                const slideConfidence = pptx.addSlide();
                slideConfidence.addText('Continuity and Confidence Snapshot', { x: 0.5, y: 0.4, fontSize: 18, color: '008080', bold: true });
                const continuityText = continuity.rows.length
                    ? continuity.rows.slice(0, 4).map(r => `${r.species}: continuity ${Number.isFinite(r.continuityScore) ? r.continuityScore.toFixed(1) : '-'}%, first ${r.firstDaa} DA-A, last ${r.lastDaa} DA-A`).join('\n')
                    : 'No species continuity table was available.';
                slideConfidence.addText(
                    `Statistical significance: ${significance.significant ? 'Significant' : 'Not significant'}\n` +
                    `Environmental suitability: ${envIndex.score}/100 (${envIndex.className})\n\n` +
                    `${continuityText}`,
                    { x: 0.8, y: 1.2, w: 12, h: 5.0, fontSize: 12, color: '334155', valign: 'top' }
                );

                if (chartImages.cover || chartImages.wceConfidence || chartImages.environmentSuitability || chartImages.speciesDistribution) {
                    const slideCharts = pptx.addSlide();
                    slideCharts.addText('Analytical Charts', { x: 0.5, y: 0.3, fontSize: 18, color: '008080', bold: true });
                    if (chartImages.cover && String(chartImages.cover).startsWith('data:image/')) {
                        slideCharts.addImage({ data: chartImages.cover, x: 0.5, y: 0.8, w: 6.2, h: 2.8 });
                    }
                    if (chartImages.wceConfidence && String(chartImages.wceConfidence).startsWith('data:image/')) {
                        slideCharts.addImage({ data: chartImages.wceConfidence, x: 6.9, y: 0.8, w: 6.2, h: 2.8 });
                    }
                    if (chartImages.environmentSuitability && String(chartImages.environmentSuitability).startsWith('data:image/')) {
                        slideCharts.addImage({ data: chartImages.environmentSuitability, x: 0.5, y: 3.8, w: 6.2, h: 2.8 });
                    }
                    if (chartImages.speciesDistribution && String(chartImages.speciesDistribution).startsWith('data:image/')) {
                        slideCharts.addImage({ data: chartImages.speciesDistribution, x: 6.9, y: 3.8, w: 6.0, h: 2.8 });
                    }
                } else {
                    // FALLBACK: Charts unavailable - add explanatory slide
                    const slideChartsFallback = pptx.addSlide();
                    slideChartsFallback.addText('Analytical Charts', { x: 0.5, y: 0.3, fontSize: 18, color: '008080', bold: true });
                    slideChartsFallback.addText(
                        'Warning: Charts Not Available\n\n' +
                        'Analytical charts could not be generated. This may occur if:\n\n' +
                        '- Insufficient efficacy data collected\n' +
                        '- Missing weed species observations\n' +
                        '- Incomplete trial setup or measurements\n\n' +
                        'Review the Executive Brief and detailed results above for comprehensive analysis.\n\n' +
                        'Action: Collect additional field observations or verify data entry completeness.',
                        { x: 1.5, y: 1.5, w: 11, h: 5, fontSize: 14, color: '334155', valign: 'top' }
                    );
                }

                // Slide: New Analytical Charts (Treatment Comparison + Heatmap)
                if ((treatmentCompImg && String(treatmentCompImg).startsWith('data:image/')) || (heatmapImg && String(heatmapImg).startsWith('data:image/'))) {
                    const slideNewCharts = pptx.addSlide();
                    slideNewCharts.addText('Advanced Analytics', { x: 0.5, y: 0.3, fontSize: 18, color: '008080', bold: true });
                    if (treatmentCompImg && String(treatmentCompImg).startsWith('data:image/')) {
                        slideNewCharts.addImage({ data: treatmentCompImg, x: 0.3, y: 0.8, w: 6.3, h: 3.0 });
                        slideNewCharts.addText('Treatment Comparison (WCE with 95% CI)', { x: 0.3, y: 3.9, w: 6.3, fontSize: 9, italic: true, color: '6b7280' });
                    }
                    if (heatmapImg && String(heatmapImg).startsWith('data:image/')) {
                        slideNewCharts.addImage({ data: heatmapImg, x: 6.8, y: 0.8, w: 6.3, h: 3.0 });
                        slideNewCharts.addText('Species - DAA Cover Heatmap', { x: 6.8, y: 3.9, w: 6.3, fontSize: 9, italic: true, color: '6b7280' });
                    }
                }

                // Slide: Results Interpretation
                if (pptInterpretationSection && (pptInterpretationSection.paragraphs.length || pptInterpretationSection.phaseRows.length)) {
                    const slideInterp = pptx.addSlide();
                    slideInterp.addText('Results Interpretation', { x: 0.5, y: 0.3, fontSize: 18, color: '008080', bold: true });
                    const interpLines = pptInterpretationSection.paragraphs.join('\n\n');
                    slideInterp.addText(applyReportStyleGuard(interpLines), { x: 0.8, y: 1.0, w: 12, h: 2.8, fontSize: 12, color: '1f2937', valign: 'top' });
                    if (pptInterpretationSection.phaseRows.length) {
                        const phaseTableData = pptInterpretationSection.phaseRows.map(r => r.map(cell => ({ text: String(cell), options: { fontSize: 11, color: '334155' } })));
                        slideInterp.addTable([
                            [{ text: 'Phase', options: { bold: true, fill: '0d9488', color: 'ffffff', fontSize: 11 } }, { text: 'Window', options: { bold: true, fill: '0d9488', color: 'ffffff', fontSize: 11 } }, { text: 'Interpretation', options: { bold: true, fill: '0d9488', color: 'ffffff', fontSize: 11 } }],
                            ...phaseTableData
                        ], { x: 0.5, y: 3.9, w: 12, colW: [2.5, 2.5, 7], border: { type: 'solid', color: 'e2e8f0' } });
                    }
                }

                // Slide: Photo Documentation Timeline
                if (pptPhotoTimelineSection && pptPhotoTimelineSection.rows.length) {
                    const slideTimeline = pptx.addSlide();
                    slideTimeline.addText('Photo Documentation Timeline', { x: 0.5, y: 0.3, fontSize: 18, color: '008080', bold: true });
                    const timelineTableData = pptPhotoTimelineSection.rows.slice(0, 6).map(r => [
                        { text: String(r.date || ''), options: { fontSize: 10, color: '334155' } },
                        { text: String(r.daa || ''), options: { fontSize: 10, color: '334155' } },
                        { text: String(r.stage || ''), options: { fontSize: 10, color: '334155' } },
                        { text: String(r.estimatedCover || ''), options: { fontSize: 10, color: '334155' } },
                        { text: applyReportStyleGuard(r.interpretation || ''), options: { fontSize: 10, color: '334155' } }
                    ]);
                    slideTimeline.addTable([
                        [
                            { text: 'Date', options: { bold: true, fill: '0d9488', color: 'ffffff', fontSize: 10 } },
                            { text: 'DAA', options: { bold: true, fill: '0d9488', color: 'ffffff', fontSize: 10 } },
                            { text: 'Stage', options: { bold: true, fill: '0d9488', color: 'ffffff', fontSize: 10 } },
                            { text: 'Est. Cover', options: { bold: true, fill: '0d9488', color: 'ffffff', fontSize: 10 } },
                            { text: 'Interpretation', options: { bold: true, fill: '0d9488', color: 'ffffff', fontSize: 10 } }
                        ],
                        ...timelineTableData
                    ], { x: 0.3, y: 1.0, w: 12.7, colW: [1.8, 0.9, 2.0, 1.5, 6.5], border: { type: 'solid', color: 'e2e8f0' } });
                    if (pptPhotoTimelineSection.summary) {
                        slideTimeline.addText(applyReportStyleGuard(pptPhotoTimelineSection.summary), { x: 0.8, y: 6.0, w: 12, fontSize: 11, italic: true, color: '64748b' });
                    }
                }

                // Slide 3: Photos - pre-convert ALL photos to base64 before adding
                const photos = safeJsonParse(trial.PhotoURLs).slice(0, 4);
                if (photos.length > 0) {
                    const slide2 = pptx.addSlide();
                    slide2.addText('Field Photos', { x: 0.5, y: 0.5, fontSize: 18, color: '008080' });

                    let xPos = 0.5;
                    let photosAdded = 0;
                    for (const p of photos) {
                        const photoSrc = getPhotoSource(p);
                        if (!photoSrc) continue;
                        try {
                            let base64Data = null;
                            if (String(photoSrc).startsWith('data:image/')) {
                                base64Data = photoSrc;
                            } else {
                                // Convert URL to base64 data URI before adding to PPT
                                base64Data = await getImageAsResizedBase64(photoSrc, 800);
                            }
                            if (base64Data && String(base64Data).startsWith('data:image/')) {
                                slide2.addImage({ data: base64Data, x: xPos, y: 1.5, w: 3, h: 3 });
                                xPos += 3.2;
                                photosAdded++;
                            } else {
                                console.warn('[PPT] Could not convert photo to base64, skipping');
                            }
                        } catch (imgErr) {
                            console.warn('[PPT] Image failed to load, skipping:', String(photoSrc).substring(0, 80), imgErr.message);
                        }
                    }
                    if (photosAdded > 0) {
                        slide2.addText(buildPublicationCaption(1, 'Field evidence panel', `Treatment: ${trial.FormulationName || 'NA'}.`), { x: 0.5, y: 5, w: 12, fontSize: 10, italic: true, color: '475569' });
                    }
                }

                try {
                    await pptx.writeFile({ fileName: `${trial.FormulationName}_Presentation.pptx` });
                    showToast('PPT downloaded.', 'success');
                } catch (pptErr) {
                    console.error('[PPT] Failed to write file:', pptErr);
                    showToast('PPT generation failed: ' + pptErr.message, 'error');
                }
            }

            function getExportStateSnapshot() {
                const seen = new WeakSet();
                const replacer = (key, value) => {
                    // Exclude runtime-only objects that can contain circular references.
                    if (key === 'charts') return undefined;
                    if (typeof value === 'function') return undefined;

                    if (value instanceof Map) return Array.from(value.entries());
                    if (value instanceof Set) return Array.from(value.values());

                    if (value && typeof value === 'object') {
                        if (seen.has(value)) return undefined;
                        seen.add(value);
                    }
                    return value;
                };

                const snapshot = JSON.parse(JSON.stringify(state, replacer));
                snapshot._exportMeta = {
                    exportedAt: new Date().toISOString(),
                    format: 'herbicide-export-v2'
                };
                return snapshot;
            }

            function injectStateIntoStandaloneHtml(html, exportedStateJson) {
                const marker = 'let state =';
                const idx = html.indexOf(marker);
                if (idx === -1) return null;

                const braceStart = html.indexOf('{', idx);
                if (braceStart === -1) return null;

                let depth = 0;
                let inSingle = false;
                let inDouble = false;
                let inTemplate = false;
                let escaping = false;
                let braceEnd = -1;

                for (let i = braceStart; i < html.length; i++) {
                    const ch = html[i];

                    if (escaping) {
                        escaping = false;
                        continue;
                    }

                    if (ch === '\\') {
                        escaping = true;
                        continue;
                    }

                    if (!inDouble && !inTemplate && ch === '\'' && html[i - 1] !== '\\') {
                        inSingle = !inSingle;
                        continue;
                    }
                    if (!inSingle && !inTemplate && ch === '"' && html[i - 1] !== '\\') {
                        inDouble = !inDouble;
                        continue;
                    }
                    if (!inSingle && !inDouble && ch === '`' && html[i - 1] !== '\\') {
                        inTemplate = !inTemplate;
                        continue;
                    }

                    if (inSingle || inDouble || inTemplate) continue;

                    if (ch === '{') depth++;
                    if (ch === '}') {
                        depth--;
                        if (depth === 0) {
                            braceEnd = i;
                            break;
                        }
                    }
                }

                if (braceEnd === -1) return null;

                const semicolonIdx = html.indexOf(';', braceEnd);
                if (semicolonIdx === -1) return null;

                const replacement = `let state = ${exportedStateJson};`;
                return html.slice(0, idx) + replacement + html.slice(semicolonIdx + 1);
            }

            function exportJson() {
                const exportState = getExportStateSnapshot();
                const dataStr = JSON.stringify(exportState, null, 2);
                const blob = new Blob([dataStr], { type: "application/json" });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `herbicide_data_${new Date().toISOString().split('T')[0]}.json`;
                a.click();
                URL.revokeObjectURL(url);
            }

            async function exportWithPhotos() {
                showToast('Creating ZIP archive...', 'info');
                const zip = new JSZip();
                const exportState = getExportStateSnapshot();
                zip.file("data.json", JSON.stringify(exportState, null, 2));

                const photosFolder = zip.folder("photos");
                const allPhotos = (exportState.trials || []).flatMap(t => safeJsonParse(t.PhotoURLs));

                for (let i = 0; i < allPhotos.length; i++) {
                    const p = allPhotos[i];
                    const photoSrc = getPhotoSource(p);
                    if (photoSrc) {
                        try {
                            const imgData = await getImageAsResizedBase64(photoSrc, 1000);
                            if (imgData) {
                                // Remove data:image/jpeg;base64, prefix
                                const base64Data = imgData.split(',')[1];
                                photosFolder.file(`photo_${i}.jpg`, base64Data, { base64: true });
                            }
                        } catch (e) { }
                    }
                }

                const content = await zip.generateAsync({ type: "blob" });
                const a = document.createElement('a');
                a.href = URL.createObjectURL(content);
                a.download = `herbicide_data_complete_${new Date().toISOString().split('T')[0]}.zip`;
                a.click();
                showToast('ZIP downloaded.', 'success');
            }

            function exportStandaloneHTML() {
                showToast('Generating standalone HTML...', 'info');
                const exportState = getExportStateSnapshot();
                const stateJson = JSON.stringify(exportState);
                const originalHtml = document.documentElement.outerHTML;
                const injected = injectStateIntoStandaloneHtml(originalHtml, stateJson);

                if (!injected) {
                    showToast('Standalone export failed: state block not found.', 'error');
                    return;
                }

                const blob = new Blob([injected], { type: 'text/html' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'herbicide-app-standalone.html';
                a.click();
                URL.revokeObjectURL(url);
                showToast('Standalone HTML downloaded.', 'success');
            }

            function extractEfficacyArrayAny(value) {
                let current = value;

                // Some records can be double-encoded JSON strings. Unwrap safely.
                for (let i = 0; i < 3; i++) {
                    if (typeof current !== 'string') break;
                    const trimmed = current.trim();
                    if (!trimmed) return [];
                    try {
                        current = JSON.parse(trimmed);
                    } catch (e) {
                        return [];
                    }
                }

                if (Array.isArray(current)) return current;
                if (!current || typeof current !== 'object') return [];

                if (Array.isArray(current.observations)) return current.observations;
                if (Array.isArray(current.efficacy)) return current.efficacy;
                if (Array.isArray(current.data)) return current.data;
                if (Array.isArray(current.items)) return current.items;

                // Fallback for object maps with numeric keys.
                const vals = Object.values(current);
                if (vals.length > 0 && vals.every(v => v && typeof v === 'object')) return vals;

                return [];
            }

            function scanEfficacyRepairIssues() {

                const trials = state.trials || [];
                const issues = [];
                let missingEfficacy = 0;
                let invalidEfficacy = 0;
                let hasStringDaa = 0;
                let missingWeedSpeciesField = 0;
                let missingWeedDetails = 0;
                let needsWeedSpeciesFromObs = 0;

                trials.forEach(t => {
                    const arr = extractEfficacyArrayAny(t.EfficacyDataJSON);
                    if (!arr || arr.length === 0) {
                        missingEfficacy++;
                        return;
                    }

                    const normalized = validateEfficacyData(arr);
                    if (!normalized || normalized.length === 0) {
                        invalidEfficacy++;
                        issues.push({ id: t.ID, formulation: t.FormulationName || '', date: t.Date || '', problem: 'Invalid EfficacyDataJSON (DAA/values)' });
                        return;
                    }

                    const anyStringDaa = arr.some(o => o && typeof o.daa === 'string');
                    if (anyStringDaa) hasStringDaa++;

                    const hasAnyWeedDetails = normalized.some(o => Array.isArray(o.weedDetails) && o.weedDetails.length > 0);
                    const hasAnyNonTotalWeed = normalized.some(o => (o.weedDetails || []).some(w => String(w.species || '').trim() && String(w.species).trim() !== 'Total'));

                    if (!hasAnyWeedDetails) {
                        missingWeedDetails++;
                        issues.push({ id: t.ID, formulation: t.FormulationName || '', date: t.Date || '', problem: 'No weedDetails in observations' });
                    }

                    if (!(t.WeedSpecies && String(t.WeedSpecies).trim())) {
                        missingWeedSpeciesField++;
                        if (hasAnyNonTotalWeed) {
                            needsWeedSpeciesFromObs++;
                            issues.push({ id: t.ID, formulation: t.FormulationName || '', date: t.Date || '', problem: 'WeedSpecies empty (can rebuild from observations)' });
                        }
                    }
                });

                return {
                    totals: { trials: (state.trials || []).length },
                    counts: { missingEfficacy, invalidEfficacy, hasStringDaa, missingWeedSpeciesField, missingWeedDetails, needsWeedSpeciesFromObs },
                    issues: issues.slice(0, 50)
                };
            }

            async function renderEfficacyRepairScan() {
                const summaryEl = document.getElementById('efficacy-scan-summary');
                const tableEl = document.getElementById('efficacy-scan-table');
                if (!summaryEl || !tableEl) return;

                const scan = scanEfficacyRepairIssues();
                summaryEl.innerHTML = `
                    <div class="grid grid-cols-2 md:grid-cols-3 gap-3 text-sm">
                        <div class="bg-slate-50 border border-slate-200 rounded-lg p-3 flex justify-between"><span class="text-slate-600">Trials</span><span class="font-bold text-slate-800">${scan.totals.trials}</span></div>
                        <div class="bg-slate-50 border border-slate-200 rounded-lg p-3 flex justify-between"><span class="text-slate-600">Missing efficacy</span><span class="font-bold text-amber-700">${scan.counts.missingEfficacy}</span></div>
                        <div class="bg-slate-50 border border-slate-200 rounded-lg p-3 flex justify-between"><span class="text-slate-600">Invalid efficacy</span><span class="font-bold text-amber-700">${scan.counts.invalidEfficacy}</span></div>
                        <div class="bg-slate-50 border border-slate-200 rounded-lg p-3 flex justify-between"><span class="text-slate-600">String DAA</span><span class="font-bold text-slate-800">${scan.counts.hasStringDaa}</span></div>
                        <div class="bg-slate-50 border border-slate-200 rounded-lg p-3 flex justify-between"><span class="text-slate-600">Missing WeedSpecies</span><span class="font-bold text-amber-700">${scan.counts.missingWeedSpeciesField}</span></div>
                        <div class="bg-slate-50 border border-slate-200 rounded-lg p-3 flex justify-between"><span class="text-slate-600">No weedDetails</span><span class="font-bold text-amber-700">${scan.counts.missingWeedDetails}</span></div>
                    </div>
                `;

                if (scan.issues.length === 0) {
                    tableEl.innerHTML = `<div class="text-sm text-emerald-700 bg-emerald-50 border border-emerald-200 rounded-lg p-3">No repair issues detected.</div>`;
                    return;
                }

                tableEl.innerHTML = `
                    <div class="overflow-x-auto">
                        <table class="w-full text-sm text-left">
                            <thead class="bg-slate-50 text-slate-500 font-bold uppercase text-xs">
                                <tr>
                                    <th class="p-3">Formulation</th>
                                    <th class="p-3">Date</th>
                                    <th class="p-3">Issue</th>
                                    <th class="p-3 text-right">Open</th>
                                </tr>
                            </thead>
                            <tbody class="divide-y divide-slate-100">
                                ${scan.issues.map(i => `
                                    <tr class="hover:bg-slate-50">
                                        <td class="p-3 font-medium text-slate-700">${sanitizeHTML(i.formulation)}</td>
                                        <td class="p-3">${sanitizeHTML(i.date)}</td>
                                        <td class="p-3 text-amber-800">${sanitizeHTML(i.problem)}</td>
                                        <td class="p-3 text-right">
                                            <button class="text-emerald-700 font-bold hover:underline" data-action="view-trial" data-id="${i.id}">Open</button>
                                        </td>
                                    </tr>
                                `).join('')}
                            </tbody>
                        </table>
                    </div>
                `;
            }

            async function repairSpeciesTracking(forceMode = false) {
                const progressEl = document.getElementById('efficacy-fix-progress');
                const modeLabel = forceMode ? 'FORCE re-repairing' : 'Repairing';
                if (progressEl) progressEl.innerHTML = `<span class="text-purple-700 font-semibold">? ${modeLabel} species tracking - you can keep using the app...</span>`;

                const trials = (state.trials || []).slice(); // snapshot
                // Keep Google Sheet row order (top to bottom)
                let repairedCount = 0;
                let skippedCount = 0;
                let errorCount = 0;
                let totalSpeciesAdded = 0;

                // Detailed log for user transparency
                const repairLog = [];

                // Helper: yield to the browser so UI stays responsive
                const yieldToUI = () => new Promise(resolve => setTimeout(resolve, 0));
                const PERENNIAL_WEEDS = window.PERENNIAL_WEEDS || new Set();
                let saveErrors = 0;
                let savedCount = 0;

                console.log(`[RepairSpecies] Starting repair on ${trials.length} trials...`);

                for (let ti = 0; ti < trials.length; ti++) {
                    // Yield every trial so the UI stays interactive
                    if (ti % 2 === 0) await yieldToUI();

                    const trial = trials[ti];
                    const trialLabel = trial.FormulationName || trial.TrialName || trial.ID;
                    if (progressEl) progressEl.innerHTML = `<span class="text-purple-700 font-semibold">? Checking ${ti + 1}/${trials.length}: ${sanitizeHTML(trialLabel)}... (app usable)</span>`;

                    try {
                        const eff = safeJsonParse(trial.EfficacyDataJSON);
                        if (!Array.isArray(eff) || eff.length < 2) {
                            repairLog.push({ trial: trialLabel, action: 'SKIPPED', reason: `Only ${Array.isArray(eff) ? eff.length : 0} observation(s)` });
                            skippedCount++; continue;
                        }

                        // Build master species list from trial WeedSpecies + all observations
                        const masterSpecies = new Map(); // lowercase ? canonical name
                        String(trial.WeedSpecies || '').split(',').map(w => w.trim()).filter(Boolean).forEach(w => {
                            if (!masterSpecies.has(w.toLowerCase())) masterSpecies.set(w.toLowerCase(), w);
                        });
                        eff.forEach(obs => {
                            (Array.isArray(obs.weedDetails) ? obs.weedDetails : []).forEach(wd => {
                                const sp = String(wd.species || wd.name || '').trim();
                                if (sp && sp.toLowerCase() !== 'total' && !masterSpecies.has(sp.toLowerCase())) {
                                    masterSpecies.set(sp.toLowerCase(), sp);
                                }
                            });
                        });

                        if (masterSpecies.size === 0) {
                            repairLog.push({ trial: trialLabel, action: 'SKIPPED', reason: 'No weed species found' });
                            skippedCount++; continue;
                        }

                        // Inject missing species into each observation
                        // Sort observations by DAA so we can check prior history
                        const sorted = eff.slice().sort((a, b) => (parseFloat(a.daa) || 0) - (parseFloat(b.daa) || 0));
                        let trialModified = false;

                        // Pre-compute best total cover per DAA across ALL observations at that DAA
                        // This handles cases where grid obs has Total=64% but species obs has weedCover=0
                        const totalByDaa = new Map();
                        sorted.forEach(ob => {
                            const daa = String(parseFloat(ob.daa) || 0);
                            let best = totalByDaa.get(daa) || 0;
                            const owc = parseFloat(ob.weedCover) || 0;
                            if (owc > best) best = owc;
                            (ob.weedDetails || []).forEach(wd => {
                                if (String(wd.species || '').trim().toLowerCase() === 'total') {
                                    const tc = parseFloat(wd.cover) || 0;
                                    if (tc > best) best = tc;
                                }
                            });
                            totalByDaa.set(daa, best);
                        });

                        sorted.forEach((obs, obsIdx) => {
                            if (!Array.isArray(obs.weedDetails)) obs.weedDetails = [];

                            // Retrofit autoInjected flag onto old entries that lack it
                            obs.weedDetails.forEach(wd => {
                                if (wd.autoInjected) return; // already flagged
                                const notes = String(wd.notes || '').toLowerCase();
                                if (notes.includes('auto-repaired:') || notes.includes('auto-added:') || notes.includes('auto-tracking:')
                                    || notes === 'previously present, now controlled.'
                                    || notes === 'added from prior observation history for daily species tracking.') {
                                    wd.autoInjected = true;
                                    trialModified = true;
                                }
                            });

                            // SKIP observations that have no real per-species data
                            // (only "Total" aggregate or empty - these are grid/aggregate-only entries)
                            const isAutoEntry = (wd) => {
                                if (wd.autoInjected === true) return true;
                                const notes = String(wd.notes || '').toLowerCase();
                                return notes.includes('auto-repaired:') || notes.includes('auto-added:') || notes.includes('auto-tracking:')
                                    || notes === 'previously present, now controlled.'
                                    || notes === 'added from prior observation history for daily species tracking.';
                            };
                            const realSpeciesEntries = obs.weedDetails.filter(wd => {
                                const sp = String(wd.species || '').trim().toLowerCase();
                                return sp && sp !== 'total' && !window.isMixedWeedPlaceholder(sp) && !isAutoEntry(wd);
                            });
                            if (realSpeciesEntries.length === 0) {
                                // Also clean up any previously injected auto entries from aggregate-only obs
                                const before = obs.weedDetails.length;
                                obs.weedDetails = obs.weedDetails.filter(wd => !isAutoEntry(wd));
                                if (obs.weedDetails.length < before) trialModified = true;
                                return; // skip injection
                            }
                            const presentSpecies = new Set(obs.weedDetails.map(wd => String(wd.species || '').trim().toLowerCase()));

                            // -- Cover gap redistribution: if total >> sum of species, fix underreported species --
                            // Use cross-observation total: grid obs may have Total=64% while species obs has weedCover=0
                            const obsDaa = String(parseFloat(obs.daa) || 0);
                            let obsTotalCover = totalByDaa.get(obsDaa) || 0;
                            if (obsTotalCover > 5) {
                                const realSpForGap = realSpeciesEntries; // already filtered to real non-Total
                                const realSpSum = realSpForGap.reduce((s, wd) => s + (parseFloat(wd.cover) || 0), 0);
                                const coverGap = obsTotalCover - realSpSum;

                                if (coverGap > 5) { // significant unaccounted cover
                                    const isBaselineDaa = obsDaa === '0';
                                    // Positive: notes describe LIVING species presence
                                    const presenceRx = /\b(grow|growing|green|active|actively|remain|remains|extensive|dominant|healthy|vigorous|coverage|present|spreading|established|thick|dense|mat|carpet|abundant|thriving|flowering|vegetat|sprouting|emerging|lush|persist|cover|covered|grass|grassy|weed)\b/i;
                                        const dominantRx = /across most of the plot|most of the plot|across the plot|across plot|throughout the plot|throughout plot|dominant|extensive|dense|thick|mat|carpet|abundant|widespread|majority/i;
                                        const minorRx = /\b(small|seedling|single|few|isolated|central|center|localized|specimen)\b/i;
                                    // Negative: notes describe damage/death (species is controlled, not underreported)
                                    const damageRx = /\b(brown|browning|desiccated|desiccation|wilting|wilted|chlorosis|chlorotic|necrosis|necrotic|dead|dying|burned|burning|scorched|dried|damage|damaged|suppressed|suppression|controlled|killed|die-?back|dieback)\b/i;
                                    const absenceRx = /\b(no\s+sign|absent|not\s+found|not\s+detected|not\s+present|dead|eliminated|zero\s+cover)\b/i;

                                    // At DAA 0 (baseline), include ALL species entries (even auto-injected)
                                    // because the baseline should reflect real pre-spray cover.
                                    const gapPool = isBaselineDaa
                                        ? obs.weedDetails.filter(wd => {
                                            const sp = String(wd.species || '').trim().toLowerCase();
                                            return sp && sp !== 'total' && !window.isMixedWeedPlaceholder(sp);
                                        })
                                        : realSpForGap;

                                    const underreported = gapPool.filter(wd => {
                                        const cover = parseFloat(wd.cover) || 0;
                                        if (cover > 0) return false; // already has cover, skip
                                        const notes = String(wd.notes || '');
                                        const alreadyCorrected = /Cover\s*corrected:\s*(\d+(?:\.\d+)?)%/i.test(notes);
                                        if (alreadyCorrected) return false;
                                        // Strip [QC] tags (everything after [QC] to end), [Cover corrected:], and Auto-* notes
                                        const cleanNotes = notes.replace(/\[QC\].*/gi, '').replace(/\[Cover corrected:[^\]]*\]/gi, '').replace(/Auto-repaired:.*/gi, '').replace(/Auto-added:.*/gi, '').replace(/Auto-tracking:.*/gi, '').trim();
                                        if (damageRx.test(cleanNotes)) return false; // damaged/dead ? not underreported
                                        if (absenceRx.test(cleanNotes)) return false;
                                        if (isBaselineDaa) {
                                            // At baseline: any non-damage notes indicate weed was present
                                            return cleanNotes.length > 0;
                                        }
                                        if (!presenceRx.test(cleanNotes)) return false;
                                            const dominantEvidence = dominantRx.test(cleanNotes);
                                            if (minorRx.test(cleanNotes) && !dominantEvidence) return false;
                                            if (coverGap > 20 && !dominantEvidence) return false;
                                            return true;
                                    });

                                    if (underreported.length > 0) {
                                        const share = Math.round((coverGap / underreported.length) * 10) / 10;
                                        underreported.forEach(wd => {
                                            wd.cover = share;
                                            // Promote auto-injected to real entry now that it has a cover value
                                            if (wd.autoInjected) wd.autoInjected = false;
                                            // Dedup: replace any existing correction note instead of appending
                                            wd.notes = window.upsertCoverCorrectionNote(wd.notes, `${share}% redistributed from total ${obsTotalCover}% gap`);
                                            trialModified = true;
                                        });
                                    }
                                }
                            }

                            // Helper: find the peak (max) real cover for a species in earlier observations
                            const getPeakPriorCover = (spLower) => {
                                let peak = 0;
                                for (let pi = 0; pi < obsIdx; pi++) {
                                    const priorObs = sorted[pi];
                                    const priorDetail = (priorObs.weedDetails || []).find(wd => {
                                        const psp = String(wd.species || '').trim().toLowerCase();
                                        return psp === spLower && psp !== 'total' && !isAutoEntry(wd);
                                    });
                                    if (priorDetail) {
                                        const pc = parseFloat(priorDetail.cover) || 0;
                                        if (pc > peak) peak = pc;
                                    }
                                }
                                return peak;
                            };

                            masterSpecies.forEach((canonicalName, spLower) => {
                                if (!presentSpecies.has(spLower)) {
                                    const peakCover = getPeakPriorCover(spLower);
                                    const bio = window.getWeedBiology(spLower);
                                    let smartStatus, statusNote;
                                    if (peakCover > 0) {
                                        // Species was present before, now at 0% ? compute graded status
                                        const controlPct = 100; // cover went to 0
                                        const graded = window.getGradedWeedStatus(controlPct, bio.isPerennial, bio.lifecycle);
                                        smartStatus = graded.grade;
                                        statusNote = `Auto-repaired: was ${peakCover.toFixed(0)}% ? now 0% (${graded.label})`;
                                    } else {
                                        smartStatus = 'Not detected';
                                        statusNote = 'Auto-repaired: species tracked in other observations';
                                    }
                                    obs.weedDetails.push({
                                        species: canonicalName,
                                        cover: 0,
                                        status: smartStatus,
                                        autoInjected: true,
                                        notes: statusNote
                                    });
                                    totalSpeciesAdded++;
                                    trialModified = true;
                                }
                            });

                            // -- Re-evaluate statuses of existing auto-injected entries using graded system --
                            obs.weedDetails.forEach(wd => {
                                if (!wd.autoInjected) return;
                                const spLower = String(wd.species || '').trim().toLowerCase();
                                if (!spLower || spLower === 'total') return;
                                if (window.isMixedWeedPlaceholder && window.isMixedWeedPlaceholder(spLower)) {
                                    if (wd.status !== 'Baseline reference') {
                                        wd.status = 'Baseline reference';
                                        trialModified = true;
                                    }
                                    return;
                                }
                                const peakCover = getPeakPriorCover(spLower);
                                const bio = window.getWeedBiology(spLower);
                                const currentCover = parseFloat(wd.cover) || 0;
                                let correctStatus;
                                if (peakCover > 0) {
                                    const controlPct = Math.max(0, Math.min(100, (1 - currentCover / peakCover) * 100));
                                    correctStatus = window.getGradedWeedStatus(controlPct, bio.isPerennial, bio.lifecycle).grade;
                                } else {
                                    correctStatus = bio.lifecycle === 'Unknown' ? 'Suppressed' : 'Not detected';
                                }
                                if (wd.status !== correctStatus) {
                                    wd.status = correctStatus;
                                    trialModified = true;
                                }
                            });

                            // -- Sanity-check & grade REAL (AI-assigned) statuses --
                            obs.weedDetails.forEach(wd => {
                                if (wd.autoInjected) return;
                                const sp = String(wd.species || '').trim().toLowerCase();
                                if (!sp || sp === 'total') return;
                                if (window.isMixedWeedPlaceholder && window.isMixedWeedPlaceholder(sp)) {
                                    if (wd.status !== 'Baseline reference') {
                                        wd.status = 'Baseline reference';
                                        trialModified = true;
                                    }
                                    return;
                                }

                                if ((parseFloat(wd.cover) || 0) <= 0.1 && /\[Cover corrected:[^\]]*\]/i.test(String(wd.notes || ''))) {
                                    wd.notes = String(wd.notes || '').replace(/\s*\[Cover corrected:[^\]]*\]/gi, '').trim();
                                    trialModified = true;
                                }

                                // 1. Ensure every species has numeric cover
                                if (wd.cover === null || wd.cover === undefined || wd.cover === '' || wd.cover === '-') {
                                    wd.cover = 0;
                                    trialModified = true;
                                }
                                const cover = parseFloat(wd.cover) || 0;
                                const st = String(wd.status || '').toLowerCase();
                                const notesText = String(wd.notes || '');
                                const deadRx = /\b(brown|browning|desiccated|desiccation|wilting|wilted|chlorosis|chlorotic|necrosis|necrotic|dead|dying|burned|burning|scorched|dried|suppressed|suppression|controlled|killed|die-?back|dieback)\b/i;
                                const growthRx = /\b(regrowth|re-emerg|re-grow|new\s+growth|new\s+green|seedling|sprouting|emerging|active\s+growth|green\s+shoot)\b/i;

                                // 2. Compute proper graded status from peak cover
                                const peakCover = getPeakPriorCover(sp);
                                const bio = window.getWeedBiology(sp);
                                if (peakCover > 0) {
                                    const controlPct = Math.max(0, Math.min(100, (1 - cover / peakCover) * 100));
                                    const graded = window.getGradedWeedStatus(controlPct, bio.isPerennial, bio.lifecycle);
                                    // "Controlled" is NEVER valid when cover > 0 (weed is still present)
                                    if (st === 'controlled' && cover > 0) {
                                        wd.status = (bio.regrowthRisk && cover > 5) ? 'Regrowth' : graded.grade;
                                        trialModified = true;
                                    } else if (st === 'unaffected' && controlPct >= 20) {
                                        wd.status = graded.grade;
                                        trialModified = true;
                                    }
                                } else {
                                    // No prior cover: fix only obviously wrong statuses
                                    if (st === 'controlled' && cover > 0) {
                                        wd.status = 'Regrowth';
                                        trialModified = true;
                                    } else if (bio.lifecycle === 'Unknown' && cover > 0 && (!wd.status || st === 'not detected')) {
                                        wd.status = 'Suppressed';
                                        trialModified = true;
                                    }
                                }

                                // 3. "Unaffected" at 0%: if species was present earlier, grade it
                                if (cover === 0 && st === 'unaffected' && peakCover > 0) {
                                    wd.status = window.getGradedWeedStatus(100, bio.isPerennial, bio.lifecycle).grade;
                                    trialModified = true;
                                }

                                // 3b. "Burndown" at 0% for perennial weeds is scientifically Top-kill.
                                if (cover === 0 && st === 'burndown' && peakCover > 0 && bio.isPerennial) {
                                    wd.status = 'Top-kill';
                                    trialModified = true;
                                }

                                // 4. "Re-emerged" requires prior cover to have actually dropped
                                if (st === 're-emerged' && obsIdx > 0) {
                                    let lowestPrior = Infinity;
                                    for (let pi = 0; pi < obsIdx; pi++) {
                                        const priorObs = sorted[pi];
                                        const priorDetail = (priorObs.weedDetails || []).find(pw => {
                                            const psp = String(pw.species || '').trim().toLowerCase();
                                            return psp === sp && !isAutoEntry(pw);
                                        });
                                        if (priorDetail) {
                                            const pc = parseFloat(priorDetail.cover);
                                            if (isFinite(pc) && pc < lowestPrior) lowestPrior = pc;
                                        }
                                    }
                                    if (lowestPrior > 10) {
                                        wd.status = cover > 10 ? 'Persistent' : 'Unaffected';
                                        trialModified = true;
                                    }
                                }

                                // 5. Regrowth detection: cover increased after prior suppression
                                if (obsIdx > 0 && cover > 5) {
                                    let previousCover = null;
                                    let highestPrior = 0, lowestAfterPeak = Infinity, foundPeak = false;
                                    for (let pi = 0; pi < obsIdx; pi++) {
                                        const priorObs = sorted[pi];
                                        const priorDetail = (priorObs.weedDetails || []).find(pw => {
                                            const psp = String(pw.species || '').trim().toLowerCase();
                                            return psp === sp && !isAutoEntry(pw);
                                        });
                                        if (priorDetail) {
                                            const pc = parseFloat(priorDetail.cover) || 0;
                                            previousCover = pc;
                                            if (pc > highestPrior) { highestPrior = pc; foundPeak = true; }
                                            if (foundPeak && pc < lowestAfterPeak) lowestAfterPeak = pc;
                                        }
                                    }
                                    // Strict rule: if previous cover exists and current cover increased, mark regrowth.
                                    if (previousCover !== null && previousCover > 0 && cover > previousCover) {
                                        wd.status = 'Regrowth';
                                        trialModified = true;
                                    }
                                    // Regrowth = had high baseline ? dropped significantly ? now increased again
                                    if (highestPrior > 10 && lowestAfterPeak < highestPrior * 0.5 && cover > lowestAfterPeak + 10) {
                                        wd.status = 'Regrowth';
                                        trialModified = true;
                                    }
                                }

                                // Status/notes consistency: dead-note cannot remain Regrowth without growth evidence.
                                // Exception: if cover > 20%, observed biomass is ground truth - stale dead notes are overridden.
                                const currentStatus = String(wd.status || '').toLowerCase();
                                if (currentStatus === 'regrowth' && deadRx.test(notesText) && !growthRx.test(notesText) && !(cover > 20)) {
                                    wd.status = bio.isPerennial ? 'Top-kill' : 'Controlled';
                                    trialModified = true;
                                }
                            });

                            // -- Cover consistency: species cannot exceed reconciled Total --
                            let reconciledTotal = parseFloat(obs.weedCover);
                            // Also check Total weedDetails entry
                            const totalWdCons = obs.weedDetails.find(wd => String(wd.species || '').trim().toLowerCase() === 'total');
                            if (totalWdCons && (!isFinite(reconciledTotal) || reconciledTotal === 0)) {
                                reconciledTotal = parseFloat(totalWdCons.cover) || 0;
                            }
                            const isReconciled = obs.weedCoverMode === 'reconciled' || obs.weedCoverMode === 'grid-manual';
                            if (isReconciled && isFinite(reconciledTotal) && reconciledTotal >= 0) {
                                const realSpecies = obs.weedDetails.filter(wd => {
                                    const s = String(wd.species || '').trim().toLowerCase();
                                    return s && s !== 'total' && !wd.autoInjected;
                                });
                                const speciesSum = realSpecies.reduce((sum, wd) => sum + (parseFloat(wd.cover) || 0), 0);
                                if (speciesSum > 0 && speciesSum > reconciledTotal * 1.1) {
                                    // Species covers collectively exceed reconciled total - scale proportionally
                                    const scaleFactor = reconciledTotal / speciesSum;
                                    realSpecies.forEach(wd => {
                                        const oldCover = parseFloat(wd.cover) || 0;
                                        if (oldCover > 0) {
                                            wd.cover = Math.round(oldCover * scaleFactor * 10) / 10;
                                            trialModified = true;
                                        }
                                    });
                                }
                            }
                        });

                        if (forceMode && !trialModified) {
                            // Force mode: re-save even if no new changes detected
                            trialModified = true;
                        }
                        if (!trialModified) {
                            repairLog.push({ trial: trialLabel, action: 'SKIPPED', reason: 'Already up-to-date (no changes needed)' });
                            skippedCount++; continue;
                        }

                        // -- DAA 0 Golden Rules: baseline must be correct before anything else --
                        // Rule 1: controlPct at baseline must be 0 (no spray applied yet)
                        // Rule 2: weed status at baseline must be 'Unaffected' (cover>0) or 'Not detected' (cover=0)
                        // Rule 3: mark first observation as isBaseline
                        sorted.forEach(obs => {
                            if ((parseFloat(obs.daa) || 0) !== 0) return;
                            if (!obs.isBaseline) { obs.isBaseline = true; trialModified = true; }
                            // Force both control fields to 0 at baseline, regardless of prior value.
                            if (obs.controlPct !== 0) { obs.controlPct = 0; trialModified = true; }
                            if (obs.control !== undefined && obs.control !== 0) { obs.control = 0; trialModified = true; }

                            // If baseline has total cover but species at 0 with existing correction note,
                            // restore species cover from the note value so baseline cannot remain fake-zero.
                            const baselineTotal = Math.max(
                                parseFloat(obs.weedCover) || 0,
                                ...((obs.weedDetails || []).filter(w => String(w.species || '').trim().toLowerCase() === 'total').map(w => parseFloat(w.cover) || 0))
                            );
                            if (Array.isArray(obs.weedDetails)) {
                                const zeroSpecies = [];
                                obs.weedDetails.forEach(wd => {
                                    const sp = String(wd.species || '').trim().toLowerCase();
                                    if (!sp || sp === 'total') return;
                                    let c = parseFloat(wd.cover) || 0;
                                    const noteText = String(wd.notes || '');
                                    if (c === 0) {
                                        const m = noteText.match(/Cover\s*corrected:\s*(\d+(?:\.\d+)?)%/i);
                                        if (m) {
                                            const corrected = Math.max(0, Math.min(100, parseFloat(m[1]) || 0));
                                            if (corrected > 0) {
                                                wd.cover = corrected;
                                                c = corrected;
                                                wd.autoInjected = false;
                                                trialModified = true;
                                            }
                                        }
                                    }
                                    if (c === 0) zeroSpecies.push(wd);
                                    const st = String(wd.status || '').toLowerCase();
                                    if (window.isMixedWeedPlaceholder && window.isMixedWeedPlaceholder(wd.species)) {
                                        // Placeholder status is finalized later after baseline precedence check.
                                    } else if (c > 0 && st !== 'unaffected') {
                                        wd.status = 'Unaffected'; // present before spray
                                        trialModified = true;
                                    } else if (c === 0 && st !== 'not detected') {
                                        wd.status = 'Not detected';
                                        trialModified = true;
                                    }
                                });

                                // Final fallback: if baseline total exists but all species are still zero,
                                // assign cover to a dominant candidate so control math has a real baseline.
                                const speciesRows = obs.weedDetails.filter(wd => {
                                    const sp = String(wd.species || '').trim().toLowerCase();
                                    return sp && sp !== 'total' && !window.isMixedWeedPlaceholder(sp);
                                });
                                const speciesSum = speciesRows.reduce((s, wd) => s + (parseFloat(wd.cover) || 0), 0);
                                if (baselineTotal > 5 && speciesRows.length > 0 && speciesSum < 0.1) {
                                    const dominantRx = /across most of the plot|most of the plot|across the plot|throughout the plot|dominant|extensive|dense|thick|mat|carpet|abundant|widespread|majority|grassy vegetation|grass/i;
                                    const targetCover = Math.round(baselineTotal * 10) / 10;
                                    const preferred = speciesRows.find(wd => dominantRx.test(String(wd.notes || '')));
                                    if (preferred) {
                                        preferred.cover = targetCover;
                                        preferred.status = 'Unaffected';
                                        preferred.autoInjected = false;
                                        preferred.notes = window.upsertCoverCorrectionNote(preferred.notes, `${targetCover}% redistributed from total ${targetCover}% baseline`);
                                    } else {
                                        const mixed = (obs.weedDetails || []).find(wd => window.isMixedWeedPlaceholder(String(wd.species || '')));
                                        if (mixed) {
                                            mixed.cover = targetCover;
                                            mixed.status = 'Baseline reference';
                                            mixed.autoInjected = false;
                                            mixed.notes = 'Auto-baseline: mixed weed baseline synthesized from DAA 0 total cover.';
                                        } else {
                                            obs.weedDetails.push({
                                                species: 'Mixed weed population',
                                                cover: targetCover,
                                                status: 'Baseline reference',
                                                autoInjected: false,
                                                notes: 'Auto-baseline: mixed weed baseline synthesized from DAA 0 total cover.'
                                            });
                                        }
                                    }
                                    trialModified = true;
                                } else if (baselineTotal > 5 && speciesRows.length === 0) {
                                    const syntheticCover = Math.round(baselineTotal * 10) / 10;
                                    const mixed = (obs.weedDetails || []).find(wd => window.isMixedWeedPlaceholder(String(wd.species || '')));
                                    if (mixed) {
                                        mixed.cover = syntheticCover;
                                        mixed.status = 'Baseline reference';
                                        mixed.autoInjected = false;
                                        mixed.notes = 'Auto-baseline: mixed weed baseline synthesized from DAA 0 total cover.';
                                    } else {
                                        obs.weedDetails.push({
                                            species: 'Mixed weed population',
                                            cover: syntheticCover,
                                            status: 'Baseline reference',
                                            autoInjected: false,
                                            notes: 'Auto-baseline: mixed weed baseline synthesized from DAA 0 total cover.'
                                        });
                                    }
                                    trialModified = true;
                                }

                                // Authoritative DAA 0 precedence:
                                // if real species exist, baseline and total must equal real species sum and mixed is removed.
                                const finalRealSpecies = obs.weedDetails.filter(wd => {
                                    const sp = String(wd.species || '').trim().toLowerCase();
                                    return sp && sp !== 'total' && !window.isMixedWeedPlaceholder(sp);
                                });
                                const finalRealSum = Math.max(0, Math.min(100, finalRealSpecies.reduce((s, wd) => s + (parseFloat(wd.cover) || 0), 0)));
                                if (finalRealSum > 0.1) {
                                    const beforeLen = obs.weedDetails.length;
                                    obs.weedDetails = obs.weedDetails.filter(wd => !window.isMixedWeedPlaceholder(String(wd.species || '')));
                                    if (obs.weedDetails.length !== beforeLen) trialModified = true;
                                    if (Math.abs((parseFloat(obs.weedCover) || 0) - finalRealSum) > 0.1) {
                                        obs.weedCover = finalRealSum;
                                        trialModified = true;
                                    }
                                    obs.weedCoverMode = 'reconciled';
                                    obs.weedDetails.forEach(wd => {
                                        const sp = String(wd.species || '').trim().toLowerCase();
                                        if (!sp || sp === 'total') return;
                                        const c = parseFloat(wd.cover) || 0;
                                        const wanted = c > 0.1 ? 'Unaffected' : 'Not detected';
                                        if (String(wd.status || '') !== wanted) {
                                            wd.status = wanted;
                                            trialModified = true;
                                        }
                                    });
                                } else {
                                    const baseline = Math.max(0, Math.min(100, parseFloat(obs.weedCover) || 0));
                                    let mixed = (obs.weedDetails || []).find(wd => window.isMixedWeedPlaceholder(String(wd.species || '')));
                                    if (!mixed) {
                                        obs.weedDetails.push({
                                            species: 'Mixed weed population',
                                            cover: baseline,
                                            status: 'Baseline reference',
                                            autoInjected: false,
                                            notes: 'Auto-baseline: mixed weed baseline synthesized from DAA 0 total cover.'
                                        });
                                        mixed = obs.weedDetails[obs.weedDetails.length - 1];
                                        trialModified = true;
                                    }
                                    if ((parseFloat(mixed.cover) || 0) !== baseline) { mixed.cover = baseline; trialModified = true; }
                                    if (String(mixed.status || '') !== 'Baseline reference') { mixed.status = 'Baseline reference'; trialModified = true; }
                                }
                            }
                        });

                        // Recalculate weedCover and sync Total entries across observations
                        // Build a map of best species sum per DAA (from whichever obs has the species)
                        const speciesSumByDaa = new Map();
                        eff.forEach(obs => {
                            const daa = String(parseFloat(obs.daa) || 0);
                            const realDetails = (obs.weedDetails || []).filter(w => {
                                const sp = String(w.species || '').toLowerCase();
                                return sp && sp !== 'total' && !window.isMixedWeedPlaceholder(sp) && !w.autoInjected;
                            });
                            const realSum = realDetails.reduce((s, w) => s + (parseFloat(w.cover) || 0), 0);
                            const prev = speciesSumByDaa.get(daa) || 0;
                            if (realSum > prev) speciesSumByDaa.set(daa, realSum);
                        });

                        eff.forEach(obs => {
                            const daa = String(parseFloat(obs.daa) || 0);
                            const realDetails = (obs.weedDetails || []).filter(w => {
                                const sp = String(w.species || '').toLowerCase();
                                return sp && sp !== 'total' && !window.isMixedWeedPlaceholder(sp) && !w.autoInjected;
                            });
                            const thisObsSum = realDetails.reduce((s, w) => s + (parseFloat(w.cover) || 0), 0);
                            // Use cross-observation species sum for this DAA
                            const bestSpeciesSum = Math.min(100, speciesSumByDaa.get(daa) || 0);

                            // DAA 0 hard rule: real species sum is the authoritative baseline when present.
                            if (daa === '0') {
                                if (bestSpeciesSum > 0.1) {
                                    obs.weedCover = bestSpeciesSum;
                                    obs.weedCoverMode = 'reconciled';
                                    const beforeLen = (obs.weedDetails || []).length;
                                    obs.weedDetails = (obs.weedDetails || []).filter(w => !window.isMixedWeedPlaceholder(String(w.species || '')));
                                    if (obs.weedDetails.length !== beforeLen) trialModified = true;
                                } else {
                                    const baseline = Math.max(0, Math.min(100, parseFloat(obs.weedCover) || 0));
                                    let mixed = (obs.weedDetails || []).find(w => window.isMixedWeedPlaceholder(String(w.species || '')));
                                    if (!mixed) {
                                        obs.weedDetails.push({
                                            species: 'Mixed weed population',
                                            cover: baseline,
                                            status: 'Baseline reference',
                                            autoInjected: false,
                                            notes: 'Auto-baseline: mixed weed baseline synthesized from DAA 0 total cover.'
                                        });
                                        mixed = obs.weedDetails[obs.weedDetails.length - 1];
                                        trialModified = true;
                                    }
                                    mixed.cover = baseline;
                                    mixed.status = 'Baseline reference';
                                }
                                obs.controlPct = 0;
                                if (obs.control !== undefined) obs.control = 0;
                                obs.isBaseline = true;
                            }

                            if (obs.weedCoverMode === 'auto') {
                                // Auto mode: total = best species sum from any obs at this DAA
                                // Only update if this obs has real species, or use cross-obs sum
                                if (thisObsSum > 0) {
                                    obs.weedCover = Math.min(100, thisObsSum);
                                } else if (bestSpeciesSum > 0) {
                                    obs.weedCover = bestSpeciesSum;
                                }
                                // Don't zero out if no species found (may be grid-only obs)
                            }

                            // Sync "Total" weedDetails entry
                            const totalWd = (obs.weedDetails || []).find(w => String(w.species || '').trim().toLowerCase() === 'total');
                            if (totalWd) {
                                const oldTotalCover = parseFloat(totalWd.cover) || 0;
                                if (obs.weedCoverMode === 'auto') {
                                    // Auto Total should match species sum
                                    const target = thisObsSum > 0 ? Math.min(100, thisObsSum) : bestSpeciesSum;
                                    if (target > 0 && Math.abs(oldTotalCover - target) > 0.1) {
                                        totalWd.cover = target;
                                    }
                                }
                                // For reconciled obs with empty weedCover, populate from Total entry
                                if ((obs.weedCoverMode === 'reconciled' || obs.weedCoverMode === 'grid-manual') && (!obs.weedCover && obs.weedCover !== 0)) {
                                    obs.weedCover = oldTotalCover;
                                }
                                if (daa === '0' && isFinite(parseFloat(obs.weedCover))) {
                                    const want = Math.max(0, Math.min(100, parseFloat(obs.weedCover) || 0));
                                    if (Math.abs(oldTotalCover - want) > 0.1) totalWd.cover = want;
                                }
                            }
                        });

                        // Save immediately so Google Sheet updates in top-to-bottom order
                        const newJSON = JSON.stringify(eff);
                        trial.EfficacyDataJSON = newJSON;
                        if (progressEl) progressEl.innerHTML = `<span class="text-purple-700 font-semibold">? Saving ${ti + 1}/${trials.length}: ${sanitizeHTML(trialLabel)}... (Google Sheet updating now)</span>`;
                        try {
                            const url = String(state.settings.scriptUrl).replace(/\s/g, '');
                            const body = JSON.stringify({
                                action: 'updateTrialRecord',
                                payload: {
                                    id: trial.ID,
                                    EfficacyDataJSON: newJSON,
                                    spreadsheetId: state.settings.sheetId,
                                    folderId: getEffectiveFolderId()
                                },
                                auth: state.auth
                            });
                            const res = await fetch(url, {
                                method: 'POST',
                                headers: { 'Content-Type': 'text/plain;charset=utf-8' },
                                body
                            });
                            if (!res.ok) {
                                console.error(`[RepairSpecies] HTTP ${res.status} saving ${trial.ID}`);
                                saveErrors++;
                                repairLog.push({ trial: trialLabel, action: 'ERROR', reason: `Save failed: HTTP ${res.status}` });
                            } else {
                                savedCount++;
                                repairLog.push({ trial: trialLabel, action: 'REPAIRED', reason: `Modified & saved to Google Sheet immediately` });
                            }
                        } catch (saveErr) {
                            console.error(`[RepairSpecies] Save error for ${trial.ID}:`, saveErr);
                            saveErrors++;
                            repairLog.push({ trial: trialLabel, action: 'ERROR', reason: `Save failed: ${saveErr.message}` });
                        }
                        await new Promise(r => setTimeout(r, 300));
                        repairedCount++;
                    } catch (e) {
                        console.error(`[RepairSpecies] Error on trial ${trial.ID}:`, e);
                        repairLog.push({ trial: trialLabel, action: 'ERROR', reason: e.message });
                        errorCount++;
                    }
                }

                console.log(`[RepairSpecies] Processing complete. ${repairedCount} repaired, ${savedCount} saved, ${skippedCount} skipped, ${errorCount} errors.`);

                // Refresh data from backend
                await loadDataFromBackend();

                const summary = `? Species tracking repair complete!\n` +
                    `- Scanned ALL ${trials.length} trials (Google Sheet top ? bottom)\n` +
                    `- ${repairedCount} trials repaired (${savedCount} saved immediately, ${totalSpeciesAdded} species entries added)\n` +
                    `- ${skippedCount} trials skipped (already complete or no data)\n` +
                    (saveErrors > 0 ? `- ${saveErrors} save errors\n` : '') +
                    (errorCount > 0 ? `- ${errorCount} processing errors\n` : '');

                // Build detailed log HTML (collapsible)
                const repairedTrials = repairLog.filter(l => l.action === 'REPAIRED');
                const skippedTrials = repairLog.filter(l => l.action === 'SKIPPED');
                const errorTrials = repairLog.filter(l => l.action === 'ERROR');

                let detailHtml = `<pre class="text-sm text-purple-800 bg-purple-50 p-3 rounded-lg mt-2 whitespace-pre-wrap">${summary}</pre>`;

                detailHtml += `<details class="mt-2"><summary class="cursor-pointer text-sm font-semibold text-purple-700">Show detailed trial-by-trial log (${repairLog.length} trials checked)</summary>`;
                detailHtml += `<div class="max-h-64 overflow-y-auto mt-1 text-xs border rounded p-2 bg-white">`;

                if (repairedTrials.length > 0) {
                    detailHtml += `<div class="font-bold text-green-700 mt-1">REPAIRED (${repairedTrials.length}):</div>`;
                    repairedTrials.forEach(l => { detailHtml += `<div class="ml-3 text-green-800">- ${sanitizeHTML(l.trial)}</div>`; });
                }
                if (skippedTrials.length > 0) {
                    detailHtml += `<div class="font-bold text-slate-500 mt-2">? SKIPPED (${skippedTrials.length}):</div>`;
                    skippedTrials.forEach(l => { detailHtml += `<div class="ml-3 text-slate-500">- ${sanitizeHTML(l.trial)} - ${sanitizeHTML(l.reason)}</div>`; });
                }
                if (errorTrials.length > 0) {
                    detailHtml += `<div class="font-bold text-red-600 mt-2">? ERRORS (${errorTrials.length}):</div>`;
                    errorTrials.forEach(l => { detailHtml += `<div class="ml-3 text-red-600">- ${sanitizeHTML(l.trial)} - ${sanitizeHTML(l.reason)}</div>`; });
                }
                detailHtml += `</div></details>`;

                if (progressEl) progressEl.innerHTML = detailHtml;
                showToast(summary, 'success');
            }

            async function autoFixWeedLinking() {
                const progressEl = document.getElementById('efficacy-fix-progress');
                if (progressEl) progressEl.textContent = 'Preparing...';

                const trials = state.trials || [];
                let fixedCount = 0;
                let skippedCount = 0;
                let errorCount = 0;

                for (let idx = 0; idx < trials.length; idx++) {
                    const t = trials[idx];
                    if (progressEl) progressEl.textContent = `Fixing ${idx + 1}/${trials.length}...`;

                    try {
                        const arr = extractEfficacyArrayAny(t.EfficacyDataJSON);
                        if (!arr || arr.length === 0) { skippedCount++; continue; }

                        const normalized = validateEfficacyData(arr);
                        if (!normalized || normalized.length === 0) { skippedCount++; continue; }

                        const existingWeedSpecies = String(t.WeedSpecies || '').trim();
                        const speciesSet = new Set();
                        normalized.forEach(o => (o.weedDetails || []).forEach(w => {
                            const s = String(w.species || '').trim();
                            if (s && s !== 'Total' && s !== 'Unknown') speciesSet.add(s);
                        }));
                        const rebuiltWeedSpecies = [...speciesSet].join(', ');

                        const newEfficacyJson = JSON.stringify(normalized);
                        const patch = { ID: t.ID };
                        let willUpdate = false;

                        if ((t.EfficacyDataJSON || '') !== newEfficacyJson) {
                            patch.EfficacyDataJSON = newEfficacyJson;
                            willUpdate = true;
                        }

                        if (!existingWeedSpecies && rebuiltWeedSpecies) {
                            patch.WeedSpecies = rebuiltWeedSpecies;
                            willUpdate = true;
                        }

                        if (!willUpdate) { skippedCount++; continue; }

                        await apiCall('updateTrialRecord', patch, false);

                        if (patch.EfficacyDataJSON) t.EfficacyDataJSON = patch.EfficacyDataJSON;
                        if (patch.WeedSpecies) t.WeedSpecies = patch.WeedSpecies;
                        fixedCount++;
                    } catch (e) {
                        console.error(e);
                        errorCount++;
                    }
                }

                if (progressEl) progressEl.textContent = '';
                showToast(`Auto-fix done. Fixed ${fixedCount}, skipped ${skippedCount}, errors ${errorCount}.`, errorCount > 0 ? 'warning' : 'success');

                if (typeof populateWeedSpeciesDropdown === 'function') populateWeedSpeciesDropdown();
                await renderEfficacyRepairScan();
            }

            async function recalcGridCovers() {
                const progressEl = document.getElementById('grid-recalc-progress');
                if (progressEl) progressEl.textContent = 'Preparing...';

                const trials = state.trials || [];
                let updatedTrials = 0;
                let updatedObs = 0;
                let skippedObs = 0;
                let errorCount = 0;

                const round1 = (n) => Math.round(n * 10) / 10;
                const isValidCell = (cellId, gridSize) => {
                    const parts = String(cellId || '').split(',');
                    if (parts.length !== 2) return false;
                    const r = parseInt(parts[0], 10);
                    const c = parseInt(parts[1], 10);
                    return isFinite(r) && isFinite(c) && r >= 0 && c >= 0 && r < gridSize && c < gridSize;
                };

                for (let i = 0; i < trials.length; i++) {
                    const t = trials[i];
                    if (progressEl) progressEl.textContent = `Recalculating ${i + 1}/${trials.length}...`;
                    try {
                        const arr = extractEfficacyArrayAny(t.EfficacyDataJSON);
                        if (!arr || arr.length === 0) continue;

                        let changed = false;
                        arr.forEach(obs => {
                            const mode = String(obs?.weedCoverMode || '').toLowerCase();
                            const cells = Array.isArray(obs?.weedCoverGridCells) ? obs.weedCoverGridCells : null;
                            if (mode !== 'grid-manual' || !cells || cells.length === 0) {
                                skippedObs++;
                                return;
                            }
                            const gridSize = parseInt(obs?.weedCoverGridSize, 10) || parseInt(obs?.gridSize, 10) || 10;
                            const totalCells = gridSize * gridSize;
                            if (!totalCells) { skippedObs++; return; }

                            const validCells = cells.filter(c => isValidCell(c, gridSize));
                            const pct = round1((validCells.length / totalCells) * 100);

                            if (obs.weedCover !== pct) { obs.weedCover = pct; changed = true; }
                            if (obs.weedCoverGrid !== pct) { obs.weedCoverGrid = pct; changed = true; }
                            if (obs.weedCoverGridSize !== gridSize) { obs.weedCoverGridSize = gridSize; changed = true; }
                            if (validCells.length !== cells.length) { obs.weedCoverGridCells = validCells; changed = true; }
                            updatedObs++;
                        });

                        if (!changed) continue;
                        const newJson = JSON.stringify(arr);
                        await apiCall('updateTrialRecord', { ID: t.ID, EfficacyDataJSON: newJson }, false);
                        t.EfficacyDataJSON = newJson;
                        updatedTrials++;
                    } catch (e) {
                        console.error(e);
                        errorCount++;
                    }
                    await new Promise(r => setTimeout(r, 150));
                }

                if (progressEl) progressEl.textContent = `Done. Updated trials ${updatedTrials}. Updated observations ${updatedObs}. Skipped ${skippedObs}. Errors ${errorCount}.`;
                showToast(`Grid recalculation complete. Updated trials ${updatedTrials}.`, updatedTrials > 0 ? 'success' : 'info');
            }

            async function rebuildCoverAllTrials() {
                const progressEl = document.getElementById('cover-rebuild-progress');
                if (progressEl) progressEl.textContent = 'Preparing full rebuild...';

                const trials = (state.trials || []).slice(); // snapshot, same traversal style as Force Full Re-repair
                const estimatedPerTrialMs = 120;
                let updatedTrials = 0;
                let updatedObs = 0;
                let skippedNoData = 0;   // no EfficacyDataJSON / no observations
                let skippedOkay = 0;     // data already correct, nothing to change
                let errorCount = 0;

                const clamp01 = (v) => Math.max(0, Math.min(100, v));
                const toNum = (v) => {
                    if (v === null || v === undefined || v === '') return null;
                    const n = typeof v === 'number' ? v : parseFloat(v);
                    return isFinite(n) ? n : null;
                };
                const round1 = (n) => Math.round((Number(n) || 0) * 10) / 10;
                const isValidCell = (cellId, gridSize) => {
                    const parts = String(cellId || '').split(',');
                    if (parts.length !== 2) return false;
                    const r = parseInt(parts[0], 10);
                    const c = parseInt(parts[1], 10);
                    return isFinite(r) && isFinite(c) && r >= 0 && c >= 0 && r < gridSize && c < gridSize;
                };
                const getLegacyCover = (obs) => {
                    const candidates = [
                        obs?.weedCover,
                        obs?.cover,
                        obs?.weed_cover,
                        obs?.coverPct,
                        obs?.percentCover,
                        obs?.totalCover,
                        obs?.weedCoverTotal
                    ];
                    for (let i = 0; i < candidates.length; i++) {
                        const n = toNum(candidates[i]);
                        if (n !== null) return clamp01(n);
                    }
                    return null;
                };
                const getTrialSpecies = (trial) => String(trial?.WeedSpecies || '')
                    .split(',')
                    .map(s => s.trim())
                    .filter(Boolean);

                for (let i = 0; i < trials.length; i++) {
                    const t = trials[i];
                    const trialLabel = t.FormulationName || t.TrialName || t.ID;
                    if (progressEl) {
                        const remainingMs = Math.max(0, (trials.length - (i + 1)) * estimatedPerTrialMs);
                        const remainingSec = Math.ceil(remainingMs / 1000);
                        progressEl.textContent = `Rebuilding ${i + 1}/${trials.length}: ${trialLabel}... about ${remainingSec}s remaining`;
                    }

                    try {
                        const arr = extractEfficacyArrayAny(t.EfficacyDataJSON);
                        if (!arr || arr.length === 0) {
                            skippedNoData++;
                            if (progressEl) progressEl.textContent = `Skipping ${i + 1}/${trials.length}: ${trialLabel} has no efficacy observations.`;
                            continue;
                        }

                        const normalized = validateEfficacyData(arr);
                        if (!Array.isArray(normalized) || normalized.length === 0) {
                            skippedNoData++;
                            if (progressEl) progressEl.textContent = `Skipping ${i + 1}/${trials.length}: ${trialLabel} has no valid efficacy rows after normalization.`;
                            continue;
                        }

                        const originalJson = JSON.stringify(arr);
                        let changed = JSON.stringify(normalized) !== originalJson;
                        const trialSpecies = getTrialSpecies(t);

                        normalized.forEach(obs => {
                            let obsChanged = false;

                            if (!Array.isArray(obs.weedDetails) || obs.weedDetails.length === 0) {
                                const legacyCover = getLegacyCover(obs);
                                const status = String(obs?.weedStatus || obs?.status || '').trim();
                                const notes = String(obs?.notes || '').trim();

                                if (legacyCover !== null) {
                                    obs.weedDetails = [{ species: 'Total', cover: legacyCover, status, notes }];
                                    obsChanged = true;
                                } else if (trialSpecies.length > 0) {
                                    obs.weedDetails = trialSpecies.map(sp => ({ species: sp, cover: null, status: '', notes: '' }));
                                    obsChanged = true;
                                }
                            }

                            const mode = String(obs?.weedCoverMode || '').toLowerCase();
                            const cells = Array.isArray(obs?.weedCoverGridCells) ? obs.weedCoverGridCells : null;

                            if (mode === 'grid-manual' && cells && cells.length > 0) {
                                const gridSize = parseInt(obs?.weedCoverGridSize, 10) || parseInt(obs?.gridSize, 10) || 10;
                                const totalCells = gridSize * gridSize;
                                if (totalCells > 0) {
                                    const validCells = cells.filter(c => isValidCell(c, gridSize));
                                    const pct = round1((validCells.length / totalCells) * 100);
                                    if (toNum(obs.weedCover) !== pct) { obs.weedCover = pct; obsChanged = true; }
                                    if (toNum(obs.weedCoverGrid) !== pct) { obs.weedCoverGrid = pct; obsChanged = true; }
                                    if (parseInt(obs.weedCoverGridSize, 10) !== gridSize) { obs.weedCoverGridSize = gridSize; obsChanged = true; }
                                    if (validCells.length !== cells.length) { obs.weedCoverGridCells = validCells; obsChanged = true; }
                                }
                            } else {
                                const computed = window.computeObservationTotalCover(obs, t);
                                if (computed !== null && computed !== undefined) {
                                    const pct = round1(computed);
                                    if (toNum(obs.weedCover) !== pct) { obs.weedCover = pct; obsChanged = true; }
                                    if (!mode || mode === 'stored' || mode === 'legacy') {
                                        if (obs.weedCoverMode !== 'auto') { obs.weedCoverMode = 'auto'; obsChanged = true; }
                                    }
                                }
                            }

                            if (obsChanged) {
                                updatedObs++;
                                changed = true;
                            }
                        });

                        const newJson = JSON.stringify(normalized);

                        if (!changed && newJson === originalJson) {
                            skippedOkay++;
                            if (progressEl) progressEl.textContent = `Skipping ${i + 1}/${trials.length}: ${trialLabel} is already correct.`;
                            continue;
                        }

                        await apiCall('updateTrialRecord', { ID: t.ID, EfficacyDataJSON: newJson }, false);
                        t.EfficacyDataJSON = newJson;
                        updatedTrials++;
                    } catch (e) {
                        console.error(e);
                        errorCount++;
                    }

                    await new Promise(r => setTimeout(r, 120));
                }

                if (progressEl) {
                    progressEl.textContent = `Done. Updated trials ${updatedTrials} (${updatedObs} observations). Already correct: ${skippedOkay}. No data: ${skippedNoData}. Errors ${errorCount}.`;
                }
                showToast(`Full rebuild complete. Updated ${updatedTrials} trial(s). ${skippedOkay} already correct, ${skippedNoData} had no observations.`, errorCount > 0 ? 'warning' : 'success');

                if (typeof renderEfficacyRepairScan === 'function') {
                    await renderEfficacyRepairScan();
                }
            }

            function exportToCSV() {
                const trials = state.selectedTrials.map(id => state.trials.find(t => t.ID === id)).filter(Boolean);
                if (trials.length === 0) return showToast('Please select trials to export.', 'error');

                // CSV Header
                let csvContent = "Formulation,Investigator,Date,Dosage,Cost/ha,Result,Weed Species,Weather,AI Cover\n";

                trials.forEach(t => {
                    const f = state.formulations.find(f => f.ID === t.FormulationID);
                    const cost = f ? parseFloat(f.EstimatedCost || 0).toFixed(2) : '0.00';
                    const ai = safeJsonParse(t.AISummariesJSON, {});
                    const clean = (str) => `"${(str || '').replace(/"/g, '""')}"`; // Escape quotes

                    csvContent += [
                        clean(t.FormulationName),
                        clean(t.InvestigatorName),
                        t.Date,
                        clean(t.Dosage),
                        cost,
                        clean(t.Result),
                        clean(t.WeedSpecies),
                        clean(`${t.Temperature || ''}C ${t.Rain || ''}mm`),
                        clean(ai.cover)
                    ].join(',') + "\n";
                });

                const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement("a");
                link.setAttribute("href", url);
                link.setAttribute("download", `herbicide_trials_data_${new Date().toISOString().split('T')[0]}.csv`);
                link.style.visibility = 'hidden';
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
                showToast('CSV downloaded.', 'success');
            }

            function handleImport(event) {
                const file = document.getElementById('import-file-input').files[0];
                if (!file) return;

                const reader = new FileReader();
                reader.onload = (e) => {
                    try {
                        if (file.name.endsWith('.json')) {
                            const importedState = JSON.parse(e.target.result);
                            state = { ...state, ...importedState };
                            saveStateToLocalStorage(); // Mock persistence
                            initializeApp(false);
                            showToast('Data imported successfully.', 'success');
                        } else {
                            showToast('ZIP import not fully supported in this demo version.', 'info');
                        }
                    } catch (err) {
                        showToast('Invalid file format.', 'error');
                    }
                };
                reader.readAsText(file);
            }

            function saveStateToLocalStorage() {
                // Backup state to localStorage for offline recovery
                // Uses safeStringify to avoid circular reference errors
                try {
                    localStorage.setItem('backupState', safeStringify(state));
                    console.log('State backup saved successfully');
                } catch (e) {
                    console.warn('Failed to save state backup to localStorage:', e.message);
                    // Fallback: try to save only critical data
                    try {
                        const criticalData = {
                            settings: state.settings,
                            filterState: state.filterState,
                            aiChatHistory: state.aiChatHistory
                        };
                        localStorage.setItem('backupState', JSON.stringify(criticalData));
                        console.log('Critical data backup saved as fallback');
                    } catch (fallbackError) {
                        console.error('All backup attempts failed:', fallbackError);
                    }
                }
            }

            async function clearAllData(confirm = false) {
                if (!confirm) {
                    showConfirmation('Delete Everything?', 'This will wipe all data from the database.', () => clearAllData(true));
                    return;
                }

                // In a real app, this would make API calls to delete everything
                state.trials = [];
                state.formulations = [];
                state.ingredients = [];
                state.organisations = [];
                state.syncQueue = [];
                saveSyncQueue();

                await apiCall('clearAllData', {}, false); // Assuming backend support
                initializeApp();
                showToast('All data cleared.', 'success');
            }

            function runComparison() {
                const weedSelect = document.getElementById('compare-weed-filter');
                const metricSelect = document.getElementById('compare-metric-filter');

                if (!weedSelect) return;

                const selectedWeed = weedSelect.value;
                const metric = 'cover';

                // --- 1. CHART RENDERING ---
                if (!selectedWeed && metric === 'cover') {
                    document.getElementById('compare-chart-title').textContent = "Please select a weed species to compare.";
                    return;
                }

                const ctx = document.getElementById('compare-chart');
                if (ctx) {
                    if (state.charts.compareChart) state.charts.compareChart.destroy();

                    const trialsToCompare = state.selectedTrials.map(id => state.trials.find(t => t.ID === id)).filter(Boolean);

                    const datasets = trialsToCompare.map((t, i) => {
                        const efficacy = safeJsonParse(t.EfficacyDataJSON, []);
                        let dataPoints = [];

                        dataPoints = efficacy.map(obs => {
                            // Try to find in weedDetails first
                            let cover = null;
                            const detail = (obs.weedDetails || []).find(d => (d.species || '').trim() === selectedWeed);
                            if (detail) {
                                cover = detail.cover;
                            } else if (selectedWeed === (t.WeedSpecies || 'Unknown').split(',')[0].trim()) {
                                // Fallback to legacy top-level cover fields if the weed matches the main trial weed
                                cover = obs.weedCover !== undefined ? obs.weedCover : (obs.cover !== undefined ? obs.cover : null);
                            }
                            return cover !== null ? { x: parseFloat(obs.daa), y: parseFloat(cover) } : null;
                        }).filter(Boolean).sort((a, b) => a.x - b.x);

                        const colors = ['#0d9488', '#d97706', '#2563eb', '#dc2626', '#7c3aed', '#db2777'];
                        return {
                            label: t.FormulationName,
                            data: dataPoints,
                            borderColor: colors[i % colors.length],
                            backgroundColor: colors[i % colors.length],
                            fill: false,
                            tension: 0.2
                        };
                    });

                    state.charts.compareChart = new Chart(ctx, {
                        type: 'line',
                        data: { datasets },
                        options: {
                            responsive: true,
                            maintainAspectRatio: false,
                            scales: {
                                x: { type: 'linear', title: { display: true, text: 'Days After Application (DA-A)' } },
                                y: { beginAtZero: true, max: 100, title: { display: true, text: '% Cover' } }
                            },
                            plugins: {
                                legend: { position: 'top' },
                                tooltip: { mode: 'index', intersect: false }
                            }
                        }
                    });

                    document.getElementById('compare-chart-title').textContent = `% Cover Comparison: ${selectedWeed}`;
                }

                // --- 2. TABLE RENDERING ---
                const tableContainer = document.getElementById('compare-table-container');
                if (tableContainer) {
                    const trials = state.selectedTrials.map(id => state.trials.find(t => t.ID === id)).filter(Boolean);
                    if (trials.length === 0) {
                        tableContainer.innerHTML = '<p class="text-gray-500">No trials selected.</p>';
                        return;
                    }

                    // Define rows for comparison
                    const rows = [
                        { label: 'Formulation', getValue: t => t.FormulationName },
                        { label: 'Investigator', getValue: t => t.InvestigatorName || '-' },
                        { label: 'Date', getValue: t => new Date(t.Date).toLocaleDateString() },
                        { label: 'Dosage', getValue: t => t.Dosage || '-' },
                        {
                            label: 'Cost/ha', getValue: t => {
                                const f = state.formulations.find(f => f.ID === t.FormulationID);
                                return f ? CURRENCY_SYMBOL + parseFloat(f.EstimatedCost || 0).toFixed(2) : '-';
                            }
                        },
                        { label: 'Result', getValue: t => `<span class="px-2 py-0.5 rounded text-xs font-bold ${t.Result === 'Excellent' ? 'bg-green-100 text-green-800' : t.Result === 'Poor' ? 'bg-red-100 text-red-800' : 'bg-gray-100'}">${t.Result || '-'}</span>` },
                        { label: 'Weed Species', getValue: t => t.WeedSpecies || '-' },
                        { label: 'Weather', getValue: t => `${t.Temperature || '-'}°C, ${t.Rain || '-'}mm` },
                        {
                            label: 'AI Cover Analysis', getValue: t => {
                                const s = safeJsonParse(t.AISummariesJSON, {});
                                return s.cover ? `<span class="whitespace-pre-wrap text-xs block min-w-[200px]">${sanitizeHTML(s.cover)}</span>` : '-';
                            }
                        },
                    ];

                    let html = `<table class="min-w-full divide-y divide-gray-200 border text-sm">`;
                    html += `<thead class="bg-gray-50"><tr><th class="px-4 py-3 text-left font-medium text-gray-500 w-1/4">Metric</th>${trials.map(t => `<th class="px-4 py-3 text-left font-bold text-slate-800">${sanitizeHTML(t.FormulationName)}</th>`).join('')}</tr></thead>`;
                    html += `<tbody class="bg-white divide-y divide-gray-200">`;

                    rows.forEach(row => {
                        html += `<tr><td class="px-4 py-3 font-medium text-gray-900 bg-gray-50/50">${row.label}</td>${trials.map(t => `<td class="px-4 py-3 text-gray-600">${row.getValue(t)}</td>`).join('')}</tr>`;
                    });

                    // Add summary stats row if weed selected
                    if (selectedWeed && metric === 'cover') {
                        html += `<tr><td class="px-4 py-3 font-medium text-emerald-800 bg-emerald-50">Final ${sanitizeHTML(selectedWeed)} Control</td>${trials.map(t => {
                            const eff = safeJsonParse(t.EfficacyDataJSON);
                            const last = eff.sort((a, b) => b.daa - a.daa)[0];
                            const detail = last ? (last.weedDetails || []).find(d => d.species === selectedWeed) : null;
                            const cover = detail ? parseFloat(detail.cover) : -1;
                            return `<td class="px-4 py-3 font-bold ${cover < 10 && cover >= 0 ? 'text-green-600' : 'text-amber-600'}">${cover >= 0 ? cover.toFixed(1) + '%' : 'N/A'}</td>`;
                        }).join('')}</tr>`;
                    }

                    html += `</tbody></table>`;
                    tableContainer.innerHTML = html;
                }
            }

            // --- MISSING HELPERS ---

            async function fetchWithRetry(url, options = {}, retries = 3, backoff = 1000) {
                for (let i = 0; i < retries; i++) {
                    try {
                        const response = await fetch(url, options);
                        if (response.ok) return response;
                        if ([502, 503, 504].includes(response.status)) {
                            console.warn(`Fetch retry ${i+1}/${retries} for ${url} due to status ${response.status}`);
                        } else {
                            return response; // Return other errors (4xx) without retry unless logic dictates otherwise
                        }
                    } catch (err) {
                        if (i === retries - 1) throw err;
                        console.warn(`Fetch retry ${i+1}/${retries} for ${url} due to error: ${err.message}`);
                    }
                    await new Promise(resolve => setTimeout(resolve, backoff * Math.pow(2, i)));
                }
                return fetch(url, options); // Last attempt
            }

            // Soil Data Integration (Multi-Provider)
            const soilCache = {};
            async function fetchSoilData(lat, lon) {
                const latNum = parseFloat(lat);
                const lonNum = parseFloat(lon);
                if (!lat || !lon || isNaN(latNum) || isNaN(lonNum)) return null;

                const cacheKey = `${latNum.toFixed(4)},${lonNum.toFixed(4)}`;
                if (soilCache[cacheKey]) {
                    populateSoilUI(soilCache[cacheKey]);
                    return soilCache[cacheKey];
                }

                showToast('Fetching soil data...', 'info');

                let result = null;

                // 1. TRY TERTIARY (PREMIUM): Ag-Analytics (if key provided)
                if (state.settings.agAnalyticsKey) {
                    try {
                        const url = `https://api.ag-analytics.info/soil?lat=${latNum}&lon=${lonNum}`;
                        const response = await fetchWithRetry(url, { headers: { 'Ocp-Apim-Subscription-Key': state.settings.agAnalyticsKey } });
                        if (response.ok) {
                            const data = await response.json();
                            if (data && data.properties) {
                                result = {
                                    ph: data.properties.ph,
                                    clay: data.properties.clay,
                                    sand: data.properties.sand,
                                    oc: data.properties.organic_carbon,
                                    provider: 'Ag-Analytics'
                                };
                            }
                        }
                    } catch (e) { console.warn('Ag-Analytics failed, trying SoilGrids...', e); }
                }

                // 2. TRY PRIMARY: SoilGrids (ISRIC)
                if (!result) {
                    try {
                         const url = `https://rest.isric.org/soilgrids/v2.0/properties/query?lat=${latNum}&lon=${lonNum}&property=phh2o&property=clay&property=sand&property=soc&property=bdod&depth=15-30cm&value=mean`;
                         const response = await fetchWithRetry(url, {}, 6, 2000);
                        if (response.ok) {
                            const data = await response.json();
                            if (data?.properties?.layers) {
                                const extractProp = (propName, scaleFactor = 1) => {
                                    const layer = data.properties.layers.find(l => l.name === propName);
                                    if (!layer || !layer.depths || !layer.depths[0]) return null;
                                    const val = layer.depths[0].values.mean;
                                    return val ? (val / scaleFactor) : null;
                                };

                                const ph = extractProp('phh2o', 10);
                                const clay = extractProp('clay', 10);
                                const sand = extractProp('sand', 10);
                                const soc = extractProp('soc', 10);

                                if (ph || clay || sand) {
                                    result = { ph, clay, sand, oc: soc, provider: 'SoilGrids' };
                                }
                            }
                        }
                    } catch (e) { console.warn('SoilGrids failed, trying fallback...', e); }
                }

                // 3. TRY SECONDARY: Kaegro (India Optimized)
                if (!result) {
                    try {
                        showToast('Falling back to Kaegro (India)...', 'info');
                        const url = `https://corsproxy.io/?https://www.kaegro.com/farms/api/soil?lat=${latNum}&lon=${lonNum}`;
                        const response = await fetchWithRetry(url);
                        if (response.ok) {
                            const data = await response.json();
                            const s = data.soil || data;
                            const chemical = s.chemical || s.chemical_properties || {};
                            const physical = s.physical || s.physical_properties || {};

                            result = {
                                ph: chemical.ph || chemical.ph_value || null,
                                clay: physical.clay || physical.clay_percentage || null,
                                sand: physical.sand || physical.sand_percentage || null,
                                oc: chemical.organic_matter || chemical.organic_carbon || null,
                                texture: physical.texture_class || physical.texture || null,
                                provider: 'Kaegro'
                            };
                        }
                    } catch (e) { console.error('Kaegro fallback failed', e); }
                }

                if (result) {
                    // Normalize and populate
                    const soilData = {
                        ph: result.ph ? parseFloat(result.ph).toFixed(1) : '-',
                        clay: result.clay ? parseFloat(result.clay).toFixed(1) : '-',
                        sand: result.sand ? parseFloat(result.sand).toFixed(1) : '-',
                        organicCarbon: result.oc ? parseFloat(result.oc).toFixed(1) : '-',
                        texture: result.texture || calculateTextureClass(result.clay, result.sand),
                        provider: result.provider,
                        timestamp: new Date().toISOString()
                    };

                    soilCache[cacheKey] = soilData;
                    populateSoilUI(soilData);
                    showToast(`Soil data loaded via ${result.provider}`, 'success');
                    return soilData;
                }

                showToast('Failed to fetch soil data from all providers.', 'error');
                return null;
            }

            function calculateTextureClass(clay, sand) {
                if (clay === null || sand === null) return 'Unknown';
                const c = parseFloat(clay);
                const s = parseFloat(sand);
                const silt = 100 - c - s;
                if (c >= 40) return 'Clay';
                if (c >= 27) return (s >= 45) ? 'Sandy Clay Loam' : (silt >= 40) ? 'Silty Clay Loam' : 'Clay Loam';
                if (s >= 70) return (c < 15) ? 'Sand' : 'Loamy Sand / Sandy Loam';
                if (silt >= 80) return 'Silt / Silty Loam';
                return 'Loam';
            }

            function populateSoilUI(soilData) {
                const form = document.getElementById('trial-form');
                if (!form || !soilData) return;

                const panel = document.getElementById('soil-data-panel');
                if (panel) panel.classList.remove('hidden');

                const ids = ['soil-ph', 'soil-clay', 'soil-sand', 'soil-oc', 'soil-texture'];
                const keys = ['ph', 'clay', 'sand', 'organicCarbon', 'texture'];

                ids.forEach((id, i) => {
                    const el = document.getElementById(id);
                    if (el) el.textContent = soilData[keys[i]] || '-';
                });

                const hiddenField = form.querySelector('[name="soilDataJSON"]');
                if (hiddenField) hiddenField.value = JSON.stringify(soilData);
            }

            async function fetchWeather(lat, lon, date) {
                let url = '';
                try {
                    const latNum = parseFloat(lat);
                    const lonNum = parseFloat(lon);
                    if (!lat || !lon || isNaN(latNum) || isNaN(lonNum)) {
                        console.error("fetchWeather: Invalid coordinates:", lat, lon);
                        return null;
                    }
                    // Validate date format YYYY-MM-DD
                    const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
                    if (!date || typeof date !== 'string' || !dateRegex.test(date)) {
                        console.error("fetchWeather: Invalid date format:", date);
                        return null;
                    }

                    const targetDate = new Date(date);
                    if (isNaN(targetDate.getTime())) {
                        console.error("fetchWeather: Invalid Date object:", date);
                        return null;
                    }

                    const today = new Date();
                    today.setHours(0, 0, 0, 0);

                    // Calculate age of date in days
                    const diffTime = today - targetDate;
                    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

                    const dateStr = date; // YYYY-MM-DD

                    // 1. TRY PREMIUM: OpenWeatherMap (if key provided)
                    if (state.settings.openWeatherMapKey) {
                        try {
                            const unixTime = Math.floor(targetDate.getTime() / 1000);
                            const owmUrl = `https://api.openweathermap.org/data/3.0/onecall/timemachine?lat=${latNum}&lon=${lonNum}&dt=${unixTime}&appid=${state.settings.openWeatherMapKey}&units=metric`;
                            const response = await fetchWithRetry(owmUrl);
                            if (response.ok) {
                                const data = await response.json();
                                if (data.data && data.data[0]) {
                                    const w = data.data[0];
                                    return {
                                        temp: w.temp,
                                        humidity: w.humidity,
                                        wind: w.wind_speed,
                                        rain: w.rain ? (w.rain['1h'] || 0) : 0,
                                        provider: 'OpenWeatherMap'
                                    };
                                }
                            }
                        } catch (e) { console.warn('OpenWeatherMap failed, trying other providers...', e); }
                    }

                    // 1.5 TRY Visual Crossing (if key provided or selected)
                    if (state.settings.visualCrossingKey || document.getElementById('settings-soil-provider')?.value === 'visual-crossing') {
                        try {
                            // If they selected it but no key in state, maybe they typed it in the input recently?
                            const vcKey = state.settings.visualCrossingKey || document.getElementById('settings-vc-key')?.value;
                            if (vcKey) {
                                const vcUrl = `https://weather.visualcrossing.com/VisualCrossingWebServices/rest/services/timeline/${latNum},${lonNum}/${dateStr}?key=${vcKey}&unitGroup=metric&include=days`;
                                const response = await fetchWithRetry(vcUrl);
                                if (response.ok) {
                                    const data = await response.json();
                                    if (data.days && data.days.length > 0) {
                                        const w = data.days[0];
                                        return {
                                            temp: w.tempmax || w.temp,
                                            humidity: w.humidity,
                                            wind: w.windspeed,
                                            rain: w.precip || 0,
                                            provider: 'Visual Crossing'
                                        };
                                    }
                                }
                            }
                        } catch (e) { console.warn('Visual Crossing failed...', e); }
                    }

                    // 1.7 TRY Tomorrow.io (if key provided or selected)
                    if (state.settings.tomorrowKey || document.getElementById('settings-soil-provider')?.value === 'tomorrow-io') {
                        try {
                            const tmKey = state.settings.tomorrowKey || document.getElementById('settings-tomorrow-key')?.value;
                            if (tmKey) {
                                const tmUrl = `https://api.tomorrow.io/v4/weather/history/recent?location=${latNum},${lonNum}&apikey=${tmKey}`;
                                const response = await fetchWithRetry(tmUrl);
                                if (response.ok) {
                                    const data = await response.json();
                                    if (data.timelines && data.timelines.daily && data.timelines.daily.length > 0) {
                                        const w = data.timelines.daily[0].values;
                                        return {
                                            temp: w.temperatureMax,
                                            humidity: w.humidityAvg,
                                            wind: w.windSpeedMax,
                                            rain: w.precipitationAccumulation || 0,
                                            provider: 'Tomorrow.io'
                                        };
                                    }
                                }
                            }
                        } catch (e) { console.warn('Tomorrow.io failed...', e); }
                    }

                    // 2. PRIMARY: Open-Meteo
                    const isOldArchive = diffDays > 14;
                    if (isOldArchive) {
                        url = `https://archive-api.open-meteo.com/v1/archive?latitude=${lat}&longitude=${lon}&start_date=${dateStr}&end_date=${dateStr}&daily=temperature_2m_max,relative_humidity_2m_mean,wind_speed_10m_max,rain_sum&timezone=auto`;
                    } else {
                        url = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&daily=temperature_2m_max,relative_humidity_2m_mean,wind_speed_10m_max,rain_sum&start_date=${dateStr}&end_date=${dateStr}&timezone=auto`;
                    }

                    const res = await fetchWithRetry(url);
                    if (!res.ok) {
                        const errData = await res.json().catch(() => ({}));
                        console.error('Weather API Error Detail:', errData);
                        throw new Error(`Weather API Error: ${res.status}${errData.reason ? ' - ' + errData.reason : ''}`);
                    }
                    const data = await res.json();

                    if (data.daily && data.daily.time && data.daily.time.length > 0) {
                        console.log('Weather API Response Dates:', data.daily.time, 'Looking for:', dateStr);

                        // Find the index that matches our requested date
                        // The API returns an array, and sometimes handles timezones by shifting the day.
                        // We trust the query 'start_date' usually, but finding the exact string match is safest.
                        const index = data.daily.time.findIndex(t => t === dateStr);

                        // Fallback: Use 0 if single day requested and match not found (typical response)
                        // But if 0 is "Today" and we asked for "Yesterday", we must be careful.
                        // If index is -1, it means the API didn't return the requested date.

                        const safeIndex = index !== -1 ? index : 0; // WARNING: This might be the bug if index is -1

                        if (index === -1) {
                            console.warn('Weather date mismatch! API returned:', data.daily.time[0], 'Expected:', dateStr);
                        }

                        // Sanity check: if returned date is not what we asked for, and we are in strict mode
                        if (index === -1 && data.daily.time[0] !== dateStr) {
                            // If the mismatch is significant, return null.
                            if (Math.abs(new Date(data.daily.time[0]) - targetDate) > 86400000) {
                                console.error('Weather date mismatch too large. Aborting.');
                                return null;
                            }
                        }

                        return {
                            temp: data.daily.temperature_2m_max[safeIndex],
                            humidity: data.daily.relative_humidity_2m_mean[safeIndex],
                            wind: data.daily.wind_speed_10m_max[safeIndex],
                            rain: data.daily.rain_sum[safeIndex],
                            provider: 'Open-Meteo'
                        };
                    }
                    return null;
                } catch (e) {
                    console.error("Weather fetch failed:", e);
                    console.error("Failed URL:", url);
                    showToast('Could not fetch weather data.', 'error');
                    return null;
                }
            }

            async function fetchWeatherForTrialDate() {
                const location = document.querySelector('[name="location"]').value;
                const date = document.querySelector('[name="date"]').value;
                if (!location || !date) return showToast('Enter location and date first.', 'error');

                let lat, lon;
                if (location.includes(',')) {
                    [lat, lon] = location.split(',').map(s => s.trim());
                }

                if (lat && lon) {
                    showToast('Syncing Field Conditions (Weather & Soil)...', 'info');

                    // 1. Weather
                    const w = await fetchWeather(lat, lon, date);
                    if (w) {
                        document.querySelector('[name="temperature"]').value = w.temp || '';
                        document.querySelector('[name="humidity"]').value = w.humidity || '';
                        document.querySelector('[name="windspeed"]').value = w.wind || '';
                        document.querySelector('[name="rain"]').value = w.rain || '';

                        const latField = document.querySelector('[name="lat"]');
                        const lonField = document.querySelector('[name="lon"]');
                        if (latField) latField.value = lat;
                        if (lonField) lonField.value = lon;

                        const weatherJsonField = document.querySelector('[name="weatherJSON"]');
                        if (weatherJsonField) weatherJsonField.value = JSON.stringify(w);
                    }

                    // 2. Soil
                    try {
                        const soil = await fetchSoilData(lat, lon);
                        if (soil) {
                            const soilPanel = document.getElementById('soil-data-panel');
                            if (soilPanel) soilPanel.classList.remove('hidden');

                            const setSoil = (name, val) => {
                                const el = document.querySelector(`[name="${name}"]`);
                                if (el) el.value = val || '';
                            };

                            setSoil('soilPH', soil.ph);
                            setSoil('soilClay', soil.clay);
                            setSoil('soilSand', soil.sand);
                            setSoil('soilOC', soil.organicCarbon);
                            setSoil('soilTexture', soil.texture);

                            const soilJsonField = document.querySelector('[name="soilDataJSON"]');
                            if (soilJsonField) soilJsonField.value = JSON.stringify(soil);
                        }
                    } catch (e) { console.error('Soil sync failed in trial modal', e); }

                    showToast('Field conditions updated from GPS.', 'success');
                } else {
                    showToast('Invalid location format (lat,lon required).', 'error');
                }
            }

