            function applyFilters(overrides = {}) {
                const search = document.querySelector('[data-type="trial-search"]')?.value.toLowerCase() || state.filterState?.search || '';
                const formulationText = document.querySelector('[data-type="trial-formulation-text"]')?.value.toLowerCase() || state.filterState?.formulationText || '';
                const formulation = document.querySelector('[data-type="trial-formulation"]')?.value || state.filterState?.formulation || '';
                const start = document.querySelector('[data-type="trial-start-date"]')?.value || state.filterState?.startDate || '';
                const end = document.querySelector('[data-type="trial-end-date"]')?.value || state.filterState?.endDate || '';
                const sortBy = overrides.sortBy || state.filterState?.sortBy || 'date';

                state.filterState = { search, formulationText, formulation, startDate: start, endDate: end, sortBy };

                let filtered = Array.isArray(state.trials) ? [...state.trials] : [];

                // Admin Individual User Filter
                if (state.auth?.Role === 'Admin' && state.adminViewUserId) {
                    filtered = filtered.filter(t => String(t.CreatedBy || '').trim() === String(state.adminViewUserId));
                }

                filtered = filtered.filter(t => {
                    const matchesSearch = !search || (t.InvestigatorName || '').toLowerCase().includes(search) || (t.WeedSpecies || '').toLowerCase().includes(search);
                    const matchesFormText = !formulationText || (t.FormulationName || '').toLowerCase().includes(formulationText);
                    const matchesForm = !formulation || t.FormulationID === formulation || t.FormulationName === formulation;
                    const matchesDate = (!start || new Date(t.Date) >= new Date(start)) && (!end || new Date(t.Date) <= new Date(end));
                    return matchesSearch && matchesFormText && matchesForm && matchesDate;
                });

                if (sortBy === 'date') {
                    filtered.sort((a, b) => {
                        const ad = a.Date ? new Date(a.Date).getTime() : 0;
                        const bd = b.Date ? new Date(b.Date).getTime() : 0;
                        if (bd !== ad) return bd - ad; // Newer dates first
                        // Keep original order when dates are tied to avoid visual jumps.
                        return 0;
                    });
                }
                if (sortBy === 'result') {
                    const scores = { excellent: 4, good: 3, fair: 2, poor: 1, none: 0, '': 0 };
                    const getResultScore = (trial) => {
                        const normalized = String(trial?.Result || '').trim().toLowerCase();
                        return Object.prototype.hasOwnProperty.call(scores, normalized) ? scores[normalized] : 0;
                    };

                    filtered.sort((a, b) => {
                        const scoreDiff = getResultScore(b) - getResultScore(a);
                        if (scoreDiff !== 0) return scoreDiff;

                        const ad = a.Date ? new Date(a.Date).getTime() : 0;
                        const bd = b.Date ? new Date(b.Date).getTime() : 0;
                        if (bd !== ad) return bd - ad;

                        return 0;
                    });
                }

                render.trials(filtered);
            }

            // --- MAP PICKER FOR EXACT LOCATION ---
            function openMapPicker() {
                const form = document.getElementById('trial-form');
                if (!form) { showToast('Please open a trial form first.', 'info'); return; }

                // Get existing coords from form or use a default
                const existingLat = parseFloat(form.querySelector('[name="lat"]')?.value) || null;
                const existingLon = parseFloat(form.querySelector('[name="lon"]')?.value) || null;

                // Parse from location text if hidden fields empty
                let startLat = existingLat, startLon = existingLon;
                if (!startLat || !startLon) {
                    const locVal = form.querySelector('[name="location"]')?.value || '';
                    if (locVal.includes(',')) {
                        const parts = locVal.split(',').map(s => parseFloat(s.trim()));
                        if (parts.length === 2 && isFinite(parts[0]) && isFinite(parts[1])) {
                            startLat = parts[0]; startLon = parts[1];
                        }
                    }
                }

                // Default to center of India if no coords
                if (!startLat || !startLon) { startLat = 15.3173; startLon = 75.7139; }

                // Create modal overlay
                const overlay = document.createElement('div');
                overlay.id = 'map-picker-overlay';
                overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);z-index:99999;display:flex;align-items:center;justify-content:center;';

                const container = document.createElement('div');
                container.style.cssText = 'background:white;border-radius:16px;width:90vw;max-width:800px;height:80vh;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 25px 50px rgba(0,0,0,0.3);';

                // Header
                const header = document.createElement('div');
                header.style.cssText = 'padding:16px 20px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid #e2e8f0;';
                header.innerHTML = `
                    <div>
                        <h3 style="font-weight:700;font-size:16px;color:#1e293b;margin:0;">Pick Exact Trial Location</h3>
                        <p style="font-size:12px;color:#64748b;margin:4px 0 0 0;">Click/tap on the map to set your trial plot location precisely</p>
                    </div>
                    <div id="map-picker-coords" style="font-family:monospace;font-size:13px;color:#059669;font-weight:600;"></div>
                `;

                // Map container
                const mapDiv = document.createElement('div');
                mapDiv.id = 'location-picker-map';
                mapDiv.style.cssText = 'flex:1;';

                // Footer
                const footer = document.createElement('div');
                footer.style.cssText = 'padding:12px 20px;display:flex;gap:12px;justify-content:flex-end;border-top:1px solid #e2e8f0;background:#f8fafc;';
                footer.innerHTML = `
                    <button id="map-picker-cancel" style="padding:8px 20px;border-radius:8px;border:1px solid #cbd5e1;background:white;color:#475569;font-weight:500;cursor:pointer;">Cancel</button>
                    <button id="map-picker-confirm" style="padding:8px 20px;border-radius:8px;border:none;background:#059669;color:white;font-weight:600;cursor:pointer;">Confirm Location</button>
                `;

                container.appendChild(header);
                container.appendChild(mapDiv);
                container.appendChild(footer);
                overlay.appendChild(container);
                document.body.appendChild(overlay);

                // Initialize Leaflet map
                let selectedLat = startLat, selectedLon = startLon;
                const pickerMap = L.map('location-picker-map').setView([startLat, startLon], 17);

                // Add satellite + plane layers with toggle
                const satellite = L.tileLayer('http://{s}.google.com/vt/lyrs=y&x={x}&y={y}&z={z}', {
                    maxZoom: 21, subdomains: ['mt0','mt1','mt2','mt3'], attribution: '- Google'
                });
                const plane = L.tileLayer('http://{s}.google.com/vt/lyrs=m&x={x}&y={y}&z={z}', {
                    maxZoom: 21, subdomains: ['mt0','mt1','mt2','mt3'], attribution: '- Google'
                });
                satellite.addTo(pickerMap);
                L.control.layers({ "Satellite": satellite, "Plane Map": plane }).addTo(pickerMap);

                // Add a draggable marker
                const marker = L.marker([startLat, startLon], { draggable: true }).addTo(pickerMap);
                const coordsDisplay = document.getElementById('map-picker-coords');
                const updateCoords = (lat, lon) => {
                    selectedLat = lat; selectedLon = lon;
                    if (coordsDisplay) coordsDisplay.textContent = `${lat.toFixed(7)}, ${lon.toFixed(7)}`;
                };
                updateCoords(startLat, startLon);

                // Click on map to move marker
                pickerMap.on('click', e => {
                    marker.setLatLng(e.latlng);
                    updateCoords(e.latlng.lat, e.latlng.lng);
                });

                // Drag marker
                marker.on('dragend', () => {
                    const pos = marker.getLatLng();
                    updateCoords(pos.lat, pos.lng);
                });

                // Cancel
                document.getElementById('map-picker-cancel').addEventListener('click', () => {
                    pickerMap.remove();
                    overlay.remove();
                });
                overlay.addEventListener('click', e => {
                    if (e.target === overlay) { pickerMap.remove(); overlay.remove(); }
                });

                // Confirm
                document.getElementById('map-picker-confirm').addEventListener('click', () => {
                    const locationInput = form.querySelector('[name="location"]');
                    const latInput = form.querySelector('[name="lat"]');
                    const lonInput = form.querySelector('[name="lon"]');
                    if (locationInput) locationInput.value = `${selectedLat.toFixed(7)}, ${selectedLon.toFixed(7)}`;
                    if (latInput) latInput.value = selectedLat;
                    if (lonInput) lonInput.value = selectedLon;
                    showToast('Location set from map!', 'success');
                    pickerMap.remove();
                    overlay.remove();

                    // Auto-fetch soil data for this new location
                    fetchSoilData(selectedLat, selectedLon);
                });

                // Try to get user's GPS to center map better
                if (navigator.geolocation) {
                    navigator.geolocation.getCurrentPosition(pos => {
                        if (!existingLat && !existingLon) {
                            const lat = pos.coords.latitude, lon = pos.coords.longitude;
                            pickerMap.setView([lat, lon], 18);
                            marker.setLatLng([lat, lon]);
                            updateCoords(lat, lon);
                        }
                    }, () => {}, { enableHighAccuracy: true, timeout: 5000 });
                }
            }

            function getGeoLocation(callback) {
                if (!navigator.geolocation) {
                    showToast('Geolocation not supported.', 'error');
                    return;
                }

                showToast('Acquiring GPS satellites, please wait', 'info');

                let bestReading = null;
                let readingCount = 0;

                // Use watchPosition to continuously refine GPS over several seconds
                const watchId = navigator.geolocation.watchPosition(
                    pos => {
                        readingCount++;
                        const accuracy = pos.coords.accuracy; // in meters

                        // Keep the reading with the smallest accuracy radius (= most precise)
                        if (!bestReading || accuracy < bestReading.accuracy) {
                            bestReading = {
                                lat: pos.coords.latitude,
                                lon: pos.coords.longitude,
                                accuracy: accuracy
                            };
                        }
                    },
                    err => {
                        navigator.geolocation.clearWatch(watchId);
                        showToast(`Location error: ${err.message}`, 'error');
                    },
                    { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 }
                );

                // After 5 seconds, stop watching and return the best reading
                setTimeout(() => {
                    navigator.geolocation.clearWatch(watchId);
                    if (bestReading) {
                        showToast(`GPS locked. Accuracy: ${Math.round(bestReading.accuracy)}m (${readingCount} readings)`, 'success');
                        callback(bestReading);
                    } else {
                        showToast('Could not get accurate GPS fix. Try again outdoors.', 'error');
                    }
                }, 5000);
            }

            // --- PLOT SCANNER LOGIC ---
            let scannerStream = null;
            let scannerAnimationId = null;
            // Create a single canvas for scanning to avoid garbage collection churn
            const scannerCanvas = document.createElement("canvas");
            const scannerCtx = scannerCanvas.getContext("2d");

            function openQrScanner() {
                const modal = document.getElementById('qr-scanner-modal-fixed');
                const video = document.getElementById('qr-video');
                if (!modal || !video) return;

                if (typeof jsQR === 'undefined') {
                    showToast('QR Scanner library not loaded. Please refresh.', 'error');
                    return;
                }

                // Check for Secure Context / Protocol
                if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
                    console.error("Camera API unavailable. Protocol:", window.location.protocol);
                    if (window.location.protocol === 'file:') {
                        alert("Camera blocked by browser security.\n\nYou are opening this file directly (file://). Modern browsers block camera access in this mode for security.\n\nSolution:\nUse a local server (like 'Live Server' in VS Code) or upload to a secure website (https://).");
                    } else {
                        showToast("Camera API not supported or blocked by browser context.", "error");
                    }
                    return;
                }

                modal.classList.remove('hidden');
                if (window.lucide) window.lucide.createIcons();

                // Helper to start camera with fallback
                const startCamera = (constraints) => {
                    navigator.mediaDevices.getUserMedia(constraints)
                        .then(stream => {
                            scannerStream = stream;
                            video.srcObject = stream;
                            video.setAttribute("playsinline", true); // Required for iOS Safari
                            video.play().catch(e => console.error("Video play error:", e));
                            requestAnimationFrame(scanQrTick);
                        })
                        .catch(err => {
                            console.warn("Camera failed with constraints:", constraints, err);
                            // Fallback: If environment camera failed, try ANY camera
                            if (constraints.video && constraints.video.facingMode === 'environment') {
                                console.log("Retrying with generic camera access...");
                                startCamera({ video: true });
                            } else {
                                console.error("All camera attempts failed:", err);
                                showToast("Could not access any camera. Please check permissions.", "error");
                                closeQrScanner();
                            }
                        });
                };

                // Initial attempt: Prefer back camera, HD resolution
                startCamera({
                    video: {
                        facingMode: "environment",
                        width: { ideal: 1280 },
                        height: { ideal: 720 }
                    }
                });
            }

            function closeQrScanner() {
                const modal = document.getElementById('qr-scanner-modal-fixed');
                const video = document.getElementById('qr-video');

                if (modal) modal.classList.add('hidden');

                if (scannerAnimationId) cancelAnimationFrame(scannerAnimationId);

                if (video) {
                    video.pause();
                    video.srcObject = null;
                }

                if (scannerStream) {
                    scannerStream.getTracks().forEach(track => track.stop());
                    scannerStream = null;
                }
            }

            function scanQrTick() {
                const video = document.getElementById('qr-video');
                const modal = document.getElementById('qr-scanner-modal-fixed');

                // Stop if modal is closed
                if (!modal || modal.classList.contains('hidden')) return;

                if (!video || !video.videoWidth) {
                    scannerAnimationId = requestAnimationFrame(scanQrTick);
                    return;
                }

                // Draw video frame to canvas
                scannerCanvas.width = video.videoWidth;
                scannerCanvas.height = video.videoHeight;
                scannerCtx.drawImage(video, 0, 0, scannerCanvas.width, scannerCanvas.height);

                const imageData = scannerCtx.getImageData(0, 0, scannerCanvas.width, scannerCanvas.height);

                // Scan for QR code
                const code = jsQR(imageData.data, imageData.width, imageData.height, {
                    inversionAttempts: "dontInvert",
                });

                if (code) {
                    // Success!
                    handleScannedQr(code.data);
                } else {
                    scannerAnimationId = requestAnimationFrame(scanQrTick);
                }
            }

            function handleScannedQr(data) {
                // Feedback
                if (navigator.vibrate) navigator.vibrate(200);

                // Try to extract Trial ID
                let trialId = null;

                // Case 1: URL with trialId parameter (Online QR)
                if (data.includes('trialId=')) {
                    try {
                        const url = new URL(data);
                        trialId = url.searchParams.get('trialId');
                    } catch (e) {
                        // Fallback regex
                        const match = data.match(/trialId=([^&]+)/);
                        if (match) trialId = match[1];
                    }
                }
                // Case 2: Just the ID
                else if (data.match(/^[0-9a-f]{8}-[0-9a-f]{4}/i)) {
                    trialId = data; // Assume it's an ID
                }

                if (trialId) {
                    const trial = state.trials.find(t => t.ID === trialId);
                    if (trial) {
                        showToast(`Scanned: ${trial.FormulationName}`, 'success');

                        const isContinuous = document.getElementById('continuous-scan-toggle')?.checked;

                        if (isContinuous) {
                            if (navigator.vibrate) navigator.vibrate([100, 50, 100]); // Distinct double vibration
                            // Pause for 1.5 seconds to avoid double scanning, then resume
                            setTimeout(() => {
                                scannerAnimationId = requestAnimationFrame(scanQrTick);
                            }, 1500);
                        } else {
                            closeQrScanner();
                            // openTrialDetail(trialId); // OLD WORKFLOW
                            openScanActions(trialId); // NEW RAPID WORKFLOW
                        }
                    } else {
                        // Trial not in local state — if it's a full URL (online QR), open the live report page directly
                        if (data.startsWith('http')) {
                            closeQrScanner();
                            showToast('Opening live report in browser...', 'info');
                            window.open(data, '_blank');
                        } else {
                            showToast('Trial not found in local data. Try refreshing the app.', 'warning');
                            const isContinuous = document.getElementById('continuous-scan-toggle')?.checked;
                            if (isContinuous) {
                                setTimeout(() => { scannerAnimationId = requestAnimationFrame(scanQrTick); }, 1500);
                            } else {
                                closeQrScanner();
                            }
                        }
                    }
                } else {
                    // Determine if it looks like an offline QR
                    if (data.includes('H-APP:')) {
                        closeQrScanner();
                        alert("This is an Offline QR Code.\\n\\nContent:\\n" + data + "\\n\\nPlease use Online QR Codes for navigation.");
                    }
                    else {
                        scannerAnimationId = requestAnimationFrame(scanQrTick);
                    }
                }
            }

            function openScanActions(trialId) {
                const trial = state.trials.find(t => t.ID === trialId);
                if (!trial) return;

                const modal = document.getElementById('scan-action-modal');
                const title = document.getElementById('scan-match-title');
                const subtitle = document.getElementById('scan-match-subtitle');

                title.textContent = trial.FormulationName;
                subtitle.textContent = `${trial.InvestigatorName || 'Unknown Info'} - ${trial.Location || 'No Loc'}`;

                // Unbind previous listeners (simple clone hack to clear)
                const btnCamera = document.getElementById('scan-action-camera');
                const btnWeed = document.getElementById('scan-action-weed');
                const btnGallery = document.getElementById('scan-action-gallery');
                const btnDetail = document.getElementById('scan-action-detail');
                const inputGallery = document.getElementById('scan-gallery-input');

                const newBtnCamera = btnCamera.cloneNode(true);
                const newBtnWeed = btnWeed.cloneNode(true);
                const newBtnGallery = btnGallery.cloneNode(true);
                const newBtnDetail = btnDetail.cloneNode(true);
                const newInputGallery = inputGallery.cloneNode(true);

                btnCamera.parentNode.replaceChild(newBtnCamera, btnCamera);
                btnWeed.parentNode.replaceChild(newBtnWeed, btnWeed);
                btnGallery.parentNode.replaceChild(newBtnGallery, btnGallery);
                btnDetail.parentNode.replaceChild(newBtnDetail, btnDetail);
                inputGallery.parentNode.replaceChild(newInputGallery, inputGallery);

                // Bind new actions
                newBtnCamera.addEventListener('click', () => {
                    modal.classList.add('hidden');
                    state.cameraMode = 'general';
                    openCamera(trialId);
                });

                newBtnWeed.addEventListener('click', () => {
                    modal.classList.add('hidden');
                    state.cameraMode = 'weed';
                    openCamera(trialId);
                });

                newBtnGallery.addEventListener('click', () => {
                    newInputGallery.click();
                });

                newInputGallery.addEventListener('change', (e) => {
                    if (e.target.files && e.target.files.length > 0) {
                        modal.classList.add('hidden');
                        state.currentTrialIdForCamera = trialId;
                        state.cameraMode = 'general'; // Default to general for gallery
                        // Reuse photo queue logic
                        state.photoQueue = Array.from(e.target.files);
                        processPhotoQueue(trialId);
                        // Reset input
                        newInputGallery.value = '';
                    }
                });

                newBtnDetail.addEventListener('click', () => {
                    modal.classList.add('hidden');
                    openTrialDetail(trialId);
                });

                modal.classList.remove('hidden');
                modal.style.display = 'flex'; // FORCE FLEX FOR CENTERING
            }

            // --- REPORTING & EXPORT LOGIC ---
            /* runComparison is defined earlier at ~3476 */

            async function getLogoDimensions(logoDataUrl) { return new Promise(resolve => { if (!logoDataUrl) { resolve(null); return; } const img = new Image(); img.onload = () => { const aspectRatio = img.width / img.height; const logoHeight = 1.2; const logoWidth = logoHeight * aspectRatio; resolve({ width: logoWidth, height: logoHeight }); }; img.onerror = () => resolve(null); img.src = logoDataUrl; }); }
            async function generateQrCodeDataUrl(dataString) { return new Promise((resolve, reject) => { try { const tempDiv = document.createElement('div'); new QRCode(tempDiv, { text: dataString, width: 256, height: 256, correctLevel: QRCode.CorrectLevel.M }); setTimeout(() => { const canvas = tempDiv.querySelector('canvas'); if (canvas) resolve(canvas.toDataURL('image/png')); else reject(new Error('QR Code generation failed.')); }, 100); } catch (error) { resolve(null); } }); }

            function getTrialCardSizeSettings() {
                let cardWidth = 9;
                let cardHeight = 6;
                const sizeSetting = state.settings.cardSize || 'ID';
                if (sizeSetting === 'A6') {
                    cardWidth = 10;
                    cardHeight = 14;
                }
                if (sizeSetting === 'A4') {
                    cardWidth = 19;
                    cardHeight = 13;
                }
                return { cardWidth, cardHeight };
            }

            function buildTrialCardsCss(cardWidth, cardHeight) {
                return `
                    @media print { body { -webkit-print-color-adjust: exact; print-color-adjust: exact; } }
                    body { margin: 0.5cm; font-family: sans-serif; background: #ffffff; }
                    .page {
                        display: grid;
                        grid-template-columns: repeat(auto-fill, minmax(${cardWidth}cm, 1fr));
                        gap: 0.5cm;
                        page-break-after: always;
                    }
                    .card {
                        width: ${cardWidth}cm;
                        height: ${cardHeight}cm;
                        border: 1px solid #ccc;
                        border-radius: 4px;
                        padding: 0.4cm;
                        box-sizing: border-box;
                        display: flex;
                        flex-direction: column;
                        justify-content: space-between;
                        page-break-inside: avoid;
                        overflow: hidden;
                        position: relative;
                        background: #ffffff;
                    }
                    .card-header { display: flex; justify-content: space-between; align-items: flex-start; }
                    .card-header h3 { font-size: 12pt; margin: 0; font-weight: bold; color: #2c5282; max-width: 65%; }
                    .logo { max-width: 2.5cm; max-height: 1.2cm; object-fit: contain; }
                    .card-body { padding-right: 2.9cm; }
                    .card-body p { font-size: 9pt; margin: 0.1cm 0; }
                    .card-footer {
                        position: absolute;
                        right: 0.4cm;
                        bottom: 0.4cm;
                        text-align: right;
                    }
                    .qr-code { width: 2.5cm; height: 2.5cm; }
                `;
            }

            async function buildTrialCardsMarkup(selectedTrials, companyLogo) {
                const cards = [];
                for (const trial of selectedTrials) {
                    const params = new URLSearchParams({ trialId: trial.ID, spreadsheetId: state.settings.sheetId });
                    const qrDataString = `${state.settings.scriptUrl}?${params.toString()}`;
                    const qrCodeUrl = await generateQrCodeDataUrl(qrDataString);

                    cards.push(`
                        <div class="card">
                            <div>
                                <div class="card-header">
                                    <h3>${sanitizeHTML(trial.FormulationName)}</h3>
                                    ${companyLogo ? `<img src="${companyLogo}" class="logo" alt="Logo">` : ''}
                                </div>
                                <div class="card-body">
                                    <p><strong>Investigator:</strong> ${sanitizeHTML(trial.InvestigatorName)}</p>
                                    <p><strong>Date:</strong> ${new Date(trial.Date).toLocaleDateString()}</p>
                                    <p><strong>Dosage:</strong> ${sanitizeHTML(trial.Dosage)}</p>
                                </div>
                            </div>
                            <div class="card-footer">
                                ${qrCodeUrl ? `<img src="${qrCodeUrl}" class="qr-code" alt="QR Code">` : ''}
                            </div>
                        </div>
                    `);
                }

                return `<div class="page">${cards.join('')}</div>`;
            }

            async function generateCardsForPrint() {
                if (state.selectedTrials.length === 0) return showToast('No trials selected.', 'error');

                const { cardWidth, cardHeight } = getTrialCardSizeSettings();
                const companyLogo = state.settings.logoBase64;

                showToast('Generating print layout...', 'info');

                const printWindow = window.open('', '_blank');
                if (!printWindow) return showToast("Pop-up blocker prevented opening print window.", 'error');

                const selected = state.selectedTrials.map(id => state.trials.find(t => t.ID === id)).filter(Boolean);
                const cardsMarkup = await buildTrialCardsMarkup(selected, companyLogo);
                const cardsCss = buildTrialCardsCss(cardWidth, cardHeight);

                const htmlContent = `
            <!DOCTYPE html>
            <html lang="en">
            <head>
                <meta charset="UTF-8">
                <title>Print Trial Cards</title>
                <style>${cardsCss}</style>
            </head>
            <body>${cardsMarkup}</body></html>`;
                printWindow.document.write(htmlContent);
                printWindow.document.close();
                setTimeout(() => { printWindow.focus(); printWindow.print(); printWindow.close(); }, 500);
            }

            async function generateCardsPdf() {
                if (state.selectedTrials.length === 0) return showToast('No trials selected.', 'error');

                const { jsPDF } = window.jspdf;
                const { cardWidth, cardHeight } = getTrialCardSizeSettings();
                const companyLogo = state.settings.logoBase64;
                const selected = state.selectedTrials.map(id => state.trials.find(t => t.ID === id)).filter(Boolean);
                const cardsMarkup = await buildTrialCardsMarkup(selected, companyLogo);
                const cardsCss = buildTrialCardsCss(cardWidth, cardHeight);

                showToast('Generating PDF cards...', 'info');

                const tempContainer = document.createElement('div');
                tempContainer.style.position = 'fixed';
                tempContainer.style.left = '-99999px';
                tempContainer.style.top = '0';
                tempContainer.style.width = '21cm';
                tempContainer.style.background = '#fff';
                tempContainer.innerHTML = `<style>${cardsCss}</style>${cardsMarkup}`;
                document.body.appendChild(tempContainer);

                try {
                    const imgPromises = Array.from(tempContainer.querySelectorAll('img')).map(img => {
                        if (img.complete) return Promise.resolve();
                        return new Promise(resolve => {
                            img.onload = () => resolve();
                            img.onerror = () => resolve();
                        });
                    });
                    await Promise.all(imgPromises);

                    const cards = Array.from(tempContainer.querySelectorAll('.card'));
                    if (!cards.length) throw new Error('No card nodes found for PDF export');

                    const doc = createPdfDoc({ orientation: 'portrait', unit: 'mm', format: 'a4' });
                    const pageW = 210;
                    const pageH = 297;
                    const margin = 5;
                    const gap = 5;
                    const cardWmm = cardWidth * 10;
                    const cardHmm = cardHeight * 10;

                    const cols = Math.max(1, Math.floor((pageW - (2 * margin) + gap) / (cardWmm + gap)));
                    const rows = Math.max(1, Math.floor((pageH - (2 * margin) + gap) / (cardHmm + gap)));
                    const perPage = Math.max(1, cols * rows);

                    for (let i = 0; i < cards.length; i++) {
                        if (i > 0 && i % perPage === 0) doc.addPage();

                        const slot = i % perPage;
                        const col = slot % cols;
                        const row = Math.floor(slot / cols);
                        const x = margin + (col * (cardWmm + gap));
                        const y = margin + (row * (cardHmm + gap));

                        const canvas = await html2canvas(cards[i], {
                            scale: 2,
                            useCORS: true,
                            backgroundColor: '#ffffff'
                        });
                        const imgData = canvas.toDataURL('image/jpeg', 0.95);
                        doc.addImage(imgData, 'JPEG', x, y, cardWmm, cardHmm, undefined, 'FAST');
                    }

                    doc.save('trial-cards.pdf');
                    showToast('PDF cards downloaded.', 'success');
                } catch (err) {
                    console.error('[PDF Cards] Failed to render:', err);
                    showToast('Failed to generate PDF cards.', 'error');
                } finally {
                    tempContainer.remove();
                }
            }

            function generateTrialCards() {
                return state.selectedTrials.map(id => {
                    const trial = state.trials.find(t => t.ID === id);
                    if (!trial) return '';
                    return `<div class="bg-white p-6 rounded-xl border border-gray-200 shadow-sm break-inside-avoid">
    <div class="flex justify-between items-start mb-4">
        <div>
            <h3 class="font-bold text-xl">${sanitizeHTML(trial.FormulationName)}</h3>
            <p class="text-gray-500 text-sm">${new Date(trial.Date).toLocaleDateString()}</p>
        </div>
        <span
            class="px-3 py-1 rounded-full text-sm font-bold result-${(trial.Result || 'none').toLowerCase()}">${trial.Result
                        || 'None'}</span>
    </div>
    <div class="grid grid-cols-2 gap-4 text-sm text-gray-700">
        <p><strong>Investigator:</strong> ${sanitizeHTML(trial.InvestigatorName)}</p>
        <p><strong>Location:</strong> ${sanitizeHTML(trial.Location)}</p>
        <p><strong>Dosage:</strong> ${sanitizeHTML(trial.Dosage)}</p>
        <p><strong>Status:</strong> ${String(trial.IsCompleted).toLowerCase() === 'true' ? 'Completed' : 'Active'}</p>
    </div>
    <div class="mt-4 pt-4 border-t flex justify-end">
        <div id="qr-${trial.ID}"></div>
    </div>
</div>`;
                }).join('');
            }





            // --- CHART RENDERER (Moved to Root Scope) ---
            function renderProjectAnalysisCharts(project) {
                if (!project || !project.AnalysisResults) return;

                const results = project.AnalysisResults;
                const dats = Object.keys(results).sort((a, b) => parseInt(a) - parseInt(b));
                if (dats.length === 0) return;

                // 1. WCE Over Time Chart
                const wceCtx = document.getElementById('project-wce-chart');
                if (wceCtx) {
                    // Add null check for treatmentStats in all results
                    const validResults = Object.values(results).filter(r => r && r.treatmentStats && !r.error);

                    if (validResults.length === 0) {
                        console.warn('[Charts] No valid treatment data available for chart rendering');
                        return;
                    }

                    const treatmentNames = [...new Set(validResults.flatMap(r => r.treatmentStats.map(ts => {
                        const f = state.formulations.find(form => form.ID === ts.treatmentId);
                        return f ? f.Name : ts.treatmentId;
                    })))];

                    const datasets = treatmentNames.map((name, index) => {
                        const dataPoints = dats.map(dat => {
                            const res = results[dat];
                            // Check if result has valid treatmentStats
                            if (!res || !res.treatmentStats || res.error) {
                                return null;
                            }
                            const f = state.formulations.find(form => form.Name === name);
                            const id = f ? f.ID : name;

                            const stat = res.treatmentStats.find(ts => ts.treatmentId === id || state.formulations.find(x => x.ID === ts.treatmentId)?.Name === name);
                            return stat ? stat.wce : 0;
                        });

                        const color = getColorForIndex(index);

                        return {
                            label: name,
                            data: dataPoints,
                            borderColor: color,
                            backgroundColor: color,
                            fill: false,
                            tension: 0.1
                        };
                    });

                    if (state.charts.projectWce) state.charts.projectWce.destroy();
                    state.charts.projectWce = new Chart(wceCtx, {
                        type: 'line',
                        data: {
                            labels: dats.map(d => `${d} DAT`),
                            datasets: datasets
                        },
                        options: {
                            responsive: true,
                            maintainAspectRatio: false,
                            plugins: {
                                legend: { position: 'bottom' },
                                title: { display: true, text: '% Weed Control Efficiency' }
                            },
                            scales: {
                                y: { beginAtZero: true, max: 100, title: { display: true, text: '% WCE' } }
                            }
                        }
                    });
                }

                // 2. Final DAT Performance Chart
                const performanceCtx = document.getElementById('project-performance-chart');
                if (performanceCtx && dats.length > 0) {
                    const finalDat = dats[dats.length - 1];
                    const finalRes = results[finalDat];

                    // Add null check for treatmentStats
                    if (!finalRes || !finalRes.treatmentStats || finalRes.error) {
                        console.warn('[Charts] No valid treatment data for performance chart');
                        return;
                    }

                    const labels = finalRes.treatmentStats.map(ts => {
                        const f = state.formulations.find(form => form.ID === ts.treatmentId);
                        return f ? f.Name : ts.treatmentId;
                    });
                    const data = finalRes.treatmentStats.map(ts => ts.mean);
                    const bgColors = finalRes.treatmentStats.map(ts => {
                        if (ts.rank === 'Superior') return 'rgba(20, 184, 166, 0.7)'; // Teal
                        if (ts.rank === 'Inferior') return 'rgba(239, 68, 68, 0.7)'; // Red
                        if (ts.rank === 'Control') return 'rgba(245, 158, 11, 0.7)'; // Amber
                        return 'rgba(100, 116, 139, 0.7)'; // Slate
                    });

                    if (state.charts.projectPerf) state.charts.projectPerf.destroy();
                    state.charts.projectPerf = new Chart(performanceCtx, {
                        type: 'bar',
                        data: {
                            labels: labels,
                            datasets: [{
                                label: `Mean ${project.Metric} (${finalDat} DAT)`,
                                data: data,
                                backgroundColor: bgColors,
                                borderColor: bgColors.map(c => c.replace('0.7', '1')),
                                borderWidth: 1
                            }]
                        },
                        options: {
                            responsive: true,
                            maintainAspectRatio: false,
                            plugins: {
                                legend: { display: false },
                                title: { display: true, text: `Efficacy at ${finalDat} DAT` }
                            },
                            scales: {
                                y: { beginAtZero: true, title: { display: true, text: project.Metric } }
                            }
                        }
                    });
                }
            }

            function getColorForIndex(index) {
                const colors = [
                    '#0d9488', // Teal
                    '#ef4444', // Red
                    '#f59e0b', // Amber
                    '#3b82f6', // Blue
                    '#8b5cf6', // Violet
                    '#ec4899', // Pink
                    '#10b981', // Emerald
                    '#6366f1'  // Indigo
                ];
                return colors[index % colors.length];
            }


            // --- STARTUP ---

            // --- SETTINGS LOGIC ---
            function bindSettingsEvents() {
                document.body.addEventListener('change', (e) => {
                    if (e.target.id === 'settings-logo-input') {
                        const file = e.target.files[0];
                        if (file) {
                            const reader = new FileReader();
                            reader.onload = (readerEvent) => {
                                const base64 = readerEvent.target.result;
                                document.getElementById('settings-logo-preview').src = base64;
                                document.getElementById('settings-logo-hidden').value = base64;
                            };
                            reader.readAsDataURL(file);
                        }
                    }
                });
            }

            // --- CONSOLIDATED HIGH-TECH OFFLINE SYNC LOGIC ---
            function saveSyncQueue() {
                try {
                    localStorage.setItem('herbicide_sync_queue', JSON.stringify(state.syncQueue));
                } catch (e) {
                    console.error("Failed to save sync queue:", e);
                }
            }

            function getSyncItemLabel(item) {
                if (!item) return 'Unknown item';
                if (item.action) return `Action: ${item.action}`;
                return item.photo?.fileName || item.photo?.label || item.photo?.date || item.id || 'Photo upload';
            }

            function removeSyncPlaceholderFromTrial(item) {
                if (!item || !item.trialId || !item.photo?.tempId) return;

                const trial = state.trials.find(t => t.ID === item.trialId);
                if (!trial) return;

                const isWeed = item.type === 'weed_upload';
                const field = isWeed ? 'WeedPhotosJSON' : 'PhotoURLs';
                const photos = safeJsonParse(trial[field], []);
                const nextPhotos = photos.filter(photo => {
                    if (photo?.tempId !== item.photo.tempId) return true;
                    return !!photo.url;
                });

                if (nextPhotos.length !== photos.length) {
                    trial[field] = JSON.stringify(nextPhotos);
                    refreshRelevantUI(item.trialId, item.type);
                }
            }

            function stopSyncItem(itemId) {
                if (itemId === '__all__') {
                    // Clear all non-uploading sync items
                    const uploading = state.syncQueue.filter(s => s.status === 'uploading');
                    const removed = state.syncQueue.length - uploading.length;
                    state.syncQueue.forEach(s => {
                        if (s.status !== 'uploading') removeSyncPlaceholderFromTrial(s);
                    });
                    state.syncQueue = uploading;
                    saveSyncQueue();
                    renderSyncStatus();
                    showToast(`Cleared ${removed} queued sync items.`, 'info');
                    return;
                }
                const item = state.syncQueue.find(s => s.id === itemId);
                if (!item) {
                    showToast('Sync item not found.', 'warning');
                    return;
                }

                const isUploading = item.status === 'uploading';
                item.cancelRequested = true;
                item.cancelledAt = new Date().toISOString();
                item.status = 'cancelled';

                if (!isUploading) {
                    removeSyncPlaceholderFromTrial(item);
                    state.syncQueue = state.syncQueue.filter(s => s.id !== itemId);
                }

                saveSyncQueue();
                renderSyncStatus();
                showToast(isUploading ? 'Sync will stop after the current upload step.' : 'Sync item stopped.', 'info');
            }

            function renderSyncStatus() {
                const el = document.getElementById('sync-status');
                const panel = document.getElementById('sync-items-panel');
                if (!el) return;

                const pending = state.syncQueue.filter(s => s.status === 'pending' || s.status === 'failed').length;
                const uploading = state.syncQueue.filter(s => s.status === 'uploading').length;
                const visibleItems = state.syncQueue.filter(s => ['pending', 'failed', 'uploading'].includes(s.status)).slice(0, 6);

                if (pending === 0 && uploading === 0) {
                    el.innerHTML = '';
                    el.classList.add('hidden');
                    if (panel) panel.style.display = 'none';
                    return;
                }

                // --- Pill: compact, single line, never grows ---
                el.classList.remove('hidden');
                if (uploading > 0) {
                    el.innerHTML = `<i data-lucide="upload-cloud" class="h-4 w-4 text-emerald-600"></i><span class="text-emerald-600 font-bold animate-pulse">Syncing ${uploading}...</span>`;
                } else {
                    el.innerHTML = `<i data-lucide="alert-circle" class="h-4 w-4 text-amber-600"></i><span class="text-amber-600">${pending} waiting</span><button onclick="processSyncQueue()" class="ml-1 px-2 py-0.5 bg-amber-600 text-white text-[11px] rounded hover:bg-amber-700">Sync Now</button>`;
                }

                // --- Detail panel: fixed-position, completely outside document flow ---
                if (panel) {
                    if (visibleItems.length === 0) {
                        panel.style.display = 'none';
                    } else {
                        const rows = visibleItems.map(item => {
                            const tone = item.status === 'failed'
                                ? 'border-red-200 bg-red-50 text-red-700'
                                : item.status === 'uploading'
                                    ? 'border-emerald-200 bg-emerald-50 text-emerald-700'
                                    : 'border-amber-200 bg-amber-50 text-amber-700';
                            const meta = item.action
                                ? 'Queued data update'
                                : `${item.type === 'weed_upload' ? 'Weed photo' : 'Trial photo'}${item.photo?.date ? ` - ${item.photo.date}` : ''}`;
                            const errorText = item.lastError ? `<div style="font-size:11px;opacity:.7;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${sanitizeHTML(item.lastError)}</div>` : '';
                            const retryButton = item.status === 'failed'
                                ? `<button data-action="retry-sync" data-id="${item.id}" style="padding:2px 8px;font-size:11px;border-radius:6px;background:#fff;border:1px solid currentColor;opacity:.7;cursor:pointer;">Retry</button>`
                                : '';
                            const stopLabel = item.status === 'uploading' ? 'Stop' : 'Remove';
                            return `<div style="border-radius:8px;border:1px solid;padding:8px 10px;display:flex;align-items:flex-start;justify-content:space-between;gap:8px;" class="${tone}">
                                <div style="min-width:0;flex:1;">
                                    <div style="font-size:12px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${sanitizeHTML(getSyncItemLabel(item))}</div>
                                    <div style="font-size:11px;opacity:.8;">${sanitizeHTML(meta)}</div>
                                    ${errorText}
                                </div>
                                <div style="display:flex;align-items:center;gap:6px;flex-shrink:0;">
                                    ${retryButton}
                                    <button data-action="stop-sync-item" data-id="${item.id}" style="padding:2px 8px;font-size:11px;border-radius:6px;background:#fff;border:1px solid currentColor;opacity:.7;cursor:pointer;">${stopLabel}</button>
                                </div>
                            </div>`;
                        }).join('');
                        panel.innerHTML = rows;
                        // Add "Clear All" button if multiple items
                        if (visibleItems.length > 1) {
                            panel.innerHTML += `<div style="text-align:center;padding:4px 0;"><button data-action="stop-sync-item" data-id="__all__" style="padding:4px 16px;font-size:12px;border-radius:6px;background:#dc2626;color:#fff;border:none;cursor:pointer;font-weight:600;">Clear All Queued</button></div>`;
                        }
                        panel.style.display = 'flex';
                    }
                }

                if (window.lucide) lucide.createIcons();
            }

            let _isSyncProcessing = false;
            let _lastSyncAttempt = 0;
            const SYNC_MIN_INTERVAL = 500;
            const SYNC_STUCK_TIMEOUT = 60000; // Reset flag if still processing after 60s

            function isDrivePermissionError(msg) {
                const m = String(msg || '').toLowerCase();
                return m.includes('driveapp') ||
                    m.includes('drive access denied') ||
                    m.includes('access denied') ||
                    m.includes('triggerdrivepermissions') ||
                    m.includes('execute as: me');
            }

            // CRITICAL FIX: Detect stuck flag every 90 seconds and force recovery
            setInterval(() => {
                if (_isSyncProcessing && Date.now() - _lastSyncAttempt > SYNC_STUCK_TIMEOUT) {
                    console.error('[HighTechSync] [ERROR] STUCK FLAG DETECTED! Forcing reset after 60s timeout.');
                    _isSyncProcessing = false;
                    setTimeout(() => {
                        if (navigator.onLine && state.syncQueue.length > 0) {
                            console.log('[HighTechSync] AUTO-RECOVERY: Retrying sync...');
                            processSyncQueue();
                        }
                    }, 1000);
                }
            }, 90000);

            async function processSyncQueue() {
                if (_isSyncProcessing || state.syncQueue.length === 0) return;

                const now = Date.now();
                if (now - _lastSyncAttempt < SYNC_MIN_INTERVAL) {
                    console.log('[HighTechSync] Rate-limiting: Skipping rapid re-trigger');
                    return;
                }

                _isSyncProcessing = true;
                _lastSyncAttempt = now;

                const queueStartTime = Date.now();
                console.log(`%c[HighTechSync] [INFO] Starting Sync Process | Queue: ${state.syncQueue.length} items`, "color: #0d9488; font-weight: bold; font-size: 1.1em;");
                renderSyncStatus();

                let itemsToProcess = state.syncQueue.filter(item =>
                    item.status === 'pending' ||
                    item.status === 'uploading' ||
                    (item.status === 'failed' && !item.noRetry)
                );

                let isFirstItem = true;

                for (const item of itemsToProcess) {
                    if (item.cancelRequested || item.status === 'cancelled') {
                        console.log(`[HighTechSync] ? Skipping cancelled item: ${getSyncItemLabel(item)}`);
                        removeSyncPlaceholderFromTrial(item);
                        state.syncQueue = state.syncQueue.filter(i => i.id !== item.id);
                        saveSyncQueue();
                        renderSyncStatus();
                        continue;
                    }

                    if (!navigator.onLine) {
                        console.warn("[HighTechSync] [WARN] Offline detected. Pausing sync.");
                        break;
                    }

                    // SAFETY: Check if we've been processing for too long (processing one item shouldn't exceed 1 minute)
                    if (Date.now() - _lastSyncAttempt > SYNC_STUCK_TIMEOUT) {
                        console.warn('[HighTechSync] [WARN] Processing timeout detected. Breaking to prevent hang.');
                        break;
                    }

                    const itemStartTime = Date.now();
                    const itemLabel = item.action ? `Action: ${item.action}` : (item.photo?.fileName || item.id);

                    if (!isFirstItem || (item.attempts || 0) > 0) {
                        const waitTime = Math.min(10000, (isFirstItem ? 0 : 500) + ((item.attempts || 0) * 2000));
                        if (waitTime > 0 && item.action) { // Actions have priority, but we still backoff on repeats
                            console.log(`[HighTechSync] Waiting ${waitTime}ms (backoff)...`);
                            await new Promise(resolve => setTimeout(resolve, waitTime));
                        }
                    }
                    isFirstItem = false;

                    // --- NEW: DATA ACTION SYNC PATH ---
                    if (item.action) {
                        try {
                            item.status = 'uploading';
                            saveSyncQueue();
                            renderSyncStatus();

                            console.log(`[HighTechSync] [INFO] Syncing Action: ${item.action}`);
                            const result = await apiCall(item.action, item.payload, false);

                            if (item.cancelRequested) {
                                console.log(`[HighTechSync] ? Cancelled after request: ${item.action}`);
                                state.syncQueue = state.syncQueue.filter(i => i.id !== item.id);
                                saveSyncQueue();
                                continue;
                            }

                            if (result && result._errType) throw new Error(result.message);

                            console.log(`%c? Action Synced: ${item.action}`, "color: #16a34a;");
                            item.status = 'completed';
                            state.syncQueue = state.syncQueue.filter(i => i.id !== item.id);
                            saveSyncQueue();
                            continue;
                        } catch (e) {
                            console.error(`[HighTechSync] ? Action Fail: ${item.action}`, e);
                            item.status = 'failed';
                            item.attempts = (item.attempts || 0) + 1;
                            saveSyncQueue();
                            continue;
                        }
                    }

                    // --- PHOTO UPLOAD SYNC PATH ---
                    // CRITICAL FIX: Dedup check - MUST work even if URL is empty (first upload attempt)
                    const trial = state.trials.find(t => t.ID === item.trialId);
                    if (trial && item.photo.tempId) {
                        const isWeed = item.type === 'weed_upload';
                        let photos = isWeed ? safeJsonParse(trial.WeedPhotosJSON) : safeJsonParse(trial.PhotoURLs);

                        // Check if this exact tempId already exists in photos AND either:
                        // 1) Has a URL (already uploaded successfully), OR
                        // 2) Another sync item is CURRENTLY uploading it (to prevent parallel uploads)
                        const existingPhoto = photos.find(p => p.tempId === item.photo.tempId);
                        if (existingPhoto && existingPhoto.url) {
                            console.log(`[HighTechSync] ? DUPLICATE BLOCKED: Photo already uploaded: ${item.photo.tempId}`);
                            item.status = 'completed';
                            state.syncQueue = state.syncQueue.filter(i => i.id !== item.id);
                            saveSyncQueue();
                            continue;
                        }

                        // Check if another sync item for the same photo is already uploading
                        const otherUploadingItem = state.syncQueue.find(s =>
                            s.photo.tempId === item.photo.tempId &&
                            s.id !== item.id &&
                            s.status === 'uploading'
                        );
                        if (otherUploadingItem) {
                            console.log(`[HighTechSync] ? Item skipped - same photo already uploading by ${otherUploadingItem.id}`);
                            item.status = 'pending';
                            saveSyncQueue();
                            // Skip this iteration, try again after other completes
                            continue;
                        }
                    }

                    item.status = 'uploading';
                    saveSyncQueue();
                    renderSyncStatus();

                    try {
                        const payloadSize = Math.round(item.photo.fileData.length / 1024);
                        console.group(`[Syncing Item] ${itemLabel} (${payloadSize} KB)`);
                        console.log(`Start Time: ${new Date(itemStartTime).toLocaleTimeString()}`);

                        const isWeed = item.type === 'weed_upload';

                        // 1. ATOMIC UPLOAD
                        if (!getEffectiveFolderId()) throw new Error("Folder ID missing.");

                        const uploadStart = Date.now();
                        console.log(`[Step 1/3] Uploading to Google Drive...`);

                        // Determine hierarchical folder path
                        let folderPath = null;
                        if (trial) {
                            const project = state.projects.find(p => p.ID === trial.ProjectID);
                            const projectName = project ? project.Name : 'Ungrouped Projects';
                            const trialNameWithDate = `${trial.FormulationName || 'Unknown Formulation'} (${trial.Date ? new Date(trial.Date).toISOString().split('T')[0] : new Date().toISOString().split('T')[0]})`.trim();
                            folderPath = [projectName, trialNameWithDate];
                        }

                        // ADD TIMEOUT SAFETY: Prevent hanging on Google Drive API (timeout after 45s)
                        let result = null;
                        try {
                            const uploadPromise = apiCall('uploadPhoto', {
                                trialId: item.trialId,
                                fileData: item.photo.fileData,
                                mimeType: item.photo.mimeType,
                                fileName: item.photo.fileName,
                                isWeed: isWeed,
                                label: item.photo.label,
                                date: item.photo.date,
                                folderPath: folderPath
                            }, false);

                            // Timeout after 45 seconds
                            result = await Promise.race([
                                uploadPromise,
                                new Promise((_, reject) =>
                                    setTimeout(() => reject(new Error('Upload timeout after 45s - connection too slow. Will retry.')), 45000)
                                )
                            ]);
                        } catch (timeoutErr) {
                            if (String(timeoutErr.message).includes('timeout')) {
                                console.error('[HighTechSync] [ERROR] Upload timeout detected:', timeoutErr.message);
                                item.status = 'pending';
                                item.attempts = (item.attempts || 0) + 1;
                                item.lastError = timeoutErr.message;
                                saveSyncQueue();
                                continue;
                            }
                            throw timeoutErr;
                        }

                        if (item.cancelRequested) {
                            console.warn(`[HighTechSync] ? Upload finished but item was cancelled: ${itemLabel}`);
                            removeSyncPlaceholderFromTrial(item);
                            state.syncQueue = state.syncQueue.filter(i => i.id !== item.id);
                            saveSyncQueue();
                            renderSyncStatus();
                            continue;
                        }

                        if (result && result._errType) throw new Error(`Server Error: ${result.message}`);
                        if (!result?.url && !result?.id) throw new Error('Empty response from script.');

                        const uploadTime = ((Date.now() - uploadStart) / 1000).toFixed(2);
                        console.log(`%c? Drive Upload Complete (${uploadTime}s)`, "color: #16a34a;");

                        const publicUrl = result.url || result.fileUrl;
                        console.log(`Cloud URL: ${publicUrl}`);

                        // 2. INTERNAL STATE & BACKGROUND AI
                        if (trial) {
                            let photos = isWeed ? safeJsonParse(trial.WeedPhotosJSON) : safeJsonParse(trial.PhotoURLs);
                            const idx = photos.findIndex(p => p.tempId === item.photo.tempId);

                            if (idx > -1) {
                                photos[idx].url = publicUrl;
                                if (!photos[idx].label || photos[idx].label === "Processing...") {
                                    photos[idx].label = item.photo.label || `Photo: ${item.photo.date || new Date().toLocaleDateString()}`;
                                }
                                delete photos[idx].fileData;
                            } else {
                                photos.push({ url: publicUrl, date: item.photo.date, label: item.photo.label || '', tempId: item.photo.tempId });
                            }

                            if (isWeed) trial.WeedPhotosJSON = JSON.stringify(photos); else trial.PhotoURLs = JSON.stringify(photos);

                            // 3. PERSIST PHOTO LINK TO SHEET
                            const handshakeStart = Date.now();
                            console.log(`[Step 2/3] Updating Spreadsheet...`);

                            await apiCall('updateTrialRecord', {
                                ID: trial.ID,
                                [isWeed ? 'WeedPhotosJSON' : 'PhotoURLs']: trial[isWeed ? 'WeedPhotosJSON' : 'PhotoURLs']
                            }, false);

                            const handshakeTime = ((Date.now() - handshakeStart) / 1000).toFixed(2);
                            console.log(`%c? Spreadsheet Handshake Complete (${handshakeTime}s)`, "color: #16a34a;");

                            refreshRelevantUI(item.trialId, item.type);

                            // 4. FIRE-AND-FORGET AI
                            console.log(`[Step 3/3] Launching Background AI Analysis (Non-blocking)...`);
                            (async () => {
                                const aiStart = Date.now();
                                try {
                                    if (isWeed) {
                                        const ids = await identifyWeedsFromPhoto(item.photo.fileData, item.photo.mimeType);
                                        if (ids?.length > 0) {
                                            const t = state.trials.find(x => x.ID === item.trialId);
                                            let wPhotos = safeJsonParse(t.WeedPhotosJSON);
                                            const pIdx = wPhotos.findIndex(p => p.tempId === item.photo.tempId);
                                            if (pIdx > -1) {
                                                wPhotos[pIdx].identifications = ids;
                                                if (!wPhotos[pIdx].label || wPhotos[pIdx].label.includes('Synced')) wPhotos[pIdx].label = ids.map(i => i.name).join(', ');
                                                t.WeedPhotosJSON = JSON.stringify(wPhotos);
                                                await apiCall('updateTrialRecord', { ID: t.ID, WeedPhotosJSON: t.WeedPhotosJSON }, false);
                                                refreshRelevantUI(item.trialId, 'weed_upload');
                                                console.log(`[AI Background] Weed ID finished in ${((Date.now() - aiStart) / 1000).toFixed(2)}s`);
                                            }
                                        }
                                    } else {
                                        // 1. Proactive Weed ID (If missing species or first photo)
                                        const shouldRunFirstPhotoCheck = shouldAutoIdentifyGeneralPhotoWeeds(trial, {
                                            tempId: item.photo.tempId,
                                            url: publicUrl
                                        });

                                        if (shouldRunFirstPhotoCheck) {
                                            console.log('[AI Background] Triggering proactive Weed ID for general photo...');
                                            const ids = await analyzeGeneralPhotoWeeds(item.trialId, {
                                                tempId: item.photo.tempId,
                                                url: publicUrl
                                            }, {
                                                showToast: false,
                                                sourceFileData: item.photo.fileData,
                                                sourceMimeType: item.photo.mimeType
                                            });
                                            if (ids && ids.length > 0) {
                                                const common = ids.flatMap(i => i.commonNames || []).join(', ');
                                                if (common) showToast(`Identified potential weeds: ${common}`, 'info');
                                            }
                                        }

                                        // 2. Weed Cover Analysis (ALWAYS RUN & SAVE)
                                        console.log('%c[AI Background] [INFO] Running weed cover detection...', 'color: #10b981; font-weight: bold;');
                                        let coverResult = null;
                                        try {
                                            const greenOnly = true;
                                            coverResult = await analyzeWeedCover(item.photo.fileData, greenOnly);
                                            console.log(`%c[Weed Cover] [INFO] ${coverResult.cover}% coverage detected (${coverResult.mode})`,
                                                "color: #10b981; font-weight: bold; font-size: 1.2em;");
                                            console.log('[Weed Cover] Breakdown:', coverResult.breakdown);
                                            console.log('[Weed Cover] Details:', coverResult.details);

                                            // SAVE WEED COVER IMMEDIATELY (even if autoAnalyze is off)
                                            const trial = state.trials.find(x => x.ID === item.trialId);
                                            if (trial && coverResult.cover > 0) {
                                                let eData = safeJsonParse(trial.EfficacyDataJSON);
                                                const daa = window.calculateDAA(item.photo.date, trial.Date);
                                                const photoDateStr = window.toDateKey(item.photo.date);

                                                // Check if observation for this date already exists
                                                const existingIdx = eData.findIndex(obs => window.toDateKey(obs.date) === photoDateStr);
                                                if (existingIdx >= 0) {
                                                    // Update existing observation
                                                    eData[existingIdx].weedCover = coverResult.cover;
                                                    eData[existingIdx].vari = coverResult.vari;
                                                    eData[existingIdx].weedCoverMode = 'auto';
                                                    eData[existingIdx].photoUrl = publicUrl;
                                                    console.log(`[Weed Cover] Updated existing obs with ${coverResult.cover}%`);
                                                } else {
                                                    // Create new observation with weed cover
                                                    eData.push({
                                                        date: photoDateStr,
                                                        daa: daa,
                                                        notes: 'Weed cover detected from photo',
                                                        photoUrl: publicUrl,
                                                        weedCover: coverResult.cover,
                                                        weedCoverMode: 'auto',
                                                        weedDetails: []
                                                    });
                                                    console.log(`[Weed Cover] Created new obs with ${coverResult.cover}%`);
                                                }

                                                trial.EfficacyDataJSON = JSON.stringify(eData);
                                                await apiCall('updateTrialRecord', { ID: trial.ID, EfficacyDataJSON: trial.EfficacyDataJSON }, false);
                                                refreshRelevantUI(item.trialId, 'general_upload');
                                                console.log(`? WEED COVER SAVED: ${coverResult.cover}%`);
                                            }
                                        } catch (wcErr) {
                                            console.error('[Weed Cover] Analysis failed:', wcErr);
                                        }

                                        // 3. Full Efficacy Analysis (If enabled)
                                        console.log('[AI Background] autoAnalyzePhotos setting:', state.settings.autoAnalyzePhotos);
                                        if (state.settings.autoAnalyzePhotos) {
                                            console.log('[AI Background] Running full efficacy analysis...');
                                                const t = state.trials.find(x => x.ID === item.trialId);
                                            let eData = safeJsonParse(t.EfficacyDataJSON);
                                            const daa = window.calculateDAA(item.photo.date, t.Date);
                                                const workingTrial = {
                                                    ...t,
                                                    EfficacyDataJSON: JSON.stringify(eData || [])
                                                };
                                                const eff = await analyzePhotoForEfficacy(item.photo.fileData, item.photo.mimeType, { trial: workingTrial, daa: daa });
                                            if (eff) {

                                                // Include weed cover in saved data
                                                const photoDate = new Date(item.photo.date);
                                                const photoDateStr = window.toDateKey(item.photo.date);
                                                const newObs = {
                                                    date: photoDateStr,
                                                    daa: daa,
                                                    notes: `AI analysis from photo taken on ${photoDate.toLocaleDateString()}`,
                                                    photoUrl: publicUrl,
                                                    weedDetails: eff.weedDetails
                                                };

                                                // Calculate total weed cover from individual species
                                                if (eff.weedDetails && eff.weedDetails.length > 0) {
                                                    newObs.weedCover = window.computeObservationTotalCover({ weedDetails: eff.weedDetails }, t);
                                                    newObs.weedCoverMode = 'auto';
                                                    console.log(`[Weed Cover] Calculated total from species: ${newObs.weedCover}% from ${eff.weedDetails.length} species`);
                                                }

                                                // Add weed cover if available from AI estimate
                                                if (eff.weedCoverEstimate) {
                                                    newObs.weedCover = eff.weedCoverEstimate.cover;
                                                    newObs.weedCoverMode = eff.weedCoverEstimate.mode;
                                                    newObs.weedCoverConfidence = eff.weedCoverEstimate.confidence;
                                                    console.log(`[Weed Cover] Using AI estimate: ${newObs.weedCover}%`);
                                                }

                                                eData.push(newObs);
                                                t.EfficacyDataJSON = JSON.stringify(eData);
                                                t.AISummariesJSON = '{}';
                                                await apiCall('updateTrialRecord', { ID: t.ID, EfficacyDataJSON: t.EfficacyDataJSON, AISummariesJSON: '{}' }, false);
                                                refreshRelevantUI(item.trialId, 'general_upload');
                                                console.log(`[AI Background] Full efficacy analysis finished in ${((Date.now() - aiStart) / 1000).toFixed(2)}s`);

                                                // Auto-prompt for grid correction if weed cover detected
                                                if (newObs.weedCover && newObs.weedCover > 0 && publicUrl) {
                                                    setTimeout(() => {
                                                        if (confirm(`Weed cover detected: ${newObs.weedCover}%\n\nRefine with grid analysis? (Recommended for separating crop from weeds)`)) {
                                                            showGridWeedCoverModal(publicUrl, newObs.weedCover, (gridData) => {
                                                                updateObservationWeedCover(t.ID, eData.length - 1, gridData);
                                                            });
                                                        }
                                                    }, 1000);
                                                }
                                            }
                                        }
                                    }
                                } catch (aiErr) { console.warn(`[AI Background] Failed:`, aiErr.message); }
                            })();
                        }

                        item.status = 'completed';
                        state.syncQueue = state.syncQueue.filter(i => i.id !== item.id);

                        const totalItemTime = ((Date.now() - itemStartTime) / 1000).toFixed(2);
                        console.log(`%cTotal Item Process Time: ${totalItemTime}s`, "font-weight: bold; color: #0d9488;");
                        console.groupEnd();
                    } catch (error) {
                        const errMsg = String(error?.message || 'Unknown error');
                        console.error(`%c[Sync Error] ${itemLabel} Failed: ${errMsg}`, "color: #dc2626; font-weight: bold;");
                        item.attempts = (item.attempts || 0) + 1;
                        const drivePermDenied = isDrivePermissionError(errMsg);
                        item.noRetry = drivePermDenied;
                        item.status = errMsg.includes('Timeout') || errMsg.includes('fetch') ? 'pending' : 'failed';
                        item.lastError = errMsg;

                        if (drivePermDenied) {
                            const now = Date.now();
                            if (!window._drivePermissionToastAt || now - window._drivePermissionToastAt > 60000) {
                                showToast('Drive permission denied by server. In Apps Script deploy Web App as "Execute as: Me", run triggerDrivePermissions() once, then redeploy.', 'error');
                                window._drivePermissionToastAt = now;
                            }
                        }
                        console.groupEnd();
                    }
                    saveSyncQueue();
                    renderSyncStatus();
                }

                _isSyncProcessing = false;
                const totalQueueTime = ((Date.now() - queueStartTime) / 1000).toFixed(2);
                console.log(`[HighTechSync] ? Queue Finished | Total Time: ${totalQueueTime}s | Pending: ${state.syncQueue.filter(s => s.status === 'pending').length}`);

                // Feedback for user
                const successCount = itemsToProcess.filter(i => i.status === 'completed').length;
                const failedCount = itemsToProcess.filter(i => i.status === 'failed' && !i.noRetry).length;
                const blockedCount = state.syncQueue.filter(i => i.status === 'failed' && i.noRetry).length;
                const pendingCount = state.syncQueue.filter(i => i.status === 'pending' || (i.status === 'failed' && !i.noRetry)).length;

                if (successCount > 0) {
                    showToast(`? Sync complete! ${successCount} item(s) uploaded. ${pendingCount} pending.`, 'success');
                } else if (failedCount > 0) {
                    showToast(`Sync finished with ${failedCount} error(s). Retrying in 30s...`, 'warning');
                    // Auto-retry failed items after 30 seconds
                    setTimeout(() => {
                        if (navigator.onLine) processSyncQueue();
                    }, 30000);
                } else if (blockedCount > 0) {
                    showToast(`Sync paused: ${blockedCount} item(s) need Drive permission fix in Apps Script settings.`, 'warning');
                } else if (pendingCount > 0) {
                    console.log(`[HighTechSync] [INFO] ${pendingCount} items still pending. Setting up auto-retry...`);
                    setTimeout(() => {
                        if (navigator.onLine && !_isSyncProcessing) processSyncQueue();
                    }, 5000);
                }

                renderSyncStatus();
            }

